-- A) Extensions
CREATE EXTENSION IF NOT EXISTS "uuid-ossp";

-- B) Enum(s)
CREATE TYPE public.user_role AS ENUM ('admin', 'staff', 'customer');
CREATE TYPE public.transaction_type AS ENUM ('recharge', 'debit');
CREATE TYPE public.training_level_name AS ENUM ('Einsteiger', 'Grundlagen', 'Fortgeschrittene', 'Masterclass', 'Expert');
CREATE TYPE public.training_status AS ENUM ('Aktuell', 'Gesperrt', 'Abgeschlossen');

-- C) Tabellen
-- profiles
CREATE TABLE public.profiles (
  id uuid DEFAULT uuid_generate_v4() PRIMARY KEY,
  user_id uuid NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
  role public.user_role DEFAULT 'customer' NOT NULL,
  CONSTRAINT unique_user_id UNIQUE (user_id)
);

-- customer_profiles
CREATE TABLE public.customer_profiles (
  id uuid DEFAULT uuid_generate_v4() PRIMARY KEY,
  auth_user_id uuid REFERENCES auth.users(id) ON DELETE SET NULL, -- Optional, SET NULL if auth user deleted but customer profile persists
  first_name text,
  last_name text,
  phone text,
  dog_name text,
  chip_number text,
  qr_code_data text
);

-- transactions
CREATE TABLE public.transactions (
  id uuid DEFAULT uuid_generate_v4() PRIMARY KEY,
  customer_profile_id uuid NOT NULL REFERENCES public.customer_profiles(id) ON DELETE CASCADE,
  created_by_user_id uuid REFERENCES auth.users(id) ON DELETE SET NULL, -- Who created the transaction (staff/admin)
  type public.transaction_type NOT NULL,
  description text,
  amount numeric NOT NULL,
  created_at timestamp with time zone DEFAULT now() NOT NULL
);

-- training_progress
CREATE TABLE public.training_progress (
  id uuid DEFAULT uuid_generate_v4() PRIMARY KEY,
  customer_profile_id uuid NOT NULL REFERENCES public.customer_profiles(id) ON DELETE CASCADE,
  level_name public.training_level_name NOT NULL,
  completed_trails integer DEFAULT 0 NOT NULL,
  status public.training_status DEFAULT 'Gesperrt' NOT NULL,
  CONSTRAINT unique_customer_level UNIQUE (customer_profile_id, level_name)
);

-- D) Trigger + Function (SECURITY DEFINER)
CREATE FUNCTION public.handle_new_user()
RETURNS TRIGGER AS $$
BEGIN
  INSERT INTO public.profiles (user_id, role)
  VALUES (NEW.id, 'customer');
  RETURN NEW;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

CREATE TRIGGER on_auth_user_created
  AFTER INSERT ON auth.users
  FOR EACH ROW EXECUTE FUNCTION public.handle_new_user();

-- E) RLS aktivieren + alle Policies
-- RLS aktivieren
ALTER TABLE public.profiles ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.customer_profiles ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.transactions ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.training_progress ENABLE ROW LEVEL SECURITY;

-- Policies für profiles
-- Admin full access
CREATE POLICY "Admin full access on profiles" ON public.profiles
  FOR ALL TO authenticated
  USING (EXISTS (SELECT 1 FROM public.profiles WHERE user_id = auth.uid() AND role = 'admin'))
  WITH CHECK (EXISTS (SELECT 1 FROM public.profiles WHERE user_id = auth.uid() AND role = 'admin'));

-- Customers can read their own profile
CREATE POLICY "Customers read own profile" ON public.profiles
  FOR SELECT TO authenticated
  USING (user_id = auth.uid());

-- Policies für customer_profiles
-- Admin full access
CREATE POLICY "Admin full access on customer_profiles" ON public.customer_profiles
  FOR ALL TO authenticated
  USING (EXISTS (SELECT 1 FROM public.profiles WHERE user_id = auth.uid() AND role = 'admin'))
  WITH CHECK (EXISTS (SELECT 1 FROM public.profiles WHERE user_id = auth.uid() AND role = 'admin'));

-- Staff read all customer profiles
CREATE POLICY "Staff read all customer_profiles" ON public.customer_profiles
  FOR SELECT TO authenticated
  USING (EXISTS (SELECT 1 FROM public.profiles WHERE user_id = auth.uid() AND role IN ('admin', 'staff')));

-- Staff can insert customer profiles
CREATE POLICY "Staff insert customer_profiles" ON public.customer_profiles
  FOR INSERT TO authenticated
  WITH CHECK (EXISTS (SELECT 1 FROM public.profiles WHERE user_id = auth.uid() AND role IN ('admin', 'staff')));

-- Staff can update all customer profiles
CREATE POLICY "Staff update all customer_profiles" ON public.customer_profiles
  FOR UPDATE TO authenticated
  USING (EXISTS (SELECT 1 FROM public.profiles WHERE user_id = auth.uid() AND role IN ('admin', 'staff')));

-- Customer can read own customer profile
CREATE POLICY "Customers read own customer_profile" ON public.customer_profiles
  FOR SELECT TO authenticated
  USING (auth_user_id = auth.uid());

-- Customer can insert own customer profile (auth_user_id must match authenticated user)
CREATE POLICY "Customers insert own customer_profile" ON public.customer_profiles
  FOR INSERT TO authenticated
  WITH CHECK (auth_user_id = auth.uid());

-- Customer can update own customer profile
CREATE POLICY "Customers update own customer_profile" ON public.customer_profiles
  FOR UPDATE TO authenticated
  USING (auth_user_id = auth.uid());

-- Policies für transactions
-- Admin full access
CREATE POLICY "Admin full access on transactions" ON public.transactions
  FOR ALL TO authenticated
  USING (EXISTS (SELECT 1 FROM public.profiles WHERE user_id = auth.uid() AND role = 'admin'))
  WITH CHECK (EXISTS (SELECT 1 FROM public.profiles WHERE user_id = auth.uid() AND role = 'admin'));

-- Staff read all transactions
CREATE POLICY "Staff read all transactions" ON public.transactions
  FOR SELECT TO authenticated
  USING (EXISTS (SELECT 1 FROM public.profiles WHERE user_id = auth.uid() AND role IN ('admin', 'staff')));

-- Staff can insert transactions (created_by_user_id must match authenticated user, and role must be staff/admin)
CREATE POLICY "Staff insert transactions" ON public.transactions
  FOR INSERT TO authenticated
  WITH CHECK (
    created_by_user_id = auth.uid() AND
    EXISTS (SELECT 1 FROM public.profiles WHERE user_id = auth.uid() AND role IN ('admin', 'staff'))
  );

-- Customer can read own transactions (via customer_profile_id linked to their auth_user_id)
CREATE POLICY "Customers read own transactions" ON public.transactions
  FOR SELECT TO authenticated
  USING (
    EXISTS (
      SELECT 1
      FROM public.customer_profiles cp
      WHERE cp.id = public.transactions.customer_profile_id AND cp.auth_user_id = auth.uid()
    )
  );

-- Policies für training_progress
-- Admin full access
CREATE POLICY "Admin full access on training_progress" ON public.training_progress
  FOR ALL TO authenticated
  USING (EXISTS (SELECT 1 FROM public.profiles WHERE user_id = auth.uid() AND role = 'admin'))
  WITH CHECK (EXISTS (SELECT 1 FROM public.profiles WHERE user_id = auth.uid() AND role = 'admin'));

-- Staff read all training progress
CREATE POLICY "Staff read all training_progress" ON public.training_progress
  FOR SELECT TO authenticated
  USING (EXISTS (SELECT 1 FROM public.profiles WHERE user_id = auth.uid() AND role IN ('admin', 'staff')));

-- Staff can update all training progress
CREATE POLICY "Staff update all training_progress" ON public.training_progress
  FOR UPDATE TO authenticated
  USING (EXISTS (SELECT 1 FROM public.profiles WHERE user_id = auth.uid() AND role IN ('admin', 'staff')));

-- Customer read own training progress
CREATE POLICY "Customers read own training_progress" ON public.training_progress
  FOR SELECT TO authenticated
  USING (
    EXISTS (
      SELECT 1
      FROM public.customer_profiles cp
      WHERE cp.id = public.training_progress.customer_profile_id AND cp.auth_user_id = auth.uid()
    )
  );

