import React, { useState, useEffect } from 'react';
import Modal from './Modal';
import Button from './Button';
import Input from './Input';
import Select from './Select';
import { User, UserRoleEnum } from '../types';

interface UserFormModalProps {
  isOpen: boolean;
  onClose: () => void;
  // password is now optional even for new users, as customer registration happens elsewhere
  // this form primarily for admin/staff editing existing users or adding customer profiles linked to auth.users
  onSubmit: (userData: { firstName: string; lastName: string; email: string; role: UserRoleEnum; password?: string }) => void;
  userToEdit: User | null;
  currentUserRole: UserRoleEnum; // Pass current user's role to restrict role selection
}

const UserFormModal: React.FC<UserFormModalProps> = ({ isOpen, onClose, onSubmit, userToEdit, currentUserRole }) => {
  const [firstName, setFirstName] = useState('');
  const [lastName, setLastName] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState(''); // New state for password
  const [role, setRole] = useState<UserRoleEnum>(UserRoleEnum.MITARBEITER);
  const [firstNameError, setFirstNameError] = useState('');
  const [lastNameError, setLastNameError] = useState('');
  const [emailError, setEmailError] = useState('');
  const [passwordError, setPasswordError] = useState(''); // New state for password error

  useEffect(() => {
    if (userToEdit) {
      setFirstName(userToEdit.firstName);
      setLastName(userToEdit.lastName);
      setEmail(userToEdit.email);
      setRole(userToEdit.role);
      setPassword(''); // Clear password field when editing for security, user can set new one
    } else {
      // Reset form for new user
      setFirstName('');
      setLastName('');
      setEmail('');
      setPassword(''); // Clear password field for new user
      setRole(UserRoleEnum.KUNDE); // Default to Kunde for new users via this form (staff/admin create them)
    }
    setFirstNameError('');
    setLastNameError('');
    setEmailError('');
    setPasswordError(''); // Clear password error
  }, [userToEdit, isOpen]); // Reset when modal opens or userToEdit changes

  const validateForm = () => {
    let isValid = true;
    if (!firstName.trim()) {
      setFirstNameError('Vorname ist erforderlich.');
      isValid = false;
    } else {
      setFirstNameError('');
    }

    if (!lastName.trim()) {
      setLastNameError('Nachname ist erforderlich.');
      isValid = false;
    } else {
      setLastNameError('');
    }

    if (!email.trim()) {
      setEmailError('E-Mail ist erforderlich.');
      isValid = false;
    } else if (!/\S+@\S+\.\S+/.test(email)) { // Basic email format validation
      setEmailError('Ungültiges E-Mail-Format.');
      isValid = false;
    } else {
      setEmailError('');
    }

    // Password is only validated if provided when editing, or for new users if applicable.
    // For new users through this form (which will primarily be customer profiles linked to auth.users),
    // password management for auth.users is external (registration page for customers) or internal (admin creating admin/staff users - not implemented client-side).
    // So for now, password is treated as optional for this form's submission.
    if (password.trim() && password.length < 6) {
      setPasswordError('Passwort muss mindestens 6 Zeichen lang sein.');
      isValid = false;
    } else {
      setPasswordError('');
    }

    return isValid;
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (validateForm()) {
      onSubmit({ firstName, lastName, email, role, password: password.trim() || undefined }); // Pass password if not empty
    }
  };

  const title = userToEdit ? 'Benutzer bearbeiten' : 'Neuen Benutzer erstellen (Kunde)'; // Clarify new user type

  // Filter role options based on current user's role
  const roleOptions = [
    { value: UserRoleEnum.ADMIN, label: 'Admin' },
    { value: UserRoleEnum.MITARBEITER, label: 'Mitarbeiter' },
    { value: UserRoleEnum.KUNDE, label: 'Kunde' },
  ].filter(option => {
    if (currentUserRole !== UserRoleEnum.ADMIN && option.value === UserRoleEnum.ADMIN) {
      return false; // Only Admin can set Admin role
    }
    return true;
  });

  return (
    <Modal isOpen={isOpen} onClose={onClose} title={title} className="max-w-md">
      <form onSubmit={handleSubmit} className="p-0">
        <div className="space-y-4">
          <Input
            id="userFirstName"
            label="Vorname"
            type="text"
            value={firstName}
            onChange={(e) => setFirstName(e.target.value)}
            placeholder="Max"
            error={firstNameError}
          />
          <Input
            id="userLastName"
            label="Nachname"
            type="text"
            value={lastName}
            onChange={(e) => setLastName(e.target.value)}
            placeholder="Mustermann"
            error={lastNameError}
          />
          <Input
            id="userEmail"
            label="E-Mail"
            type="email"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            placeholder="max.mustermann@example.com"
            error={emailError}
            // For new user creation through this form, email is editable.
            // For editing, email is typically read-only or requires special permissions for auth.users.
            // For now, allow editing of email, but note that it might not update auth.users.email directly.
          />
          <Input // New password input field (optional for existing users, not for auth.users create)
            id="userPassword"
            label="Passwort (nur für neue Kunden-Registrierung oder optional ändern)"
            type="password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            placeholder="Passwort ändern"
            error={passwordError}
            disabled={!!userToEdit && userToEdit.role !== UserRoleEnum.KUNDE} // Only allow changing password for customer profiles
          />
          <Select
            id="userRole"
            label="Rolle"
            options={roleOptions}
            value={role}
            onChange={(e) => setRole(e.target.value as UserRoleEnum)}
            disabled={userToEdit?.id === 'mock-admin-user-id' && currentUserRole !== UserRoleEnum.ADMIN} // Prevent non-admins from changing roles of main admin
          />
        </div>
        <div className="p-4 border-t border-gray-200 mt-6 flex justify-end space-x-3">
          <Button variant="outline" onClick={onClose} type="button">
            Abbrechen
          </Button>
          <Button variant="success" type="submit">
            Speichern
          </Button>
        </div>
      </form>
    </Modal>
  );
};

export default UserFormModal;

import React, { useState } from 'react';
import Card from '../components/Card';
import Input from '../components/Input';
import Button from '../components/Button';
import { supabase } from '../supabaseClient';
import { UserRoleEnum } from '../types';

interface LoginPageProps {
  onLogin: (email: string, password: string) => Promise<boolean>; // Updated to return Promise
  onRegister: (email: string, password: string) => Promise<boolean>; // New prop for registration
}

const LoginPage: React.FC<LoginPageProps> = ({ onLogin, onRegister }) => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [emailError, setEmailError] = useState('');
  const [passwordError, setPasswordError] = useState('');
  const [loginError, setLoginError] = useState('');
  const [isRegistering, setIsRegistering] = useState(false); // State to toggle between login/register

  const validateForm = () => {
    let isValid = true;
    setEmailError('');
    setPasswordError('');
    setLoginError('');

    if (!email.trim()) {
      setEmailError('E-Mail ist erforderlich.');
      isValid = false;
    } else if (!/\S+@\S+\.\S+/.test(email)) {
      setEmailError('Ungültiges E-Mail-Format.');
      isValid = false;
    }

    if (!password.trim()) {
      setPasswordError('Passwort ist erforderlich.');
      isValid = false;
    } else if (password.length < 6) {
      setPasswordError('Passwort muss mindestens 6 Zeichen lang sein.');
      isValid = false;
    }

    return isValid;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (validateForm()) {
      setLoginError(''); // Clear previous errors
      try {
        if (isRegistering) {
          const success = await onRegister(email, password);
          if (success) {
            alert('Registrierung erfolgreich! Sie sind jetzt angemeldet.');
            // onRegister already handles auto-login and redirection
          } else {
            setLoginError('Registrierung fehlgeschlagen. Bitte versuchen Sie es erneut.');
          }
        } else {
          const success = await onLogin(email, password);
          if (!success) {
            setLoginError('Ungültige E-Mail oder ungültiges Passwort.');
          }
        }
      } catch (error: any) {
        console.error('Auth error:', error.message);
        setLoginError(`Ein Fehler ist aufgetreten: ${error.message || 'Bitte versuchen Sie es erneut.'}`);
      }
    }
  };

  return (
    <div className="flex items-center justify-center min-h-screen w-full bg-gray-100 p-4">
      <Card className="max-w-md w-full p-8">
        <h1 className="text-3xl font-bold text-gray-900 text-center mb-6">Mantrailing Card</h1>
        <p className="text-gray-600 text-center mb-8">{isRegistering ? 'Registrieren Sie sich, um fortzufahren' : 'Melden Sie sich an, um fortzufahren'}</p>

        <form onSubmit={handleSubmit} className="space-y-6">
          <Input
            id="authEmail"
            label="E-Mail"
            type="email"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            placeholder="ihre.email@example.com"
            error={emailError}
          />
          <Input
            id="authPassword"
            label="Passwort"
            type="password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            placeholder="********"
            error={passwordError}
          />

          {loginError && (
            <div className="text-red-600 text-sm text-center -mt-4">
              {loginError}
            </div>
          )}

          <Button type="submit" variant="primary" className="w-full">
            {isRegistering ? 'Registrieren' : 'Anmelden'}
          </Button>
        </form>

        <div className="mt-6 text-center text-sm text-gray-600">
          {isRegistering ? (
            <>
              Sie haben bereits ein Konto?{' '}
              <button
                type="button"
                className="text-blue-600 hover:text-blue-800 font-medium"
                onClick={() => setIsRegistering(false)}
              >
                Jetzt anmelden
              </button>
            </>
          ) : (
            <>
              Sie haben noch kein Konto?{' '}
              <button
                type="button"
                className="text-blue-600 hover:text-blue-800 font-medium"
                onClick={() => setIsRegistering(true)}
