  // Derive MOCK_REPORT_EMPLOYEES from actual users who made transactions
  const uniqueEmployeeIds = new Set(transactions.map(t => t.employeeId).filter(Boolean));
  const reportEmployees = [
    { value: 'Alle Mitarbeiter', label: 'Alle Mitarbeiter' },
    ...Array.from(uniqueEmployeeIds).map(empId => {
      const employeeUser = users.find(u => u.id === empId);
      return {
        value: empId!,
        label: employeeUser ? `${employeeUser.firstName} ${employeeUser.lastName}` : `Unbekannter Mitarbeiter (${empId})`,
      };
    }),
  ];


  // Effect to update availableTimePeriods and reset timePeriod when reportType changes
  useEffect(() => {
    const newPeriods = generateReportPeriods(reportType, REFERENCE_DATE);
    setAvailableTimePeriods(newPeriods);
    if (newPeriods.length > 0) {
      setTimePeriod(newPeriods[0].value); // Set to the first option by default
    } else {
      setTimePeriod('Gesamt'); // Fallback
    }
  }, [reportType]);


  // Helper for parsing current filter period
  const getFilterPeriodDate = () => {
    if (timePeriod === 'Gesamt') return null;

    // Check if it's a year (e.g., "2025")
    if (!isNaN(parseInt(timePeriod, 10)) && timePeriod.length === 4) {
      return new Date(parseInt(timePeriod, 10), 0, 1); // January 1st of the year
    }

    // Assume "Month YYYY" format for detailed filtering
    const [monthName, year] = timePeriod.split(' ');
    const monthMap: { [key: string]: number } = {
      'Januar': 0, 'Februar': 1, 'März': 2, 'April': 3, 'Mai': 4, 'Juni': 5,
      'Juli': 6, 'August': 7, 'September': 8, 'Oktober': 9, 'November': 10, 'Dezember': 11
    };
    const monthIndex = monthMap[monthName];
    if (monthIndex !== undefined && year) {
      return new Date(parseInt(year, 10), monthIndex, 1);
    }
    return null;
  };

  const selectedFilterPeriod = getFilterPeriodDate();

  // Filter transactions based on selected criteria
  const filteredTransactions = transactions.filter(t => {
    const transactionDate = parseDateString(t.date);
    if (!transactionDate) return false;

    // Filter by period
    let matchesPeriod = true;
    if (timePeriod === 'Gesamt') {
      matchesPeriod = true;
    } else if (reportType === 'Monatlich' && selectedFilterPeriod) {
      matchesPeriod = isSameMonth(transactionDate, selectedFilterPeriod);
    } else if (reportType === 'Jährlich' && selectedFilterPeriod) {
      matchesPeriod = transactionDate.getFullYear() === selectedFilterPeriod.getFullYear();
    }


    // Filter by employee (using employeeId)
    const matchesEmployee = employee === 'Alle Mitarbeiter' || t.employeeId === employee;

    // Filter by transaction type
    let matchesTransactionType = true;
    if (transactionFilter === 'Einnahmen (Aufladungen)') {
      matchesTransactionType = t.type === 'recharge';
    } else if (transactionFilter === 'Ausgaben (Abbuchungen)') {
      matchesTransactionType = t.type === 'debit';
    }

    return matchesPeriod && matchesEmployee && matchesTransactionType;
  });

  // Dynamic calculations for Report Stats
  const monthlyRecharges = filteredTransactions
    .filter(t => t.type === 'recharge')
    .reduce((sum, t) => sum + Math.abs(t.amount), 0);

  const monthlyDebits = filteredTransactions
    .filter(t => t.type === 'debit')
    .reduce((sum, t) => sum + Math.abs(t.amount), 0);

  const totalMonthlyTransactions = filteredTransactions.length;

  const activeCustomerIdsInPeriod = new Set(
    filteredTransactions.map(t => t.customerId)
  );
  const activeCustomersInPeriodCount = customers.filter(c => activeCustomerIdsInPeriod.has(c.id)).length;


  const getTopCustomers = () => {
    const customerTransactions: { [key: string]: { count: number; totalAmount: number } } = {};
    filteredTransactions.forEach(t => {
      if (!customerTransactions[t.customerId]) {
        customerTransactions[t.customerId] = { count: 0, totalAmount: 0 };
      }
      customerTransactions[t.customerId].count++;
      customerTransactions[t.customerId].totalAmount += Math.abs(t.amount);
    });

    return Object.entries(customerTransactions)
      .sort(([, a], [, b]) => b.totalAmount - a.totalAmount)
      .slice(0, 3)
      .map(([customerId, data]) => {
        const customer = customers.find(c => c.id === customerId);
        return {
          customerName: customer ? `${customer.firstName} ${customer.lastName}` : 'Unbekannt',
          dogName: customer?.dogName || '',
          transactionCount: data.count,
          totalAmount: data.totalAmount,
          avatarInitials: customer?.avatarInitials || '?',
          avatarColor: customer?.avatarColor || 'bg-gray-400',
          id: customerId,
        };
      });
  };

  const topCustomers = getTopCustomers();

  const handleExportPdf = async () => {
    setIsGeneratingPdf(true);
    try {
      const doc = new jsPDF();
      let yPos = 20;

      // Report Title
      doc.setFontSize(22);
      doc.text(`Mantrailing Card App - ${reportType} Bericht`, 105, yPos, { align: 'center' });
      yPos += 10;
      doc.line(20, yPos, 190, yPos); // Horizontal line
      yPos += 10;

      // Filter Details
      doc.setFontSize(12);
      doc.text(`Berichtstyp: ${reportType}`, 20, yPos);
      yPos += 7;
      doc.text(`Zeitraum: ${timePeriod}`, 20, yPos);
      yPos += 7;
      doc.text(`Mitarbeiter: ${employee === 'Alle Mitarbeiter' ? 'Alle Mitarbeiter' : users.find(u => u.id === employee)?.firstName + ' ' + users.find(u => u.id === employee)?.lastName || employee}`, 20, yPos);
      yPos += 7;
      doc.text(`Transaktionstyp: ${transactionFilter}`, 20, yPos);
      yPos += 7;
      doc.text(`Erstellt am: ${REFERENCE_DATE.toLocaleDateString('de-DE')}`, 20, yPos);
      yPos += 15;

      // Summary Stats
      doc.setFontSize(16);
      doc.text('Übersicht', 20, yPos);
      yPos += 7;
      doc.setFontSize(12);
      doc.text(`Gesamtaufladungen: ${monthlyRecharges.toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })}`, 20, yPos);
      yPos += 7;
      doc.text(`Abbuchungen: ${monthlyDebits.toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })}`, 20, yPos);
      yPos += 7;
      doc.text(`Anzahl Transaktionen: ${totalMonthlyTransactions}`, 20, yPos);
      yPos += 7;
      doc.text(`Aktive Kunden: ${activeCustomersInPeriodCount}`, 20, yPos);
      yPos += 15;

      // Transactions Table
      doc.setFontSize(16);
      doc.text(`${transactionFilter} im Zeitraum`, 20, yPos);
      yPos += 5;

      const transactionsHeaders = [['Datum', 'Beschreibung', 'Kunde', 'Mitarbeiter', 'Typ', 'Betrag']];
      const transactionsData = filteredTransactions.map(t => {
        const customer = customers.find(c => c.id === t.customerId);
        const customerName = customer ? `${customer.firstName} ${customer.lastName}` : 'Unbekannt';
        const isRecharge = t.type === 'recharge';
        const amountSign = isRecharge ? '+' : '-';
        const formattedAmount = `${amountSign}${Math.abs(t.amount).toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })}`;
        return [t.date, t.description, customerName, t.employee, t.type === 'recharge' ? 'Aufladung' : 'Abbuchung', formattedAmount];
      });

      (doc as any).autoTable({
        startY: yPos,
        head: transactionsHeaders,
        body: transactionsData,
        theme: 'striped',
        headStyles: { fillColor: [0, 161, 214] },
        margin: { top: 10, right: 20, bottom: 10, left: 20 },
        didParseCell: function (data: any) {
          if (data.section === 'body' && data.column.index === 5) {
            const amountStr = data.cell.text[0];
            if (amountStr && amountStr.startsWith('+')) {
              data.cell.styles.textColor = [34, 139, 34];
            } else if (amountStr && amountStr.startsWith('-')) {
              data.cell.styles.textColor = [220, 20, 60];
            }
          }
        },
      });

      yPos = (doc as any).autoTable.previous.finalY + 15;

      // Top Customers Table
      doc.setFontSize(16);
      doc.text('Top Kunden im Zeitraum', 20, yPos);
      yPos += 5;

      const topCustomersHeaders = [['Rang', 'Kunde', 'Hund', 'Transaktionen', 'Gesamtbetrag']];
      const topCustomersData = topCustomers.map((c, index) => [
        index + 1,
        c.customerName,
        c.dogName,
        c.transactionCount,
        c.totalAmount.toLocaleString('de-DE', { style: 'currency', currency: 'EUR' }),
      ]);

      (doc as any).autoTable({
        startY: yPos,
        head: topCustomersHeaders,
        body: topCustomersData,
        theme: 'striped',
        headStyles: { fillColor: [0, 161, 214] },
        margin: { top: 10, right: 20, bottom: 10, left: 20 },
      });

      const fileName = `Bericht_${reportType.replace(' ', '_')}_${timePeriod.replace(' ', '_')}_${employee.replace('Alle Mitarbeiter', 'Alle').replace(' ', '_')}_${transactionFilter.replace(' ', '_')}.pdf`;
      doc.save(fileName);
      alert('PDF Export erfolgreich!');
    } catch (error) {
      console.error("Fehler beim Erstellen der PDF:", error);
      alert('Fehler beim PDF Export. Bitte versuchen Sie es erneut.');
    } finally {
      setIsGeneratingPdf(false);
    }
  };

  return (
    <div className="p-6 md:p-8 lg:p-10">
      <h1 className="text-3xl font-bold text-gray-900 mb-2">Berichte & Statistiken</h1>
      <p className="text-gray-600 mb-8">Analysieren und exportieren Sie Ihre Geschäftsdaten</p>

      {/* Filters and Export Button */}
      <Card className="mb-8">
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 items-end">
          <Select
            id="reportType"
            label="Berichtstyp"
            options={MOCK_REPORT_TYPES.map(type => ({ value: type, label: type }))}
            value={reportType}
            onChange={(e) => setReportType(e.target.value)}
            disabled={isGeneratingPdf}
          />
          <Select
            id="timePeriod"
            label="Zeitraum"
            options={availableTimePeriods}
            value={timePeriod}
            onChange={(e) => setTimePeriod(e.target.value)}
            disabled={isGeneratingPdf}
          />
          <Select
            id="employee"
            label="Mitarbeiter"
            options={reportEmployees}
            value={employee}
            onChange={(e) => setEmployee(e.target.value)}
            disabled={isGeneratingPdf}
          />
          <Select
            id="transactionFilter"
            label="Transaktionstyp"
            options={MOCK_TRANSACTION_FILTERS.map(filter => ({ value: filter, label: filter }))}
            value={transactionFilter}
            onChange={(e) => setTransactionFilter(e.target.value)}
            disabled={isGeneratingPdf}
          />
          {/* Button moved to the last position in the grid to appear bottom-right */}
          <Button
            variant="success"
            className="w-full sm:col-span-1 lg:col-start-4 lg:col-span-1 lg:w-auto"
            onClick={handleExportPdf}
            disabled={isGeneratingPdf}
          >
            {isGeneratingPdf ? 'PDF wird generiert...' : 'Als PDF exportieren'}
          </Button>
        </div>
      </Card>

      {/* Stats Cards for Reports */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
        <StatCard
          title="Gesamtaufladungen"
          value={monthlyRecharges.toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })}
          icon={UsersIcon}
          color="bg-green-100 text-green-700"
        />
        <StatCard
          title="Abbuchungen"
          value={monthlyDebits.toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })}
          icon={DollarSignIcon}
          color="bg-orange-100 text-orange-700"
        />
        <StatCard
          title="Transaktionen"
          value={totalMonthlyTransactions}
          icon={ClipboardIcon}
          color="bg-blue-100 text-blue-700"
        />
        <StatCard
          title="Aktive Kunden"
          value={activeCustomersInPeriodCount}
          icon={UsersIcon}
          color="bg-purple-100 text-purple-700"
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Transaktionen im Zeitraum */}
        <Card>
          <h2 className="text-xl font-semibold text-gray-900 mb-4">{transactionFilter} im Zeitraum ({filteredTransactions.length})</h2>
          <div className="space-y-4 max-h-96 overflow-y-auto custom-scrollbar">
            {filteredTransactions.length === 0 ? (
              <p className="text-gray-500">Keine Transaktionen für den ausgewählten Zeitraum, Mitarbeiter und Transaktionstyp gefunden.</p>
            ) : (
              filteredTransactions.map((transaction) => {
                const customer = customers.find(c => c.id === transaction.customerId);
                const isRecharge = transaction.type === 'recharge';
                const TransactionIcon = isRecharge ? ArrowUpCircleIcon : ArrowDownCircleIcon;
                const iconColor = isRecharge ? 'text-green-500' : 'text-red-500';
                const amountColor = isRecharge ? 'text-green-700' : 'text-red-700';
                const amountSign = isRecharge ? '+' : '-';

                return (
                  <div key={transaction.id} className="flex items-center justify-between p-3 bg-gray-50 rounded-lg">
                    <div className="flex items-center">
                      <span className={`p-2 rounded-full bg-gray-200 mr-3 ${iconColor}`}>
                        <TransactionIcon className="h-5 w-5" />
                      </span>
                      <div>
                        <p className="font-medium text-gray-900">{transaction.description}</p>
                        <p className="text-sm text-gray-500">
                          {transaction.date} von {transaction.employee}
                          {customer && ` für ${customer.firstName} ${customer.lastName}`}
                        </p>
                      </div>
                    </div>
                    <p className={`font-semibold ${amountColor}`}>
                      {amountSign}{Math.abs(transaction.amount).toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })}
                    </p>
                  </div>
                );
              })
            )}
          </div>
        </Card>

        {/* Top Kunden im Zeitraum */}
        <Card>
          <h2 className="text-xl font-semibold text-gray-900 mb-4">Top Kunden im Zeitraum</h2>
          <div className="space-y-4 max-h-96 overflow-y-auto custom-scrollbar">
            {topCustomers.length === 0 ? (
              <p className="text-gray-500">Keine Top-Kunden für den ausgewählten Zeitraum und Mitarbeiter gefunden.</p>
            ) : (
              topCustomers.map((customer, index) => (
                <div key={customer.id} className="flex items-center justify-between p-3 bg-gray-50 rounded-lg">
                  <div className="flex items-center">
                    <span className="text-lg font-bold text-gray-700 mr-3">{index + 1}.</span>
                    <Avatar initials={customer.avatarInitials} color={customer.avatarColor} size="md" className="mr-3" />
                    <div>
                      <p className="font-medium text-gray-900">{customer.customerName}</p>
                      <p className="text-sm text-gray-500}>
                        {customer.dogName} &bull; {customer.transactionCount} Transaktion{customer.transactionCount !== 1 ? 'en' : ''}
                      </p>
                    </div>
                  </div>
                  <p className="font-semibold text-gray-800">
                    {customer.totalAmount.toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })}
                  </p>
                </div>
              ))
            )}
          </div>
        </Card>
      </div>
    </div>
  );
};

export default Reports;

import React, { useState, useEffect } from 'react';
import { Routes, Route, useNavigate, Navigate } from 'react-router-dom';
import Sidebar from './components/Sidebar';
import Dashboard from './pages/Dashboard';
import CustomerManagement from './pages/CustomerManagement';
import CustomerDetails from './pages/CustomerDetails';
import Reports from './pages/Reports';
import UserManagement from './pages/UserManagement';
import LoginPage from './pages/LoginPage';
import { Customer, Transaction, TrainingLevelEnum, User, UserRoleEnum, DbCustomerProfile, DbTransaction, DbTrainingProgress, DbProfile } from './types';
import { REFERENCE_DATE, TRAINING_LEVEL_DEFINITIONS, ADMIN_STAFF_USER_DETAILS } from './constants';
import { supabase } from './supabaseClient';
import { parseDateString } from './utils';

const App: React.FC = () => {
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [users, setUsers] = useState<User[]>([]); // Includes admin, staff, and customer users
  const [session, setSession] = useState<any>(null); // Supabase session object
  const [currentUser, setCurrentUser] = useState<User | null>(null); // Current logged-in user with app-specific details
  const [isLoadingInitialData, setIsLoadingInitialData] = useState(true);
  const navigate = useNavigate();

  // Helper to derive firstName, lastName, avatar for admin/staff
  const getAdminStaffUserDetails = (userId: string, email: string) => {
    const details = ADMIN_STAFF_USER_DETAILS[userId];
    if (details) {
      return {
        firstName: details.firstName || 'Unbekannt',
        lastName: details.lastName || 'Benutzer',
        avatarInitials: details.avatarInitials || '?',
        avatarColor: details.avatarColor || 'bg-gray-500',
      };
    }
    // Fallback if not in explicit mapping, e.g., for newly created staff/admin not yet mapped
    const initials = email.charAt(0).toUpperCase() + (email.split('@')[0]?.charAt(1) || '').toUpperCase();
    const randomColor = `bg-${['blue', 'green', 'orange', 'red', 'purple', 'indigo'][Math.floor(Math.random() * 6)]}-500`;
    return {
      firstName: email.split('@')[0],
      lastName: '',
      avatarInitials: initials,
      avatarColor: randomColor,
    };
  };

  const fetchAllData = async () => {
    setIsLoadingInitialData(true);
    try {
      const { data: { session: currentSession } } = await supabase.auth.getSession();
      setSession(currentSession);

      if (!currentSession) {
        setCustomers([]);
        setTransactions([]);
        setUsers([]);
        setCurrentUser(null);
        return; // No session, nothing to fetch
      }

      const authUserId = currentSession.user.id;

      // 1. Fetch profiles and current user's role
      const { data: dbProfiles, error: profilesError } = await supabase
        .from('profiles')
        .select('*');

      if (profilesError) throw profilesError;

      const { data: authUsersData, error: authUsersError } = await supabase.auth.admin.listUsers();
      if (authUsersError) throw authUsersError;
      const allAuthUsers = authUsersData?.users || [];

      // Map Supabase auth users to User interface, getting roles from profiles
      const transformedUsers: User[] = allAuthUsers.map((authUser: any) => {
        const profile = dbProfiles?.find((p: DbProfile) => p.user_id === authUser.id);
        const role: UserRoleEnum = profile?.role || UserRoleEnum.KUNDE; // Default to customer if no profile entry (shouldn't happen with trigger)

        let firstName = '';
        let lastName = '';
        let avatarInitials = '';
        let avatarColor = '';
        let associatedCustomerId: string | undefined = undefined;

        if (role === UserRoleEnum.KUNDE) {
          // For customer users, try to fetch from customer_profiles
          const customerProfile = customers.find(c => c.authUserId === authUser.id);
          if (customerProfile) {
            firstName = customerProfile.firstName;
            lastName = customerProfile.lastName;
            avatarInitials = customerProfile.avatarInitials;
            avatarColor = customerProfile.avatarColor;
            associatedCustomerId = customerProfile.id;
          } else {
            // Fallback for new customer user without a customer_profile yet
            firstName = authUser.email.split('@')[0];
            lastName = '';
            avatarInitials = authUser.email.charAt(0).toUpperCase();
            avatarColor = `bg-${['blue', 'green', 'orange', 'red', 'purple', 'indigo'][Math.floor(Math.random() * 6)]}-500`;
          }
        } else {
          // For admin/staff, use predefined mappings
          const details = getAdminStaffUserDetails(authUser.id, authUser.email);
          firstName = details.firstName;
          lastName = details.lastName;
          avatarInitials = details.avatarInitials;
          avatarColor = details.avatarColor;
        }

        return {
          id: authUser.id,
          email: authUser.email,
          role,
          createdAt: parseDateString(authUser.created_at)?.toLocaleDateString('de-DE') || authUser.created_at,
          firstName,
          lastName,
          avatarInitials,
          avatarColor,
          associatedCustomerId,
        };
      });
      setUsers(transformedUsers);

      const currentLoggedInUser = transformedUsers.find(u => u.id === authUserId);
      setCurrentUser(currentLoggedInUser || null);

      if (!currentLoggedInUser) {
        console.warn('Logged-in user not found in transformed users data.');
        return;
      }

      // Check for customer_profiles for the logged-in customer if it's a customer role
      if (currentLoggedInUser.role === UserRoleEnum.KUNDE && !currentLoggedInUser.associatedCustomerId) {
        const { data: existingCustomerProfile, error: customerProfileFetchError } = await supabase
          .from('customer_profiles')
          .select('id')
          .eq('auth_user_id', authUserId)
          .single();

        if (customerProfileFetchError && customerProfileFetchError.code !== 'PGRST116') { // PGRST116 means "no rows found"
          throw customerProfileFetchError;
        }

        if (!existingCustomerProfile) {
          // Auto-create customer_profile if it doesn't exist for a logged-in customer
          const { data: newCustomerProfile, error: createProfileError } = await supabase
            .from('customer_profiles')
            .insert({
              auth_user_id: authUserId,
              // Default values, user can update them later
              first_name: currentLoggedInUser.firstName || 'Neuer',
              last_name: currentLoggedInUser.lastName || 'Kunde',
              qr_code_data: `https://example.com/customer/${authUserId}`, // Placeholder QR
              // created_at is automatic
            })
            .select('id')
            .single();

          if (createProfileError) {
            throw createProfileError;
          }
          currentLoggedInUser.associatedCustomerId = newCustomerProfile.id; // Update current user with new customer ID
          setCurrentUser({ ...currentLoggedInUser }); // Update state to reflect new associatedCustomerId
        } else {
          currentLoggedInUser.associatedCustomerId = existingCustomerProfile.id;
          setCurrentUser({ ...currentLoggedInUser });
        }
      }


      // 2. Fetch customer profiles
      const { data: dbCustomerProfiles, error: customerProfilesError } = await supabase
        .from('customer_profiles')
        .select('*');

      if (customerProfilesError) throw customerProfilesError;

      // 3. Fetch all transactions
      const { data: dbTransactions, error: transactionsError } = await supabase
        .from('transactions')
        .select('*');

      if (transactionsError) throw transactionsError;

      // 4. Fetch all training progress
      const { data: dbTrainingProgress, error: trainingProgressError } = await supabase
        .from('training_progress')
        .select('*');

      if (trainingProgressError) throw trainingProgressError;

      // Transform db data to app's Customer, Transaction, TrainingSection types
      const transformedCustomers: Customer[] = dbCustomerProfiles.map((dbCustomer: DbCustomerProfile) => {
        const customerTransactions = dbTransactions.filter(t => t.customer_profile_id === dbCustomer.id);
        const balance = customerTransactions.reduce((sum, t) => t.type === 'recharge' ? sum + t.amount : sum - t.amount, 0);
        const totalTransactions = customerTransactions.length;

        const customerTrainingProgress = dbTrainingProgress.filter(tp => tp.customer_profile_id === dbCustomer.id);

        const trainingProgressForUI = TRAINING_LEVEL_DEFINITIONS.map(levelDef => {
          const progressEntry = customerTrainingProgress.find(p => p.level_name === levelDef.name);
          return {
            id: levelDef.id,
            dbId: progressEntry?.id || '',
            name: levelDef.name,
            requiredHours: levelDef.requiredHours,
            completedHours: progressEntry?.completed_trails || 0,
            status: progressEntry?.status || (levelDef.id === 1 ? 'Aktuell' : 'Gesperrt'),
          };
        }).sort((a, b) => a.id - b.id);

        const currentLevel = trainingProgressForUI.find(p => p.status === 'Aktuell')?.name || TrainingLevelEnum.EINSTEIGER;

        const customerAuthUser = allAuthUsers.find(u => u.id === dbCustomer.auth_user_id);
        const initials = `${dbCustomer.first_name?.charAt(0) || ''}${dbCustomer.last_name?.charAt(0) || ''}`.toUpperCase().slice(0, 2);
        const randomColor = `bg-${['blue', 'green', 'orange', 'red', 'purple', 'indigo'][Math.floor(Math.random() * 6)]}-500`;

        return {
          id: dbCustomer.id,
          authUserId: dbCustomer.auth_user_id,
          avatarInitials: initials, // Can be generated or stored
          avatarColor: randomColor, // Can be generated or stored
          firstName: dbCustomer.first_name || '',
          lastName: dbCustomer.last_name || '',
          email: customerAuthUser?.email || 'N/A', // Get email from auth.users
          phone: dbCustomer.phone || '',
          dogName: dbCustomer.dog_name || '',
          chipNumber: dbCustomer.chip_number || '',
          qrCodeData: dbCustomer.qr_code_data || '',
          balance,
          totalTransactions,
          level: currentLevel,
          createdAt: parseDateString(dbCustomer.created_at || new Date().toISOString())?.toLocaleDateString('de-DE') || '',
          documents: [], // Placeholder
          trainingProgress: trainingProgressForUI,
        };
      });
      setCustomers(transformedCustomers);

      const transformedTransactions: Transaction[] = dbTransactions.map((dbTrx: DbTransaction) => {
        const employeeUser = transformedUsers.find(u => u.id === dbTrx.created_by_user_id);
        const employeeName = employeeUser ? `${employeeUser.firstName} ${employeeUser.lastName}` : 'System';
        return {
          id: dbTrx.id,
          customerId: dbTrx.customer_profile_id,
          employeeId: dbTrx.created_by_user_id,
          type: dbTrx.type,
          description: dbTrx.description || (dbTrx.type === 'recharge' ? 'Aufladung' : 'Trails'),
          amount: dbTrx.amount,
          date: parseDateString(dbTrx.created_at)?.toLocaleDateString('de-DE') || dbTrx.created_at,
          employee: employeeName,
        };
      });
      setTransactions(transformedTransactions);

    } catch (error: any) {
      console.error('Error fetching initial data:', error.message);
      alert(`Fehler beim Laden der Daten: ${error.message}`);
    } finally {
      setIsLoadingInitialData(false);
    }
  };


  useEffect(() => {
    // Initial fetch
    fetchAllData();

    // Set up real-time listener for auth changes
    const { data: authListener } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
      // Re-fetch all data on auth state change (login/logout)
      fetchAllData();
    });

    return () => {
      authListener?.subscription.unsubscribe();
    };
  }, []); // Empty dependency array means this runs once on mount


  // Effect for initial redirection based on login status and user role
  useEffect(() => {
    if (isLoadingInitialData) return; // Wait until initial data is loaded

    if (!session) {
      if (window.location.hash !== '#/login') {
        navigate('/login', { replace: true });
      }
    } else if (currentUser) { // If logged in and currentUser is available
      if (currentUser.role === UserRoleEnum.KUNDE && currentUser.associatedCustomerId) {
        const expectedPath = `/customers/${currentUser.associatedCustomerId}`;
        if (!window.location.hash.startsWith(`#${expectedPath}`)) {
          navigate(expectedPath, { replace: true });
        }
      } else if (window.location.hash === '#/login' || window.location.hash === '#/') {
        // Redirect non-customer users from login or root to dashboard
        navigate('/', { replace: true });
      }
    }
  }, [session, currentUser, isLoadingInitialData, navigate]);


  const handleLogin = async (email: string, passwordInput: string): Promise<boolean> => {
    const { data, error } = await supabase.auth.signInWithPassword({
      email,
      password: passwordInput,
    });
    if (error) {
      console.error('Login error:', error.message);
      return false;
    }
    // Session change handled by onAuthStateChange listener, which triggers fetchAllData and re-routes
    return true;
  };

  const handleRegister = async (email: string, passwordInput: string): Promise<boolean> => {
    const { data, error } = await supabase.auth.signUp({
      email,
      password: passwordInput,
    });
    if (error) {
      console.error('Registration error:', error.message);
      return false;
    }
    // After sign up, the user is typically logged in automatically.
    // The onAuthStateChange listener will pick this up and re-fetch data/re-route.
    return true;
  };

  const handleLogout = async () => {
    const { error } = await supabase.auth.signOut();
    if (error) {
      console.error('Logout error:', error.message);
      alert('Fehler beim Abmelden.');
    } else {
      alert('Sie wurden abgemeldet.');
      // onAuthStateChange listener will handle state clear and redirection
    }
  };

  // These are passed down but will mainly trigger a full data refresh from App.tsx
  const handleUpdateCustomer = (updatedCustomer: Customer) => {
    // This now just triggers a refresh, actual DB update is in CustomerDetails
    console.log('handleUpdateCustomer triggered refresh:', updatedCustomer.id);
    fetchAllData();
  };

  const handleAddTransaction = (newTransaction: Transaction) => {
    // This now just triggers a refresh, actual DB insert is in CustomerDetails
    console.log('handleAddTransaction triggered refresh:', newTransaction.id);
    fetchAllData();
  };

  // User management functions (for Admin/Staff to manage other users)
  const handleAddUser = async (newUserData: { firstName: string; lastName: string; email: string; role: UserRoleEnum; password?: string }) => {
    try {
      if (newUserData.role === UserRoleEnum.KUNDE) {
        // For 'Kunde' role, this means creating a customer_profile linked to an EXISTING auth.user.id (from registration)
        // Or for admin/staff to create a customer profile if auth.user is known.
        // For simplicity, this function will create a customer_profile and link it to a *newly provided* authUserId if available,
        // or flag that the user must exist. The current implementation implicitly links to `authUserId` when registering.
        // If an admin wants to add a customer profile to an existing auth user, they'd use `update`.
        // This function will primarily update the users and customers state, as auth.user creation for staff/admin is server-side.

        // Create the customer_profile
        const { data: customerProfileData, error: customerProfileError } = await supabase
          .from('customer_profiles')
          .insert({
            auth_user_id: newUserData.email, // This is a temp placeholder, should be actual auth.user.id
            first_name: newUserData.firstName,
            last_name: newUserData.lastName,
            qr_code_data: `https://example.com/customer/${newUserData.email}`, // Placeholder QR
            // Other fields default or are empty
          })
          .select()
          .single();

        if (customerProfileError) throw customerProfileError;

        alert(`Kundenprofil für ${newUserData.email} erstellt. Bitte beachten Sie, dass die E-Mail-Adresse eine vorhandene Supabase Auth User ID sein sollte, um richtig zu funktionieren.`);
      } else {
        alert('Erstellung von Admin/Mitarbeiter-Benutzern ist nur über die Supabase-Verwaltungskonsole oder serverseitig möglich.');
      }
      fetchAllData(); // Refresh all data
    } catch (error: any) {
      console.error('Error adding user/customer profile:', error.message);
      alert(`Fehler beim Hinzufügen des Benutzers: ${error.message}`);
    }
  };

  const handleUpdateUser = async (updatedUser: User) => {
    try {
      // Update role in public.profiles
      const { error: profileUpdateError } = await supabase
        .from('profiles')
        .update({ role: updatedUser.role })
        .eq('user_id', updatedUser.id);

      if (profileUpdateError) throw profileUpdateError;

      // If it's a customer, update customer_profiles details
      if (updatedUser.role === UserRoleEnum.KUNDE && updatedUser.associatedCustomerId) {
        const { error: customerProfileUpdateError } = await supabase
          .from('customer_profiles')
          .update({
            first_name: updatedUser.firstName,
            last_name: updatedUser.lastName,
            email: updatedUser.email, // Assuming email can be updated here, though auth.users email is separate
          })
          .eq('id', updatedUser.associatedCustomerId);

        if (customerProfileUpdateError) throw customerProfileUpdateError;
      }
      alert('Benutzer erfolgreich aktualisiert.');
      fetchAllData(); // Refresh all data
    } catch (error: any) {
      console.error('Error updating user:', error.message);
      alert(`Fehler beim Aktualisieren des Benutzers: ${error.message}`);
    }
  };

  const handleDeleteUser = async (userId: string) => {
    try {
      // Find the user to delete
      const userToDelete = users.find(u => u.id === userId);
      if (!userToDelete) throw new Error('Benutzer nicht gefunden.');

      if (userToDelete.id === currentUser?.id) {
        alert('Sie können sich nicht selbst löschen. Bitte melden Sie sich ab und löschen Sie den Account ggf. direkt in Supabase.');
        return;
      }

      // If it's a customer, also delete their customer_profile
      if (userToDelete.role === UserRoleEnum.KUNDE && userToDelete.associatedCustomerId) {
        const { error: customerDeleteError } = await supabase
          .from('customer_profiles')
          .delete()
          .eq('id', userToDelete.associatedCustomerId);
        if (customerDeleteError) throw customerDeleteError;
      }

      // Delete the profile entry (role)
      const { error: profileDeleteError } = await supabase
        .from('profiles')
        .delete()
        .eq('user_id', userId);

      if (profileDeleteError) throw profileDeleteError;

      // NOTE: Deleting the actual auth.user for *other* users requires a service role key
      // and should ideally be handled on the server for security.
      // For this client-side demo, we only remove the profile and customer_profile,
      // effectively deactivating their app access. The auth.user record remains in Supabase.
      alert('Benutzerprofil und zugehörige Daten erfolgreich gelöscht (Auth.user bleibt bestehen).');
      fetchAllData(); // Refresh all data

    } catch (error: any) {
      console.error('Error deleting user:', error.message);
      alert(`Fehler beim Löschen des Benutzers: ${error.message}`);
    }
  };


  if (isLoadingInitialData) {
    return (
      <div className="flex items-center justify-center min-h-screen bg-gray-100">
        <div className="text-xl text-gray-700">Lade Anwendungsdaten...</div>
      </div>
    );
  }

  return (
    <div className="flex min-h-screen bg-gray-100">
      {session && currentUser ? (
        <>
          <Sidebar appName="Mantrailing Card" currentUser={currentUser} onLogout={handleLogout} />
          <main className="flex-1 md:ml-64 p-0">
            <Routes>
              {currentUser.role === UserRoleEnum.ADMIN ? (
                // Admin has full access
                <>
                  <Route path="/" element={<Dashboard customers={customers} transactions={transactions} currentUser={currentUser} />} />
                  <Route path="/customers" element={<CustomerManagement customers={customers} transactions={transactions} currentUser={currentUser} />} />
                  <Route
                    path="/customers/:id"
                    element={<CustomerDetails customers={customers} allTransactions={transactions} onUpdateCustomer={handleUpdateCustomer} onAddTransaction={handleAddTransaction} currentUser={currentUser} onRefreshData={fetchAllData} />}
                  />
                  <Route path="/reports" element={<Reports customers={customers} transactions={transactions} users={users} />} />
                  <Route path="/users" element={<UserManagement users={users} onAddUser={handleAddUser} onUpdateUser={handleUpdateUser} onDeleteUser={handleDeleteUser} currentUser={currentUser} />} />
                  <Route path="*" element={<Dashboard customers={customers} transactions={transactions} currentUser={currentUser} />} />
                </>
              ) : currentUser.role === UserRoleEnum.MITARBEITER ? (
                // Mitarbeiter has restricted access
                <>
                  <Route path="/" element={<Dashboard customers={customers} transactions={transactions} currentUser={currentUser} />} />
                  <Route path="/customers" element={<CustomerManagement customers={customers} transactions={transactions} currentUser={currentUser} />} />
                  <Route
                    path="/customers/:id"
                    element={<CustomerDetails customers={customers} allTransactions={transactions} onUpdateCustomer={handleUpdateCustomer} onAddTransaction={handleAddTransaction} currentUser={currentUser} onRefreshData={fetchAllData} />}
                  />
                  {/* Redirect any restricted path or unknown path for Mitarbeiter to dashboard */}
                  <Route path="/reports" element={<Reports customers={customers} transactions={transactions} users={users} />} />
                  <Route path="/users" element={<Dashboard customers={customers} transactions={transactions} currentUser={currentUser} />} />
                  <Route path="*" element={<Dashboard customers={customers} transactions={transactions} currentUser={currentUser} />} />
                </>
              ) : currentUser.role === UserRoleEnum.KUNDE && currentUser.associatedCustomerId ? (
                // Kunde has access only to their own customer details
                <>
                  <Route
                    path="/customers/:id"
                    element={<CustomerDetails customers={customers} allTransactions={transactions} onUpdateCustomer={handleUpdateCustomer} onAddTransaction={handleAddTransaction} currentUser={currentUser} onRefreshData={fetchAllData} />}
                  />
                  <Route path="/" element={<Navigate replace to={`/customers/${currentUser.associatedCustomerId}`} />} />
                  <Route path="*" element={<Navigate replace to={`/customers/${currentUser.associatedCustomerId}`} />} />
                </>
              ) : (
                // Fallback for any other unexpected logged-in state (should ideally not happen)
                <Route path="*" element={<Dashboard customers={customers} transactions={transactions} currentUser={currentUser} />} />
              )}
            </Routes>
          </main>
        </>
      ) : (
        // Not logged in
        <Routes>
          <Route path="/login" element={<LoginPage onLogin={handleLogin} onRegister={handleRegister} />} />
          <Route path="*" element={<LoginPage onLogin={handleLogin} onRegister={handleRegister} />} />
        </Routes>
      )}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import Card from '../components/Card';
import Button from '../components/Button';
import Avatar from '../components/Avatar';
import UserFormModal from '../components/UserFormModal';
import UserDeleteConfirmationModal from '../components/UserDeleteConfirmationModal';
import { EditIcon, TrashIcon, UserPlusIcon, ChevronDownIcon } from '../components/Icons';
import { User, UserRoleEnum } from '../types';
import { REFERENCE_DATE } from '../constants'; // Only REFERENCE_DATE remains

interface UserManagementProps {
  users: User[]; // All users including admin, staff, and customer from App.tsx state
  onAddUser: (newUser: { firstName: string; lastName: string; email: string; role: UserRoleEnum; password?: string }) => Promise<void>;
  onUpdateUser: (updatedUser: User) => Promise<void>;
  onDeleteUser: (userId: string) => Promise<void>;
  currentUser: User | null; // Current logged-in user to check permissions
}

const UserManagement: React.FC<UserManagementProps> = ({ users, onAddUser, onUpdateUser, onDeleteUser, currentUser }) => {
  const [showUserFormModal, setShowUserFormModal] = useState(false);
  const [userToEdit, setUserToEdit] = useState<User | null>(null);
  const [showDeleteConfirmationModal, setShowDeleteConfirmationModal] = useState(false);
  const [userToDeleteId, setUserToDeleteId] = useState<string | null>(null);

  // State to manage expanded/collapsed sections for each role
  const [expandedRoles, setExpandedRoles] = useState<Record<UserRoleEnum, boolean>>({
    [UserRoleEnum.ADMIN]: true, // Admins expanded by default
    [UserRoleEnum.MITARBEITER]: false,
    [UserRoleEnum.KUNDE]: false,
  });

  const toggleRoleSection = (role: UserRoleEnum) => {
    setExpandedRoles(prev => ({
      ...prev,
      [role]: !prev[role],
    }));
  };

  const handleOpenAddUserModal = () => {
    setUserToEdit(null);
    setShowUserFormModal(true);
  };

  const handleOpenEditUserModal = (user: User) => {
    setUserToEdit(user);
    setShowUserFormModal(true);
  };

  const handleCloseUserFormModal = () => {
    setShowUserFormModal(false);
    setUserToEdit(null);
  };

  const handleSubmitUserForm = async (userData: { firstName: string; lastName: string; email: string; role: UserRoleEnum; password?: string }) => {
    if (!currentUser) return; // Should not happen if this component is rendered

    try {
      if (userToEdit) {
        // Editing existing user
        const updatedUser: User = {
          ...userToEdit,
          firstName: userData.firstName,
          lastName: userData.lastName,
          email: userData.email,
          role: userData.role,
          // Password field from form is ignored here; password changes are not handled via this form for existing auth.users
        };
        await onUpdateUser(updatedUser);
      } else {
        // Creating new user (only for customers from this UI, other roles are admin-only in Supabase)
        if (userData.role !== UserRoleEnum.KUNDE) {
          alert('Erstellung von Admin/Mitarbeiter-Benutzern ist nur über die Supabase-Verwaltungskonsole oder serverseitig möglich.');
          return;
        }

        // For new customer users, we create a new auth.user (via registration page ideally)
        // For simplicity, if an admin is adding a new "Kunde" here, they'd conceptually provide an email that
        // already corresponds to an existing auth.user (e.g. they registered themselves).
        // This 'onAddUser' call will update the local state and ideally trigger customer_profile creation if needed.
        const newUserId = `temp-${Date.now()}`; // Placeholder for now, real ID comes from auth.user
        const initials = `${userData.firstName.charAt(0)}${userData.lastName.charAt(0)}`.toUpperCase().slice(0, 2);
        const avatarColors = ['bg-red-500', 'bg-orange-500', 'bg-purple-500', 'bg-indigo-500', 'bg-blue-500', 'bg-green-500', 'bg-teal-500', 'bg-fuchsia-500', 'bg-lime-500'];
        const randomColor = avatarColors[Math.floor(Math.random() * avatarColors.length)];

        // This is primarily for adding a *customer profile* for an existing auth.user if not linked.
        // It's not creating an auth.user from scratch.
        const newUserToCreate: { firstName: string; lastName: string; email: string; role: UserRoleEnum; password?: string; } = {
          ...userData,
          // associatedCustomerId: newUserId, // For a new customer, this will be created by App.tsx
        };
        await onAddUser(newUserToCreate);
      }
      handleCloseUserFormModal();
    } catch (error: any) {
      console.error('Error submitting user form:', error.message);
      alert(`Fehler beim Speichern des Benutzers: ${error.message}`);
    }
  };

  const handleOpenDeleteConfirmation = (userId: string) => {
    setUserToDeleteId(userId);
    setShowDeleteConfirmationModal(true);
  };

  const handleConfirmDelete = async () => {
    if (userToDeleteId) {
      try {
        await onDeleteUser(userToDeleteId);
        alert('Benutzer erfolgreich gelöscht.');
      } catch (error: any) {
        console.error('Error during delete confirmation:', error.message);
        alert(`Fehler beim Löschen des Benutzers: ${error.message}`);
      }
    }
    setShowDeleteConfirmationModal(false);
    setUserToDeleteId(null);
  };

  const handleCloseDeleteConfirmation = () => {
    setShowDeleteConfirmationModal(false);
    setUserToDeleteId(null);
  };

  const getRoleColorClass = (role: UserRoleEnum) => {
    switch (role) {
      case UserRoleEnum.ADMIN:
        return 'bg-red-100 text-red-800';
      case UserRoleEnum.MITARBEITER:
        return 'bg-blue-100 text-blue-800';
      case UserRoleEnum.KUNDE:
        return 'bg-teal-100 text-teal-800';
      default:
        return 'bg-gray-100 text-gray-800';
    }
  };

  // Filter users by role
  const adminUsers = users.filter(user => user.role === UserRoleEnum.ADMIN);
  const mitarbeiterUsers = users.filter(user => user.role === UserRoleEnum.MITARBEITER);
  const kundeUsers = users.filter(user => user.role === UserRoleEnum.KUNDE);


  interface UserRoleSectionProps {
    title: string;
    role: UserRoleEnum;
    users: User[];
    isExpanded: boolean;
    onToggle: (role: UserRoleEnum) => void;
    onOpenEditUserModal: (user: User) => void;
    onOpenDeleteConfirmation: (userId: string) => void;
    currentLoggedInUser: User | null; // To check if user is editing/deleting themselves
  }

  const UserRoleSection: React.FC<UserRoleSectionProps> = ({
    title,
    role,
    users,
    isExpanded,
    onToggle,
    onOpenEditUserModal,
    onOpenDeleteConfirmation,
    currentLoggedInUser,
  }) => {
    return (
      <Card padding="none" className="overflow-hidden">
        <button
          className="flex items-center justify-between w-full p-4 bg-gray-50 hover:bg-gray-100 transition-colors duration-200"
          onClick={() => onToggle(role)}
          aria-expanded={isExpanded}
          aria-controls={`user-list-${role}`}
        >
          <h2 className="text-xl font-semibold text-gray-900 flex items-center">
            {title}
            <span className={`ml-3 px-2.5 py-0.5 rounded-full text-xs font-medium ${getRoleColorClass(role)}`}>
              {users.length}
            </span>
          </h2>
          <ChevronDownIcon className={`h-6 w-6 text-gray-500 transition-transform duration-200 ${isExpanded ? 'rotate-180' : ''}`} />
        </button>

        {isExpanded && (
          <div id={`user-list-${role}`} className={`p-4 border-t border-gray-200 ${users.length > 5 ? 'max-h-96 overflow-y-auto custom-scrollbar' : ''}`}>
            {users.length === 0 ? (
              <p className="text-gray-500 text-sm py-4 text-center">Keine Benutzer in dieser Rolle gefunden.</p>
            ) : (
              <div className="divide-y divide-gray-200">
                {users.map(user => (
                  <div key={user.id} className="flex items-center justify-between py-3">
                    <div className="flex items-center">
                      <Avatar initials={user.avatarInitials} color={user.avatarColor} size="md" className="mr-3" />
                      <div>
                        <p className="font-medium text-gray-900">{user.firstName} {user.lastName}</p>
                        <p className="text-sm text-gray-500">{user.email}</p>
                      </div>
                    </div>
                    <div className="flex items-center space-x-3">
                      <button
                        onClick={(e) => { e.stopPropagation(); onOpenEditUserModal(user); }}
                        className="text-gray-500 hover:text-blue-600"
                        aria-label={`Benutzer ${user.firstName} ${user.lastName} bearbeiten`}
                        disabled={user.id === currentLoggedInUser?.id} // Cannot edit own role/profile via this form
                      >
                        <EditIcon className="h-5 w-5" />
                      </button>
                      <button
                        onClick={(e) => { e.stopPropagation(); onOpenDeleteConfirmation(user.id); }}
                        className="text-gray-500 hover:text-red-600"
                        aria-label={`Benutzer ${user.firstName} ${user.lastName} löschen`}
                        disabled={user.id === currentLoggedInUser?.id} // Cannot delete self
                      >
                        <TrashIcon className="h-5 w-5" />
                      </button>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        )}
      </Card>
    );
  };


  const userToDelete = users.find(u => u.id === userToDeleteId);

  return (
    <div className="p-6 md:p-8 lg:p-10">
      <div className="flex justify-between items-center mb-2">
        <div>
          <h1 className="text-3xl font-bold text-gray-900">Benutzerverwaltung</h1>
          <p className="text-gray-600">Verwalten Sie alle Systembenutzer an einem Ort</p>
        </div>
        <Button variant="success" icon={UserPlusIcon} onClick={handleOpenAddUserModal}>
          Neuer Benutzer (Kunde)
        </Button>
      </div>

      <div className="mt-8 space-y-6">
        <UserRoleSection
          title="Administratoren"
          role={UserRoleEnum.ADMIN}
          users={adminUsers}
          isExpanded={expandedRoles[UserRoleEnum.ADMIN]}
          onToggle={toggleRoleSection}
          onOpenEditUserModal={handleOpenEditUserModal}
          onOpenDeleteConfirmation={handleOpenDeleteConfirmation}
          currentLoggedInUser={currentUser}
        />
        <UserRoleSection
          title="Mitarbeiter"
          role={UserRoleEnum.MITARBEITER}
          users={mitarbeiterUsers}
          isExpanded={expandedRoles[UserRoleEnum.MITARBEITER]}
          onToggle={toggleRoleSection}
          onOpenEditUserModal={handleOpenEditUserModal}
          onOpenDeleteConfirmation={handleOpenDeleteConfirmation}
          currentLoggedInUser={currentUser}
        />
        <UserRoleSection
          title="Kunden"
          role={UserRoleEnum.KUNDE}
          users={kundeUsers}
          isExpanded={expandedRoles[UserRoleEnum.KUNDE]}
          onToggle={toggleRoleSection}
          onOpenEditUserModal={handleOpenEditUserModal}
          onOpenDeleteConfirmation={handleOpenDeleteConfirmation}
          currentLoggedInUser={currentUser}
        />
      </div>


      <UserFormModal
        isOpen={showUserFormModal}
        onClose={handleCloseUserFormModal}
        onSubmit={handleSubmitUserForm}
        userToEdit={userToEdit}
        currentUserRole={currentUser?.role || UserRoleEnum.KUNDE} // Pass current user role
      />

      <UserDeleteConfirmationModal
        isOpen={showDeleteConfirmationModal}
        onClose={handleCloseDeleteConfirmation}
        onConfirm={handleConfirmDelete}
        userNameToDelete={userToDelete ? `${userToDelete.firstName} ${userToDelete.lastName}`.trim() : ''}
      />
    </div>
  );
};

export default UserManagement;

