// Dies ist die Client-Seite, die mit Ihren (extern zu implementierenden) Supabase Edge Functions
// oder einer anderen Backend-API kommunizieren würde, um Admin-Operationen durchzuführen.
// Der SUPABASE_URL wird hier vom Client-Setup übernommen. Für die Edge Functions selbst
// müsste der Service Role Key als Geheimnis (Environment Variable) konfiguriert werden.

const SUPABASE_API_URL = process.env.SUPABASE_URL; // Beispiel für die Basis-URL Ihrer Supabase-Instanz

interface InviteUserResponse {
  message: string;
  userEmail?: string;
  resetPasswordUrl?: string; // Supabase invite/reset link
}

interface UserAPIResponse {
  id: string;
  email: string;
  role: 'admin' | 'staff' | 'customer';
  created_at: string;
  customer_profile?: {
    id: string;
    first_name: string | null;
    last_name: string | null;
  } | null;
}

/**
 * Ruft alle Anwendungsbenutzer über eine serverseitige API ab.
 * Diese API-Route sollte supabase.auth.admin.listUsers() verwenden und Profile verknüpfen.
 * @returns Promise<UserAPIResponse[]>
 */
export async function getAllAppUsers(): Promise<UserAPIResponse[]> {
  try {
    // Annahme: Sie haben eine Edge Function 'get-all-users' bereitgestellt
    // unter https://[Ihre-Projekt-ID].supabase.co/functions/v1/get-all-users
    const response = await fetch(`${SUPABASE_API_URL}/functions/v1/get-all-users`, {
      method: 'GET',
      headers: {
        'Content-Type': 'application/json',
        // 'Authorization': `Bearer ${await supabase.auth.getSession().then(s => s.data.session?.access_token)}`,
        // Auth-Header hier nicht unbedingt notwendig, wenn die Edge Function selbst den Service Role Key verwendet
        // oder eine API-Schlüssel-Authentifizierung für Edge Functions genutzt wird.
        // Für dieses Beispiel gehen wir davon aus, dass die Edge Function intern authentifiziert ist.
      },
    });

    if (!response.ok) {
      const errorData = await response.json();
      throw new Error(errorData.message || `Fehler beim Abrufen aller Benutzer: ${response.statusText}`);
    }

    const data: UserAPIResponse[] = await response.json();
    return data;
  } catch (error: any) {
    console.error('Fehler in getAllAppUsers:', error.message);
    throw error;
  }
}


/**
 * Lädt einen neuen Admin- oder Mitarbeiter-Benutzer über eine serverseitige API ein.
 * Diese API-Route sollte supabase.auth.admin.inviteUserByEmail() verwenden und die Rolle setzen.
 * @param email Die E-Mail-Adresse des einzuladenden Benutzers.
 * @param role Die Rolle des Benutzers ('admin' oder 'staff').
 * @returns Promise<InviteUserResponse>
 */
export async function inviteUser(email: string, role: 'admin' | 'staff'): Promise<InviteUserResponse> {
  try {
    // Annahme: Sie haben eine Edge Function 'invite-user' bereitgestellt
    // unter https://[Ihre-Projekt-ID].supabase.co/functions/v1/invite-user
    const response = await fetch(`${SUPABASE_API_URL}/functions/v1/invite-user`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        // Hier könnte ein Auth-Header nötig sein, um die Edge Function aufzurufen,
        // falls sie nicht öffentlich ist, aber der Service Role Key in der Edge Function
        // übernimmt die eigentliche Admin-Auth.
        // Für dieses Beispiel gehen wir davon aus, dass die Edge Function intern authentifiziert ist.
      },
      body: JSON.stringify({ email, role }),
    });

    if (!response.ok) {
      const errorData = await response.json();
      throw new Error(errorData.message || `Fehler beim Einladen des Benutzers: ${response.statusText}`);
    }

    const data: InviteUserResponse = await response.json();
    return data;
  } catch (error: any) {
    console.error('Fehler in inviteUser:', error.message);
    throw error;
  }
}

/**
 * Aktualisiert einen vorhandenen Benutzer über eine serverseitige API.
 * Diese API-Route sollte supabase.auth.admin.updateUserById() und profiles.update() verwenden.
 * @param userId Die ID des zu aktualisierenden Benutzers.
 * @param updates Die zu aktualisierenden Felder (z.B. { email: 'new@example.com', role: 'admin' }).
 * @returns Promise<void>
 */
export async function updateAppUser(userId: string, updates: { email?: string; role?: 'admin' | 'staff' | 'customer'; firstName?: string; lastName?: string; associatedCustomerId?: string }): Promise<void> {
  try {
    // Annahme: Sie haben eine Edge Function 'update-user' bereitgestellt
    // unter https://[Ihre-Projekt-ID].supabase.co/functions/v1/update-user
    const response = await fetch(`${SUPABASE_API_URL}/functions/v1/update-user`, {
      method: 'POST', // Oder PUT, je nach API-Design
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({ userId, updates }),
    });

    if (!response.ok) {
      const errorData = await response.json();
      throw new Error(errorData.message || `Fehler beim Aktualisieren des Benutzers: ${response.statusText}`);
    }
    // Keine Rückgabe notwendig, da die Änderungen in App.tsx über fetchAllData aktualisiert werden
  } catch (error: any) {
    console.error('Fehler in updateAppUser:', error.message);
    throw error;
  }
}


/**
 * Löscht einen Benutzer über eine serverseitige API.
 * Diese API-Route sollte supabase.auth.admin.deleteUser() und zugehörige Profil-Einträge löschen.
 * @param userId Die ID des zu löschenden Benutzers.
 * @returns Promise<void>
 */
export async function deleteAppUser(userId: string): Promise<void> {
  try {
    // Annahme: Sie haben eine Edge Function 'delete-user' bereitgestellt
    // unter https://[Ihre-Projekt-ID].supabase.co/functions/v1/delete-user
    const response = await fetch(`${SUPABASE_API_URL}/functions/v1/delete-user`, {
      method: 'POST', // Oder DELETE, je nach API-Design
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({ userId }),
    });

    if (!response.ok) {
      const errorData = await response.json();
      throw new Error(errorData.message || `Fehler beim Löschen des Benutzers: ${response.statusText}`);
    }
  } catch (error: any) {
    console.error('Fehler in deleteAppUser:', error.message);
    throw error;
  }
}


