import React, { useState, useEffect } from 'react';
import Modal from './Modal';
import Button from './Button';
import Input from './Input';
import Select from './Select';
import { User, UserRoleEnum } from '../types';

interface UserFormModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSubmit: (userData: { firstName: string; lastName: string; email: string; role: UserRoleEnum; password?: string }) => void;
  userToEdit: User | null;
  currentUserRole: UserRoleEnum; // Aktuelle Benutzerrolle übergeben, um die Rollenauswahl einzuschränken
}

const UserFormModal: React.FC<UserFormModalProps> = ({ isOpen, onClose, onSubmit, userToEdit, currentUserRole }) => {
  const [firstName, setFirstName] = useState('');
  const [lastName, setLastName] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState(''); // Status für Passwort
  const [role, setRole] = useState<UserRoleEnum>(UserRoleEnum.KUNDE); // Standard auf Kunde setzen
  const [firstNameError, setFirstNameError] = useState('');
  const [lastNameError, setLastNameError] = useState('');
  const [emailError, setEmailError] = useState('');
  const [passwordError, setPasswordError] = useState(''); // Status für Passwortfehler

  useEffect(() => {
    if (userToEdit) {
      setFirstName(userToEdit.firstName);
      setLastName(userToEdit.lastName);
      setEmail(userToEdit.email);
      setRole(userToEdit.role);
      setPassword(''); // Passwortfeld beim Bearbeiten aus Sicherheitsgründen leeren
    } else {
      // Formular für neuen Benutzer zurücksetzen
      setFirstName('');
      setLastName('');
      setEmail('');
      setPassword('');
      setRole(UserRoleEnum.KUNDE); // Standard auf Kunde setzen für neue Benutzer über dieses Formular
    }
    setFirstNameError('');
    setLastNameError('');
    setEmailError('');
    setPasswordError(''); // Passwortfehler leeren
  }, [userToEdit, isOpen]); // Zurücksetzen, wenn Modal geöffnet wird oder userToEdit sich ändert

  const validateForm = () => {
    let isValid = true;
    if (!firstName.trim() && role === UserRoleEnum.KUNDE) { // Vorname nur für Kunden erforderlich
      setFirstNameError('Vorname ist erforderlich.');
      isValid = false;
    } else {
      setFirstNameError('');
    }

    if (!lastName.trim() && role === UserRoleEnum.KUNDE) { // Nachname nur für Kunden erforderlich
      setLastNameError('Nachname ist erforderlich.');
      isValid = false;
    } else {
      setLastNameError('');
    }

    if (!email.trim()) {
      setEmailError('E-Mail ist erforderlich.');
      isValid = false;
    } else if (!/\S+@\S+\.\S+/.test(email)) { // Grundlegende E-Mail-Formatvalidierung
      setEmailError('Ungültiges E-Mail-Format.');
      isValid = false;
    } else {
      setEmailError('');
    }

    // Passwort ist nur für neue Admin/Mitarbeiter-Einladungen relevant (nicht direkt hier gesetzt),
    // oder wenn ein Kunde sein Passwort ändert. Für die Erstellung von Admin/Mitarbeiter über dieses Formular
    // wird ein Invite-Flow erwartet, bei dem das Passwort nicht direkt hier eingegeben wird.
    if (!userToEdit && (role === UserRoleEnum.ADMIN || role === UserRoleEnum.MITARBEITER) && !password.trim()) {
      // Passwörter werden für Admin/Mitarbeiter nicht direkt im Frontend gesetzt,
      // sondern über den Supabase Invite-Flow. Das Feld kann leer bleiben.
      setPasswordError(''); // Keine Fehlermeldung, da Invite-Link verwendet wird
    } else if (password.trim() && password.length < 6) {
      setPasswordError('Passwort muss mindestens 6 Zeichen lang sein.');
      isValid = false;
    } else {
      setPasswordError('');
    }

    return isValid;
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (validateForm()) {
      onSubmit({ firstName, lastName, email, role, password: password.trim() || undefined });
    }
  };

  const title = userToEdit ? 'Benutzer bearbeiten' : 'Neuen Benutzer einladen / Kundenprofil erstellen';

  // Rollenoptionen basierend auf der Rolle des aktuellen Benutzers filtern
  const roleOptions = [
    { value: UserRoleEnum.ADMIN, label: 'Admin' },
    { value: UserRoleEnum.MITARBEITER, label: 'Mitarbeiter' },
    { value: UserRoleEnum.KUNDE, label: 'Kunde' },
  ].filter(option => {
    // Nur Admins können andere Admins oder sich selbst als Admin bearbeiten
    if (currentUserRole !== UserRoleEnum.ADMIN && option.value === UserRoleEnum.ADMIN) {
      return false; // Nur Admin kann Admin-Rolle setzen
    }
    return true;
  });

  return (
    <Modal isOpen={isOpen} onClose={onClose} title={title} className="max-w-md">
      <form onSubmit={handleSubmit} className="p-0">
        <div className="space-y-4">
          <Input
            id="userEmail"
            label="E-Mail"
            type="email"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            placeholder="max.mustermann@example.com"
            error={emailError}
            // E-Mail ist für neue Benutzer (Einladung) bearbeitbar.
            // Für die Bearbeitung vorhandener Admin/Mitarbeiter-E-Mails sollte dies über die Backend-API gehen.
            // Für Kunden ist die E-Mail read-only in CustomerDetails.tsx, hier ist es für das Aktualisieren der Auth-E-Mail vorgesehen.
            disabled={!!userToEdit && (userToEdit.role === UserRoleEnum.ADMIN || userToEdit.role === UserRoleEnum.MITARBEITER)} // E-Mail für Admin/Mitarbeiter nur über Invite-Flow ändern
          />
          {(role === UserRoleEnum.KUNDE || userToEdit?.role === UserRoleEnum.KUNDE) && ( // Nur für Kunden ist Name direkt hier relevant
            <>
              <Input
                id="userFirstName"
                label="Vorname"
                type="text"
                value={firstName}
                onChange={(e) => setFirstName(e.target.value)}
                placeholder="Max"
                error={firstNameError}
              />
              <Input
                id="userLastName"
                label="Nachname"
                type="text"
                value={lastName}
                onChange={(e) => setLastName(e.target.value)}
                placeholder="Mustermann"
                error={lastNameError}
              />
            </>
          )}

          {/* Passwortfeld nur anzeigen, wenn es sich um einen NEUEN Kunden handelt ODER der BEIM BEARBEITEN
              EINES KUNDEN ein Passwort setzen/ändern möchte. Bei Admin/Mitarbeiter-Einladung kommt das Passwort
              über den Invite-Link. */}
          {(!userToEdit && role === UserRoleEnum.KUNDE) || (userToEdit && userToEdit.role === UserRoleEnum.KUNDE) ? (
            <Input
              id="userPassword"
              label="Passwort (nur für neue Kunden-Registrierung oder optional ändern)"
              type="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder="Passwort"
              error={passwordError}
              // Disabled wenn es sich um Admin/Mitarbeiter handelt, da Invite-Link verwendet wird
              disabled={!!userToEdit && (userToEdit.role === UserRoleEnum.ADMIN || userToEdit.role === UserRoleEnum.MITARBEITER)}
            />
          ) : (
            <p className="text-sm text-gray-500">
              Für Admin/Mitarbeiter wird ein Einladungslink per E-Mail gesendet, um das Passwort zu setzen.
            </p>
          )}

          <Select
            id="userRole"
            label="Rolle"
            options={roleOptions}
            value={role}
            onChange={(e) => setRole(e.target.value as UserRoleEnum)}
            disabled={currentUserRole !== UserRoleEnum.ADMIN} // Nur Admins dürfen Rollen ändern
          />
        </div>
        <div className="p-4 border-t border-gray-200 mt-6 flex justify-end space-x-3">
          <Button variant="outline" onClick={onClose} type="button">
            Abbrechen
          </Button>
          <Button variant="success" type="submit">
            Speichern
          </Button>
        </div>
      </form>
    </Modal>
  );
};

