import React from 'react';


export interface DbCustomerProfile {
  id: string; // PK
  auth_user_id: string | null; // FK to auth.users.id
  first_name: string | null;
  last_name: string | null;
  phone: string | null;
  dog_name: string | null;
  chip_number: string | null;
  qr_code_data: string | null;
  // Assuming a created_at field is present or handled by Supabase default.
  // If not, this can be derived from auth.users.created_at or omitted.
  created_at?: string;
}

export interface DbProfile {
  user_id: string; // PK, FK to auth.users.id
  role: UserRoleEnum;
}

export interface DbTransaction {
  id: string; // PK
  customer_profile_id: string; // FK to customer_profiles.id
  created_by_user_id: string | null; // FK to auth.users.id
  type: 'recharge' | 'debit';
  description: string | null;
  amount: number;
  created_at: string;
}

export interface DbTrainingProgress {
  id: string; // PK
  customer_profile_id: string; // FK to customer_profiles.id
  level_name: TrainingLevelEnum;
  completed_trails: number;
  status: 'Aktuell' | 'Gesperrt' | 'Abgeschlossen';
}

export interface Customer {
  id: string; // customer_profile.id
  authUserId: string | null; // customer_profile.auth_user_id
  avatarInitials: string;
  avatarColor: string;
  firstName: string; // customer_profile.first_name
  lastName: string; // customer_profile.last_name
  email: string; // from auth.users or customer_profile (if denormalized)
  phone: string; // customer_profile.phone
  dogName: string; // customer_profile.dog_name
  chipNumber: string; // customer_profile.chip_number
  balance: number; // Calculated from transactions
  totalTransactions: number; // Calculated from transactions
  level: TrainingLevelEnum; // Derived from trainingProgress
  createdAt: string; // customer_profile.created_at (formatted)
  qrCodeData: string; // customer_profile.qr_code_data
  documents: Document[]; // Still mock/placeholder, not from DB
  trainingProgress: TrainingSection[]; // Derived from DbTrainingProgress
}

export interface Transaction {
  id: string; // transactions.id
  customerId: string; // transactions.customer_profile_id
  employeeId: string | null; // transactions.created_by_user_id
  type: 'recharge' | 'debit';
  description: string; // transactions.description
  amount: number;
  date: string; // transactions.created_at (formatted)
  employee: string; // Derived from employeeId and user data
}

export enum TrainingLevelEnum {
  EINSTEIGER = 'Einsteiger',
  GRUNDLAGEN = 'Grundlagen',
  FORTGESCHRITTENE = 'Fortgeschrittene',
  MASTERCLASS = 'Masterclass',
  EXPERT = 'Expert',
}

export interface TrainingSection {
  id: number; // Logical order ID (1, 2, 3, etc.)
  dbId: string; // training_progress.id (actual PK in DB)
  name: TrainingLevelEnum;
  requiredHours: number;
  completedHours: number; // training_progress.completed_trails
  status: 'Aktuell' | 'Gesperrt' | 'Abgeschlossen';
}

export interface Document {
  id: string;
  name: string;
  url: string;
}

export interface StatCardProps {
  title: string;
  value: string | number;
  icon: React.ElementType; // SVG component
  color: string; // Tailwind color class
  description?: string;
}

export interface NavigationItem {
  path: string;
  label: string;
  icon: React.ElementType; // SVG component
}

export interface CustomerTableData {
  id: string;
  avatarInitials: string;
  avatarColor: string;
  name: string;
  dog: string;
  balance: number;
  level: TrainingLevelEnum;
  createdAt: string;
}

export interface TransactionConfirmationData {
  customerId: string;
  customerName: string;
  employee: string;
  transactionType: 'Aufladung' | 'Abbuchung';
  amount: number;
  oldBalance: number;
  newBalance: number;
  description?: string; // Optional description for the transaction, especially for debits
}

export enum UserRoleEnum {
  ADMIN = 'admin', // Matches SQL enum
  MITARBEITER = 'staff', // Matches SQL enum
  KUNDE = 'customer', // Matches SQL enum
}

// Schnittstelle für die Antwort von der Backend-API für alle Benutzer
export interface FullUserResponse {
  id: string;
  email: string;
  role: UserRoleEnum; // Verwenden Sie UserRoleEnum
  created_at: string;
  customer_profile: {
    id: string;
    first_name: string | null;
    last_name: string | null;
  } | null;
}

export interface User {
  id: string; // auth.users.id
  avatarInitials: string;
  avatarColor: string;
  firstName: string;
  lastName: string;
  email: string;
  role: UserRoleEnum; // public.profiles.role
  createdAt: string; // auth.users.created_at (formatted)
  associatedCustomerId?: string; // Optional: for customer role, links to their customer ID
}

export interface UserTableData {
  id: string;
  avatarInitials: string;
  avatarColor: string;
  name: string; // Derived from firstName and lastName for display in table
  firstName: string; // Added for internal use
  lastName: string;  // Added for internal use
  email: string;
  role: UserRoleEnum;
  createdAt: string;
}

import React, { useState, useEffect } from 'react';
import { Routes, Route, useNavigate, Navigate } from 'react-router-dom';
import Sidebar from './components/Sidebar';
import Dashboard from './pages/Dashboard';
import CustomerManagement from './pages/CustomerManagement';
import CustomerDetails from './pages/CustomerDetails';
import Reports from './pages/Reports';
import UserManagement from './pages/UserManagement';
import LoginPage from './pages/LoginPage';
import { Customer, Transaction, TrainingLevelEnum, User, UserRoleEnum, DbCustomerProfile, DbTransaction, DbTrainingProgress, FullUserResponse } from './types';
import { REFERENCE_DATE, TRAINING_LEVEL_DEFINITIONS } from './constants'; // ADMIN_STAFF_USER_DETAILS entfernt
import { supabase } from './supabaseClient';
import { parseDateString } from './utils';
import { getAllAppUsers, inviteUser, updateAppUser, deleteAppUser } from './api'; // Import der neuen API-Funktionen

const App: React.FC = () => {
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [users, setUsers] = useState<User[]>([]); // Enthält Admin-, Mitarbeiter- und Kundenbenutzer
  const [session, setSession] = useState<any>(null); // Supabase Session Objekt
  const [currentUser, setCurrentUser] = useState<User | null>(null); // Aktueller eingeloggter Benutzer mit App-spezifischen Details
  const [isLoadingInitialData, setIsLoadingInitialData] = useState(true);
  const navigate = useNavigate();

  // Hilfsfunktion zur deterministischen Ableitung von Namen und Avataren aus der E-Mail
  const deriveUserDetailsFromEmail = (email: string, role: UserRoleEnum) => {
    const parts = email.split('@')[0].split('.');
    let firstName = '';
    let lastName = '';

    if (parts.length > 0) {
      firstName = parts[0].charAt(0).toUpperCase() + parts[0].slice(1);
      if (parts.length > 1) {
        lastName = parts.slice(1).map(part => part.charAt(0).toUpperCase() + part.slice(1)).join(' ');
      }
    }

    const initials = `${firstName.charAt(0) || '?'}${lastName.charAt(0) || ''}`.toUpperCase().slice(0, 2);
    // Zufällige, aber konsistente Farbauswahl basierend auf dem ersten Initial
    const colors = ['bg-blue-500', 'bg-green-500', 'bg-orange-500', 'bg-red-500', 'bg-purple-500', 'bg-indigo-500', 'bg-pink-500', 'bg-yellow-500', 'bg-teal-500'];
    const colorIndex = initials.charCodeAt(0) % colors.length;
    const avatarColor = colors[colorIndex];

    return { firstName, lastName, avatarInitials: initials, avatarColor };
  };

  const fetchAllData = async () => {
    setIsLoadingInitialData(true);
    try {
      const { data: { session: currentSession } } = await supabase.auth.getSession();
      setSession(currentSession);

      if (!currentSession) {
        setCustomers([]);
        setTransactions([]);
        setUsers([]);
        setCurrentUser(null);
        return; // Keine Session, nichts zu laden
      }

      const authUserId = currentSession.user.id;

      // 1. Alle Benutzer (Auth-Details + Profile + Kundenprofile) über die Backend-API abrufen
      const allApiUsers: FullUserResponse[] = await getAllAppUsers();

      // Transformiere FullUserResponse[] in User[]
      const transformedUsers: User[] = allApiUsers.map((apiUser: FullUserResponse) => {
        let firstName = '';
        let lastName = '';
        let avatarInitials = '';
        let avatarColor = '';
        let associatedCustomerId: string | undefined = undefined;

        if (apiUser.role === UserRoleEnum.KUNDE && apiUser.customer_profile) {
          firstName = apiUser.customer_profile.first_name || '';
          lastName = apiUser.customer_profile.last_name || '';
          associatedCustomerId = apiUser.customer_profile.id;
        } else {
          // Für Admin/Mitarbeiter und Kunden ohne customer_profile: Namen aus E-Mail ableiten
          const derived = deriveUserDetailsFromEmail(apiUser.email, apiUser.role);
          firstName = derived.firstName;
          lastName = derived.lastName;
        }
        const derivedAvatar = deriveUserDetailsFromEmail(apiUser.email, apiUser.role);
        avatarInitials = derivedAvatar.avatarInitials;
        avatarColor = derivedAvatar.avatarColor;


        return {
          id: apiUser.id,
          email: apiUser.email,
          role: apiUser.role,
          createdAt: parseDateString(apiUser.created_at)?.toLocaleDateString('de-DE') || apiUser.created_at,
          firstName,
          lastName,
          avatarInitials,
          avatarColor,
          associatedCustomerId,
        };
      });
      setUsers(transformedUsers);

      const currentLoggedInUser = transformedUsers.find(u => u.id === authUserId);
      setCurrentUser(currentLoggedInUser || null);

      if (!currentLoggedInUser) {
        console.warn('Eingeloggter Benutzer nicht in den transformierten Benutzerdaten gefunden.');
        return;
      }

      // Prüfe auf customer_profiles für den eingeloggten Kunden, falls es eine Kundenrolle ist
      if (currentLoggedInUser.role === UserRoleEnum.KUNDE && !currentLoggedInUser.associatedCustomerId) {
        const { data: existingCustomerProfile, error: customerProfileFetchError } = await supabase
          .from('customer_profiles')
          .select('id')
          .eq('auth_user_id', authUserId)
          .single();

        if (customerProfileFetchError && customerProfileFetchError.code !== 'PGRST116') { // PGRST116 bedeutet "keine Zeilen gefunden"
          throw customerProfileFetchError;
        }

        if (!existingCustomerProfile) {
          // Automatisches Erstellen eines customer_profile, falls es für einen eingeloggten Kunden nicht existiert
          const { data: newCustomerProfile, error: createProfileError } = await supabase
            .from('customer_profiles')
            .insert({
              auth_user_id: authUserId,
              first_name: currentLoggedInUser.firstName || 'Neuer',
              last_name: currentLoggedInUser.lastName || 'Kunde',
              qr_code_data: `https://example.com/customer/${authUserId}`, // Platzhalter QR
            })
            .select('id')
            .single();

          if (createProfileError) {
            throw createProfileError;
          }
          currentLoggedInUser.associatedCustomerId = newCustomerProfile.id; // Aktuellen Benutzer mit neuer Kunden-ID aktualisieren
          setCurrentUser({ ...currentLoggedInUser }); // State aktualisieren, um neue associatedCustomerId widerzuspiegeln
        } else {
          currentLoggedInUser.associatedCustomerId = existingCustomerProfile.id;
          setCurrentUser({ ...currentLoggedInUser });
        }
      }

      // 2. Kundenprofile abrufen (alle, da Admin/Mitarbeiter Zugriff auf alle haben)
      const { data: dbCustomerProfiles, error: customerProfilesError } = await supabase
        .from('customer_profiles')
        .select('*');

      if (customerProfilesError) throw customerProfilesError;

      // 3. Alle Transaktionen abrufen
      const { data: dbTransactions, error: transactionsError } = await supabase
        .from('transactions')
        .select('*');

      if (transactionsError) throw transactionsError;

      // 4. Alle Trainingsfortschritte abrufen
      const { data: dbTrainingProgress, error: trainingProgressError } = await supabase
        .from('training_progress')
        .select('*');

      if (trainingProgressError) throw trainingProgressError;

      // Transformation der DB-Daten in die App-internen Customer, Transaction, TrainingSection Typen
      const transformedCustomers: Customer[] = dbCustomerProfiles.map((dbCustomer: DbCustomerProfile) => {
        const customerTransactions = dbTransactions.filter(t => t.customer_profile_id === dbCustomer.id);
        const balance = customerTransactions.reduce((sum, t) => t.type === 'recharge' ? sum + t.amount : sum - t.amount, 0);
        const totalTransactions = customerTransactions.length;

        const customerTrainingProgress = dbTrainingProgress.filter(tp => tp.customer_profile_id === dbCustomer.id);

        const trainingProgressForUI = TRAINING_LEVEL_DEFINITIONS.map(levelDef => {
          const progressEntry = customerTrainingProgress.find(p => p.level_name === levelDef.name);
          return {
            id: levelDef.id,
            dbId: progressEntry?.id || '',
            name: levelDef.name,
            requiredHours: levelDef.requiredHours,
            completedHours: progressEntry?.completed_trails || 0,
            status: progressEntry?.status || (levelDef.id === 1 ? 'Aktuell' : 'Gesperrt'),
          };
        }).sort((a, b) => a.id - b.id);

        const currentLevel = trainingProgressForUI.find(p => p.status === 'Aktuell')?.name || TrainingLevelEnum.EINSTEIGER;

        // Finde den zugehörigen Auth-Benutzer, um die E-Mail zu erhalten
        const customerAuthUser = transformedUsers.find(u => u.id === dbCustomer.auth_user_id);
        const derived = deriveUserDetailsFromEmail(customerAuthUser?.email || '', UserRoleEnum.KUNDE);

        return {
          id: dbCustomer.id,
          authUserId: dbCustomer.auth_user_id,
          avatarInitials: derived.avatarInitials,
          avatarColor: derived.avatarColor,
          firstName: dbCustomer.first_name || '',
          lastName: dbCustomer.last_name || '',
          email: customerAuthUser?.email || 'N/A', // E-Mail vom Auth-Benutzer abrufen
          phone: dbCustomer.phone || '',
          dogName: dbCustomer.dog_name || '',
          chipNumber: dbCustomer.chip_number || '',
          qrCodeData: dbCustomer.qr_code_data || '',
          balance,
          totalTransactions,
          level: currentLevel,
          createdAt: parseDateString(dbCustomer.created_at || new Date().toISOString())?.toLocaleDateString('de-DE') || '',
          documents: [], // Platzhalter
          trainingProgress: trainingProgressForUI,
        };
      });
      setCustomers(transformedCustomers);

      const transformedTransactions: Transaction[] = dbTransactions.map((dbTrx: DbTransaction) => {
        const employeeUser = transformedUsers.find(u => u.id === dbTrx.created_by_user_id);
        const employeeName = employeeUser ? `${employeeUser.firstName} ${employeeUser.lastName}` : 'System';
        return {
          id: dbTrx.id,
          customerId: dbTrx.customer_profile_id,
          employeeId: dbTrx.created_by_user_id,
          type: dbTrx.type,
          description: dbTrx.description || (dbTrx.type === 'recharge' ? 'Aufladung' : 'Trails'),
          amount: dbTrx.amount,
          date: parseDateString(dbTrx.created_at)?.toLocaleDateString('de-DE') || dbTrx.created_at,
          employee: employeeName,
        };
      });
      setTransactions(transformedTransactions);

    } catch (error: any) {
      console.error('Fehler beim Laden der Initialdaten:', error.message);
      alert(`Fehler beim Laden der Daten: ${error.message}`);
    } finally {
      setIsLoadingInitialData(false);
    }
  };


  useEffect(() => {
    // Initialer Abruf
    fetchAllData();

    // Listener für Auth-Änderungen einrichten
    const { data: authListener } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
      // Alle Daten bei Auth-Statusänderung (Login/Logout) neu abrufen
      fetchAllData();
    });

    return () => {
      authListener?.subscription.unsubscribe();
    };
  }, []); // Leeres Abhängigkeits-Array bedeutet, dass dies einmal beim Mounten ausgeführt wird


  // Effekt für initiale Weiterleitung basierend auf Login-Status und Benutzerrolle
  useEffect(() => {
    if (isLoadingInitialData) return; // Warten, bis Initialdaten geladen sind

    if (!session) {
      if (window.location.hash !== '#/login') {
        navigate('/login', { replace: true });
      }
    } else if (currentUser) { // Wenn eingeloggt und currentUser verfügbar ist
      if (currentUser.role === UserRoleEnum.KUNDE && currentUser.associatedCustomerId) {
        const expectedPath = `/customers/${currentUser.associatedCustomerId}`;
        if (!window.location.hash.startsWith(`#${expectedPath}`)) {
          navigate(expectedPath, { replace: true });
        }
      } else if (window.location.hash === '#/login' || window.location.hash === '#/') {
        // Nicht-Kunden-Benutzer von Login oder Root zum Dashboard weiterleiten
        navigate('/', { replace: true });
      }
    }
  }, [session, currentUser, isLoadingInitialData, navigate]);


  const handleLogin = async (email: string, passwordInput: string): Promise<boolean> => {
    const { data, error } = await supabase.auth.signInWithPassword({
      email,
      password: passwordInput,
    });
    if (error) {
      console.error('Login-Fehler:', error.message);
      return false;
    }
    // Session-Änderung wird vom onAuthStateChange-Listener behandelt, der fetchAllData und die Weiterleitung auslöst
    return true;
  };

  const handleRegister = async (email: string, passwordInput: string): Promise<boolean> => {
    const { data, error } = await supabase.auth.signUp({
      email,
      password: passwordInput,
    });
    if (error) {
      console.error('Registrierungsfehler:', error.message);
      return false;
    }
    // Nach der Registrierung wird der Benutzer in der Regel automatisch eingeloggt.
    // Der onAuthStateChange-Listener wird dies erkennen und Daten neu abrufen/weiterleiten.
    return true;
  };

  const handleLogout = async () => {
    const { error } = await supabase.auth.signOut();
    if (error) {
      console.error('Abmeldefehler:', error.message);
      alert('Fehler beim Abmelden.');
    } else {
      alert('Sie wurden abgemeldet.');
      // onAuthStateChange-Listener behandelt das Leeren des States und die Weiterleitung
    }
  };

  // Diese werden weitergegeben, lösen aber hauptsächlich eine vollständige Datenaktualisierung von App.tsx aus
  const handleUpdateCustomer = (updatedCustomer: Customer) => {
    // Dies löst jetzt nur eine Aktualisierung aus, die eigentliche DB-Aktualisierung erfolgt in CustomerDetails
    console.log('handleUpdateCustomer hat Aktualisierung ausgelöst:', updatedCustomer.id);
    fetchAllData();
  };

  const handleAddTransaction = (newTransaction: Transaction) => {
    // Dies löst jetzt nur eine Aktualisierung aus, die eigentliche DB-Einfügung erfolgt in CustomerDetails
    console.log('handleAddTransaction hat Aktualisierung ausgelöst:', newTransaction.id);
    fetchAllData();
  };

  // Benutzerverwaltungsfunktionen (für Admin/Mitarbeiter zur Verwaltung anderer Benutzer)
  const handleAddUser = async (newUserData: { firstName: string; lastName: string; email: string; role: UserRoleEnum; password?: string }) => {
    try {
      if (newUserData.role === UserRoleEnum.KUNDE) {
        // Für die Rolle 'Kunde' wird die Registrierung über LoginPage gehandhabt.
        // Wenn ein Admin hier ein Kundenprofil hinzufügen möchte, das zu einem vorhandenen auth.user gehört,
        // müsste der auth_user_id des Kunden bekannt sein.
        // Für diesen Flow gehen wir davon aus, dass neue Kunden sich selbst registrieren.
        // Dies hier ist eher ein Platzhalter, falls ein Admin ein "blankes" Kundenprofil erstellen möchte
        // und es später mit einem Auth-Benutzer verknüpft wird.
        const { data: customerProfileData, error: customerProfileError } = await supabase
          .from('customer_profiles')
          .insert({
            first_name: newUserData.firstName,
            last_name: newUserData.lastName,
            // auth_user_id bleibt null, bis ein registrierter Kunde damit verknüpft wird,
            // oder es wird manuell von einem Admin verknüpft.
            qr_code_data: `https://example.com/customer/${newUserData.email}`, // Platzhalter QR
          })
          .select()
          .single();

        if (customerProfileError) throw customerProfileError;
        alert(`Kundenprofil für ${newUserData.firstName} ${newUserData.lastName} erstellt. Es ist noch kein Supabase Auth-Benutzer damit verknüpft.`);
      } else {
        // Für Admin/Mitarbeiter-Rollen wird die Einladung über die serverseitige API gehandhabt.
        const response = await inviteUser(newUserData.email, newUserData.role);
        alert(`Einladung an ${response.userEmail} (${newUserData.role}) gesendet. Link zum Passwort setzen: ${response.resetPasswordUrl || 'Nicht verfügbar'}`);
      }
      fetchAllData(); // Alle Daten aktualisieren
    } catch (error: any) {
      console.error('Fehler beim Hinzufügen des Benutzers/Kundenprofils:', error.message);
      alert(`Fehler beim Hinzufügen des Benutzers: ${error.message}`);
    }
  };

  const handleUpdateUser = async (updatedUser: User) => {
    try {
      const updates: { email?: string; role?: UserRoleEnum; firstName?: string; lastName?: string; associatedCustomerId?: string } = {
        role: updatedUser.role,
      };

      // Wenn der Benutzer ein Kunde ist, aktualisiere die customer_profiles-Details
      if (updatedUser.role === UserRoleEnum.KUNDE && updatedUser.associatedCustomerId) {
        updates.firstName = updatedUser.firstName;
        updates.lastName = updatedUser.lastName;
        updates.associatedCustomerId = updatedUser.associatedCustomerId; // Für die Backend-Funktion
        // E-Mail für Kunden wird direkt über das Kundenprofil aktualisiert, nicht über auth.users
        const { error: customerProfileUpdateError } = await supabase
          .from('customer_profiles')
          .update({
            first_name: updatedUser.firstName,
            last_name: updatedUser.lastName,
            // email ist nicht im customer_profiles Schema, also wird es hier nicht aktualisiert
          })
          .eq('id', updatedUser.associatedCustomerId);

        if (customerProfileUpdateError) throw customerProfileUpdateError;
      } else if (updatedUser.email !== users.find(u => u.id === updatedUser.id)?.email) {
        // Wenn es kein Kunde ist und die E-Mail geändert wurde, aktualisiere die Auth-E-Mail über Backend
        updates.email = updatedUser.email;
      }

      await updateAppUser(updatedUser.id, updates);

      alert('Benutzer erfolgreich aktualisiert.');
      fetchAllData(); // Alle Daten aktualisieren
    } catch (error: any) {
      console.error('Fehler beim Aktualisieren des Benutzers:', error.message);
      alert(`Fehler beim Aktualisieren des Benutzers: ${error.message}`);
    }
  };

  const handleDeleteUser = async (userId: string) => {
    try {
      const userToDelete = users.find(u => u.id === userId);
      if (!userToDelete) throw new Error('Benutzer nicht gefunden.');

      if (userToDelete.id === currentUser?.id) {
        alert('Sie können sich nicht selbst löschen. Bitte melden Sie sich ab und lassen Sie den Account ggf. von einem anderen Administrator löschen.');
        return;
      }

      await deleteAppUser(userId); // Backend-API zum Löschen aufrufen
      alert('Benutzer erfolgreich gelöscht (inkl. zugehöriger Profile und Auth.user).');
      fetchAllData(); // Alle Daten aktualisieren

    } catch (error: any) {
      console.error('Fehler beim Löschen des Benutzers:', error.message);
      alert(`Fehler beim Löschen des Benutzers: ${error.message}`);
    }
  };


  if (isLoadingInitialData) {
    return (
      <div className="flex items-center justify-center min-h-screen bg-gray-100">
        <div className="text-xl text-gray-700">Lade Anwendungsdaten...</div>
      </div>
    );
  }

  return (
    <div className="flex min-h-screen bg-gray-100">
      {session && currentUser ? (
        <>
          <Sidebar appName="Mantrailing Card" currentUser={currentUser} onLogout={handleLogout} />
          <main className="flex-1 md:ml-64 p-0">
            <Routes>
              {currentUser.role === UserRoleEnum.ADMIN ? (
                // Admin hat vollen Zugriff
                <>
                  <Route path="/" element={<Dashboard customers={customers} transactions={transactions} currentUser={currentUser} />} />
                  <Route path="/customers" element={<CustomerManagement customers={customers} transactions={transactions} currentUser={currentUser} />} />
                  <Route
                    path="/customers/:id"
                    element={<CustomerDetails customers={customers} allTransactions={transactions} onUpdateCustomer={handleUpdateCustomer} onAddTransaction={handleAddTransaction} currentUser={currentUser} onRefreshData={fetchAllData} />}
                  />
                  <Route path="/reports" element={<Reports customers={customers} transactions={transactions} users={users} currentUser={currentUser} />} />
                  <Route path="/users" element={<UserManagement users={users} onAddUser={handleAddUser} onUpdateUser={handleUpdateUser} onDeleteUser={handleDeleteUser} currentUser={currentUser} />} />
                  <Route path="*" element={<Dashboard customers={customers} transactions={transactions} currentUser={currentUser} />} />
                </>
              ) : currentUser.role === UserRoleEnum.MITARBEITER ? (
                // Mitarbeiter hat eingeschränkten Zugriff
                <>
                  <Route path="/" element={<Dashboard customers={customers} transactions={transactions} currentUser={currentUser} />} />
                  <Route path="/customers" element={<CustomerManagement customers={customers} transactions={transactions} currentUser={currentUser} />} />
                  <Route
                    path="/customers/:id"
                    element={<CustomerDetails customers={customers} allTransactions={transactions} onUpdateCustomer={handleUpdateCustomer} onAddTransaction={handleAddTransaction} currentUser={currentUser} onRefreshData={fetchAllData} />}
                  />
                  {/* Mitarbeiter dürfen nicht auf /reports oder /users zugreifen */}
                  <Route path="/reports" element={<Navigate replace to="/" />} />
                  <Route path="/users" element={<Navigate replace to="/" />} />
                  <Route path="*" element={<Dashboard customers={customers} transactions={transactions} currentUser={currentUser} />} />
                </>
              ) : currentUser.role === UserRoleEnum.KUNDE && currentUser.associatedCustomerId ? (
                // Kunde hat Zugriff nur auf die eigene Kundenkarte
                <>
                  <Route
                    path="/customers/:id"
                    element={<CustomerDetails customers={customers} allTransactions={transactions} onUpdateCustomer={handleUpdateCustomer} onAddTransaction={handleAddTransaction} currentUser={currentUser} onRefreshData={fetchAllData} />}
                  />
                  <Route path="/" element={<Navigate replace to={`/customers/${currentUser.associatedCustomerId}`} />} />
                  <Route path="*" element={<Navigate replace to={`/customers/${currentUser.associatedCustomerId}`} />} />
                </>
              ) : (
                // Fallback für jeden anderen unerwarteten eingeloggten Zustand (sollte idealerweise nicht passieren)
                <Route path="*" element={<Dashboard customers={customers} transactions={transactions} currentUser={currentUser} />} />
              )}
            </Routes>
          </main>
        </>
      ) : (
        // Nicht eingeloggt
        <Routes>
          <Route path="/login" element={<LoginPage onLogin={handleLogin} onRegister={handleRegister} />} />
          <Route path="*" element={<LoginPage onLogin={handleLogin} onRegister={handleRegister} />} />
        </Routes>
      )}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { NavLink } from 'react-router-dom';
import { NAVIGATION_ITEMS } from '../constants';
import { LogoutIcon } from './Icons'; // Import LogoutIcon
import Avatar from './Avatar'; // Import Avatar component
import { User, UserRoleEnum } from '../types'; // Import User type and UserRoleEnum

interface SidebarProps {
  appName: string;
  currentUser: User | null; // Added currentUser prop
  onLogout: () => void; // Added onLogout prop
}

const Sidebar: React.FC<SidebarProps> = ({ appName, currentUser, onLogout }) => {
  const [isOpen, setIsOpen] = useState(false); // Für mobilen Sidebar-Toggle

  const toggleSidebar = () => {
    setIsOpen(!isOpen);
  };

  // Navigationspunkte basierend auf der currentUser-Rolle filtern
  const filteredNavigationItems = NAVIGATION_ITEMS.filter(item => {
    if (!currentUser) return false; // Sollte nicht passieren, wenn Sidebar gerendert wird, aber gut für die Typsicherheit

    if (currentUser.role === UserRoleEnum.ADMIN) {
      return true; // Admin sieht alles
    }
    if (currentUser.role === UserRoleEnum.MITARBEITER) {
      // Mitarbeiter sieht Übersicht und Kunden, aber NICHT Berichte und Benutzer
      // item.path === '/reports' wird jetzt in App.tsx über <Navigate> behandelt,
      // aber der Menüpunkt sollte hier auch ausgeblendet werden.
      return item.path === '/' || item.path === '/customers';
    }
    // Kundenrolle sollte keine Navigationspunkte in der Sidebar sehen
    return false;
  });

  return (
    <>
      {/* Mobiler Menü-Button */}
      <button
        onClick={toggleSidebar}
        className="fixed bottom-4 left-4 z-40 p-3 bg-blue-600 text-white rounded-full shadow-lg md:hidden"
        aria-label="Navigation umschalten"
      >
        <svg
          className="h-6 w-6"
          xmlns="http://www.w3.org/2000/svg"
          fill="none"
          viewBox="0 0 24 24"
          stroke="currentColor"
        >
          {isOpen ? (
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
          ) : (
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16M4 18h16" />
          )}
        </svg>
      </button>

      {/* Backdrop für Mobilgeräte */}
      {isOpen && (
        <div
          className="fixed inset-0 bg-black bg-opacity-50 z-30 md:hidden"
          onClick={toggleSidebar}
        ></div>
      )}

      {/* Sidebar */}
      <aside
        className={`fixed inset-y-0 left-0 w-64 bg-[#00A1D6] text-white flex flex-col z-40 transition-transform duration-300 ease-in-out
          ${isOpen ? 'translate-x-0' : '-translate-x-full md:translate-x-0'}`}
      >
        <div className="p-6 text-2xl font-bold flex-shrink-0">
          {appName}
        </div>

        <nav className="flex-grow p-4 space-y-2">
          {filteredNavigationItems.map((item) => (
            <NavLink
              key={item.path}
              to={item.path}
              className={({ isActive }) =>
                `flex items-center space-x-3 p-3 rounded-lg transition-colors duration-200 group
                 ${isActive ? 'bg-blue-500 text-white shadow-md' : 'text-white hover:bg-white/10'}`
              }
              onClick={() => setIsOpen(false)} // Sidebar bei Navigation für Mobilgeräte schließen
            >
              <item.icon className="h-6 w-6 text-white group-hover:text-white" />
              <span className="text-lg">{item.label}</span>
            </NavLink>
          ))}
        </nav>

        {/* Aktuelle Benutzerinformationen und Abmeldung */}
        {currentUser && (
          <div className="p-4 border-t border-white/20 flex-shrink-0">
            <div className="flex items-center mb-4">
              <Avatar initials={currentUser.avatarInitials} color={currentUser.avatarColor} size="md" className="mr-3" />
              <div>
                <p className="font-semibold text-white">{currentUser.firstName} {currentUser.lastName}</p>
                <p className="text-sm text-gray-200">{currentUser.role === UserRoleEnum.ADMIN ? 'Admin' : currentUser.role === UserRoleEnum.MITARBEITER ? 'Mitarbeiter' : 'Kunde'}</p>
              </div>
            </div>
            <button
              onClick={onLogout}
              className="flex items-center space-x-3 p-3 w-full rounded-lg text-white hover:bg-white/10 transition-colors duration-200"
            >
              <LogoutIcon className="h-6 w-6 text-white" />
              <span className="text-lg">Abmelden</span>
            </button>
          </div>
        )}
      </aside>
    </>
  );
};

export default Sidebar;

import React, { useState, useEffect } from 'react';
import Card from '../components/Card';
import StatCard from '../components/StatCard';
import Button from '../components/Button';
import Select from '../components/Select';
import Avatar from '../components/Avatar';
import { MOCK_REPORT_TYPES, MOCK_TRANSACTION_FILTERS, REFERENCE_DATE } from '../constants';
import { ArrowUpCircleIcon, ArrowDownCircleIcon, DollarSignIcon, ClipboardIcon, UsersIcon } from '../components/Icons';
import { parseDateString, isSameMonth } from '../utils';
import { Customer, Transaction, User, UserRoleEnum } from '../types'; // UserRoleEnum importiert
import { useNavigate } from 'react-router-dom'; // useNavigate importiert

import jsPDF from 'jspdf';
import 'jspdf-autotable';

interface ReportsProps {
  customers: Customer[];
  transactions: Transaction[];
  users: User[]; // Alle Benutzer, um Mitarbeiternamen zuzuordnen
  currentUser: User | null; // currentUser hinzugefügt für Berechtigungsprüfung
}

// Hilfsfunktion zum Generieren dynamischer Berichtszeiträume
const generateReportPeriods = (reportType: string, referenceDate: Date) => {
  const periods = [];
  const currentMonthName = referenceDate.toLocaleString('de-DE', { month: 'long' });
  const currentYear = referenceDate.getFullYear();

  if (reportType === 'Monatlich') {
    // Aktueller Monat
    periods.push({ value: `${currentMonthName.charAt(0).toUpperCase() + currentMonthName.slice(1)} ${currentYear}`, label: `${currentMonthName.charAt(0).toUpperCase() + currentMonthName.slice(1)} ${currentYear}` });

    // Vorheriger Monat
    const prevMonthDate = new Date(referenceDate);
    prevMonthDate.setMonth(referenceDate.getMonth() - 1);
    const prevMonthName = prevMonthDate.toLocaleString('de-DE', { month: 'long' });
    const prevMonthYear = prevMonthDate.getFullYear();
    periods.push({ value: `${prevMonthName.charAt(0).toUpperCase() + prevMonthName.slice(1)} ${prevMonthYear}`, label: `${prevMonthName.charAt(0).toUpperCase() + prevMonthName.slice(1)} ${prevMonthYear}` });

  } else if (reportType === 'Jährlich') {
    // Aktuelles Jahr
    periods.push({ value: String(currentYear), label: String(currentYear) });

    // Vorheriges Jahr
    periods.push({ value: String(currentYear - 1), label: String(currentYear - 1) });
  } else if (reportType === 'Benutzerdefiniert') {
    // Vorerst steht "Gesamt" für einen benutzerdefinierten, alles umfassenden Zeitraum
    periods.push({ value: 'Gesamt', label: 'Gesamt' });
  }
  return periods;
};


const Reports: React.FC<ReportsProps> = ({ customers, transactions, users, currentUser }) => {
  const navigate = useNavigate();
  const [reportType, setReportType] = useState('Monatlich');
  const [employee, setEmployee] = useState('Alle Mitarbeiter');
  const [transactionFilter, setTransactionFilter] = useState('Alle Transaktionen');

  const initialPeriods = generateReportPeriods('Monatlich', REFERENCE_DATE);
  const [timePeriod, setTimePeriod] = useState(initialPeriods.length > 0 ? initialPeriods[0].value : 'Gesamt');
  const [availableTimePeriods, setAvailableTimePeriods] = useState(initialPeriods);
  const [isGeneratingPdf, setIsGeneratingPdf] = useState(false);

  // Berechtigungsprüfung: Nur Admin darf Berichte sehen
  useEffect(() => {
    if (currentUser && currentUser.role !== UserRoleEnum.ADMIN) {
      alert('Sie haben keine Berechtigung, diese Seite anzuzeigen.');
      navigate('/'); // Zum Dashboard umleiten
    }
  }, [currentUser, navigate]);

  // Mitarbeiter für Berichte aus den tatsächlichen Benutzern ableiten, die Transaktionen durchgeführt haben
  const uniqueEmployeeIds = new Set(transactions.map(t => t.employeeId).filter(Boolean));
  const reportEmployees = [
    { value: 'Alle Mitarbeiter', label: 'Alle Mitarbeiter' },
    ...Array.from(uniqueEmployeeIds).map(empId => {
      const employeeUser = users.find(u => u.id === empId);
      return {
        value: empId!,
        label: employeeUser ? `${employeeUser.firstName} ${employeeUser.lastName}` : `Unbekannter Mitarbeiter (${empId})`,
      };
    }),
  ];


  // Effekt zum Aktualisieren von availableTimePeriods und Zurücksetzen von timePeriod, wenn sich reportType ändert
  useEffect(() => {
    const newPeriods = generateReportPeriods(reportType, REFERENCE_DATE);
    setAvailableTimePeriods(newPeriods);
    if (newPeriods.length > 0) {
      setTimePeriod(newPeriods[0].value); // Standardmäßig auf die erste Option setzen
    } else {
      setTimePeriod('Gesamt'); // Fallback
    }
  }, [reportType]);


  // Hilfsfunktion zum Parsen des aktuellen Filterzeitraums
  const getFilterPeriodDate = () => {
    if (timePeriod === 'Gesamt') return null;

    // Prüfen, ob es sich um ein Jahr handelt (z.B. "2025")
    if (!isNaN(parseInt(timePeriod, 10)) && timePeriod.length === 4) {
      return new Date(parseInt(timePeriod, 10), 0, 1); // 1. Januar des Jahres
    }

    // Angenommenes Format "Monat JJJJ" für detaillierteres Filtern
    const [monthName, year] = timePeriod.split(' ');
    const monthMap: { [key: string]: number } = {
      'Januar': 0, 'Februar': 1, 'März': 2, 'April': 3, 'Mai': 4, 'Juni': 5,
      'Juli': 6, 'August': 7, 'September': 8, 'Oktober': 9, 'November': 10, 'Dezember': 11
    };
    const monthIndex = monthMap[monthName];
    if (monthIndex !== undefined && year) {
      return new Date(parseInt(year, 10), monthIndex, 1);
    }
    return null;
  };

  const selectedFilterPeriod = getFilterPeriodDate();

  // Transaktionen basierend auf ausgewählten Kriterien filtern
  const filteredTransactions = transactions.filter(t => {
    const transactionDate = parseDateString(t.date);
    if (!transactionDate) return false;

    // Nach Zeitraum filtern
    let matchesPeriod = true;
    if (timePeriod === 'Gesamt') {
      matchesPeriod = true;
    } else if (reportType === 'Monatlich' && selectedFilterPeriod) {
      matchesPeriod = isSameMonth(transactionDate, selectedFilterPeriod);
    } else if (reportType === 'Jährlich' && selectedFilterPeriod) {
      matchesPeriod = transactionDate.getFullYear() === selectedFilterPeriod.getFullYear();
    }


    // Nach Mitarbeiter filtern (mittels employeeId)
    const matchesEmployee = employee === 'Alle Mitarbeiter' || t.employeeId === employee;

    // Nach Transaktionstyp filtern
    let matchesTransactionType = true;
    if (transactionFilter === 'Einnahmen (Aufladungen)') {
      matchesTransactionType = t.type === 'recharge';
    } else if (transactionFilter === 'Ausgaben (Abbuchungen)') {
      matchesTransactionType = t.type === 'debit';
    }

    return matchesPeriod && matchesEmployee && matchesTransactionType;
  });

  // Dynamische Berechnungen für Berichtsstatistiken
  const monthlyRecharges = filteredTransactions
    .filter(t => t.type === 'recharge')
    .reduce((sum, t) => sum + Math.abs(t.amount), 0);

  const monthlyDebits = filteredTransactions
    .filter(t => t.type === 'debit')
    .reduce((sum, t) => sum + Math.abs(t.amount), 0);

  const totalMonthlyTransactions = filteredTransactions.length;

  const activeCustomerIdsInPeriod = new Set(
    filteredTransactions.map(t => t.customerId)
  );
  const activeCustomersInPeriodCount = customers.filter(c => activeCustomerIdsInPeriod.has(c.id)).length;


  const getTopCustomers = () => {
    const customerTransactions: { [key: string]: { count: number; totalAmount: number } } = {};
    filteredTransactions.forEach(t => {
      if (!customerTransactions[t.customerId]) {
        customerTransactions[t.customerId] = { count: 0, totalAmount: 0 };
      }
      customerTransactions[t.customerId].count++;
      customerTransactions[t.customerId].totalAmount += Math.abs(t.amount);
    });

    return Object.entries(customerTransactions)
      .sort(([, a], [, b]) => b.totalAmount - a.totalAmount)
      .slice(0, 3)
      .map(([customerId, data]) => {
        const customer = customers.find(c => c.id === customerId);
        return {
          customerName: customer ? `${customer.firstName} ${customer.lastName}` : 'Unbekannt',
          dogName: customer?.dogName || '',
          transactionCount: data.count,
          totalAmount: data.totalAmount,
          avatarInitials: customer?.avatarInitials || '?',
          avatarColor: customer?.avatarColor || 'bg-gray-400',
          id: customerId,
        };
      });
  };

  const topCustomers = getTopCustomers();

  const handleExportPdf = async () => {
    setIsGeneratingPdf(true);
    try {
      const doc = new jsPDF();
      let yPos = 20;

      // Berichttitel
      doc.setFontSize(22);
      doc.text(`Mantrailing Card App - ${reportType} Bericht`, 105, yPos, { align: 'center' });
      yPos += 10;
      doc.line(20, yPos, 190, yPos); // Horizontale Linie
      yPos += 10;

      // Filterdetails
      doc.setFontSize(12);
      doc.text(`Berichtstyp: ${reportType}`, 20, yPos);
      yPos += 7;
      doc.text(`Zeitraum: ${timePeriod}`, 20, yPos);
      yPos += 7;
      doc.text(`Mitarbeiter: ${employee === 'Alle Mitarbeiter' ? 'Alle Mitarbeiter' : users.find(u => u.id === employee)?.firstName + ' ' + users.find(u => u.id === employee)?.lastName || employee}`, 20, yPos);
      yPos += 7;
      doc.text(`Transaktionstyp: ${transactionFilter}`, 20, yPos);
      yPos += 7;
      doc.text(`Erstellt am: ${REFERENCE_DATE.toLocaleDateString('de-DE')}`, 20, yPos);
      yPos += 15;

      // Zusammenfassende Statistiken
      doc.setFontSize(16);
      doc.text('Übersicht', 20, yPos);
      yPos += 7;
      doc.setFontSize(12);
      doc.text(`Gesamtaufladungen: ${monthlyRecharges.toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })}`, 20, yPos);
      yPos += 7;
      doc.text(`Abbuchungen: ${monthlyDebits.toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })}`, 20, yPos);
      yPos += 7;
      doc.text(`Anzahl Transaktionen: ${totalMonthlyTransactions}`, 20, yPos);
      yPos += 7;
      doc.text(`Aktive Kunden: ${activeCustomersInPeriodCount}`, 20, yPos);
      yPos += 15;

      // Transaktionstabelle
      doc.setFontSize(16);
      doc.text(`${transactionFilter} im Zeitraum`, 20, yPos);
      yPos += 5;

      const transactionsHeaders = [['Datum', 'Beschreibung', 'Kunde', 'Mitarbeiter', 'Typ', 'Betrag']];
      const transactionsData = filteredTransactions.map(t => {
        const customer = customers.find(c => c.id === t.customerId);
        const customerName = customer ? `${customer.firstName} ${customer.lastName}` : 'Unbekannt';
        const isRecharge = t.type === 'recharge';
        const amountSign = isRecharge ? '+' : '-';
        const formattedAmount = `${amountSign}${Math.abs(t.amount).toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })}`;
        return [t.date, t.description, customerName, t.employee, t.type === 'recharge' ? 'Aufladung' : 'Abbuchung', formattedAmount];
      });

      (doc as any).autoTable({
        startY: yPos,
        head: transactionsHeaders,
        body: transactionsData,
        theme: 'striped',
        headStyles: { fillColor: [0, 161, 214] },
        margin: { top: 10, right: 20, bottom: 10, left: 20 },
        didParseCell: function (data: any) {
          if (data.section === 'body' && data.column.index === 5) {
            const amountStr = data.cell.text[0];
            if (amountStr && amountStr.startsWith('+')) {
              data.cell.styles.textColor = [34, 139, 34];
            } else if (amountStr && amountStr.startsWith('-')) {
              data.cell.styles.textColor = [220, 20, 60];
            }
          }
        },
      });

      yPos = (doc as any).autoTable.previous.finalY + 15;

      // Top Kunden Tabelle
      doc.setFontSize(16);
      doc.text('Top Kunden im Zeitraum', 20, yPos);
      yPos += 5;

      const topCustomersHeaders = [['Rang', 'Kunde', 'Hund', 'Transaktionen', 'Gesamtbetrag']];
      const topCustomersData = topCustomers.map((c, index) => [
        index + 1,
        c.customerName,
        c.dogName,
        c.transactionCount,
        c.totalAmount.toLocaleString('de-DE', { style: 'currency', currency: 'EUR' }),
      ]);

      (doc as any).autoTable({
        startY: yPos,
        head: topCustomersHeaders,
        body: topCustomersData,
        theme: 'striped',
        headStyles: { fillColor: [0, 161, 214] },
        margin: { top: 10, right: 20, bottom: 10, left: 20 },
      });

      const fileName = `Bericht_${reportType.replace(' ', '_')}_${timePeriod.replace(' ', '_')}_${employee.replace('Alle Mitarbeiter', 'Alle').replace(' ', '_')}_${transactionFilter.replace(' ', '_')}.pdf`;
      doc.save(fileName);
      alert('PDF-Export erfolgreich!');
    } catch (error) {
      console.error("Fehler beim Erstellen der PDF:", error);
      alert('Fehler beim PDF-Export. Bitte versuchen Sie es erneut.');
    } finally {
      setIsGeneratingPdf(false);
    }
  };

  // Wenn der Benutzer kein Admin ist, rendern Sie nichts oder eine Lade-/Fehlermeldung
  if (currentUser && currentUser.role !== UserRoleEnum.ADMIN) {
    return (
      <div className="p-8 text-center text-red-600">
        Sie haben keine Berechtigung, diese Seite anzuzeigen. Sie werden zum Dashboard umgeleitet.
      </div>
    );
  }

  return (
    <div className="p-6 md:p-8 lg:p-10">
      <h1 className="text-3xl font-bold text-gray-900 mb-2">Berichte & Statistiken</h1>
      <p className="text-gray-600 mb-8">Analysieren und exportieren Sie Ihre Geschäftsdaten</p>

      {/* Filter und Export-Button */}
      <Card className="mb-8">
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 items-end">
          <Select
            id="reportType"
            label="Berichtstyp"
            options={MOCK_REPORT_TYPES.map(type => ({ value: type, label: type }))}
            value={reportType}
            onChange={(e) => setReportType(e.target.value)}
            disabled={isGeneratingPdf}
          />
          <Select
            id="timePeriod"
            label="Zeitraum"
            options={availableTimePeriods}
            value={timePeriod}
            onChange={(e) => setTimePeriod(e.target.value)}
            disabled={isGeneratingPdf}
          />
          <Select
            id="employee"
            label="Mitarbeiter"
            options={reportEmployees}
            value={employee}
            onChange={(e) => setEmployee(e.target.value)}
            disabled={isGeneratingPdf}
          />
          <Select
            id="transactionFilter"
            label="Transaktionstyp"
            options={MOCK_TRANSACTION_FILTERS.map(filter => ({ value: filter, label: filter }))}
            value={transactionFilter}
            onChange={(e) => setTransactionFilter(e.target.value)}
            disabled={isGeneratingPdf}
          />
          {/* Button in die letzte Position im Raster verschoben, um unten rechts zu erscheinen */}
          <Button
            variant="success"
            className="w-full sm:col-span-1 lg:col-start-4 lg:col-span-1 lg:w-auto"
            onClick={handleExportPdf}
            disabled={isGeneratingPdf}
          >
            {isGeneratingPdf ? 'PDF wird generiert...' : 'Als PDF exportieren'}
          </Button>
        </div>
      </Card>

      {/* Statistik-Karten für Berichte */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
        <StatCard
          title="Gesamtaufladungen"
          value={monthlyRecharges.toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })}
          icon={UsersIcon}
          color="bg-green-100 text-green-700"
        />
        <StatCard
          title="Abbuchungen"
          value={monthlyDebits.toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })}
          icon={DollarSignIcon}
          color="bg-orange-100 text-orange-700"
        />
        <StatCard
          title="Transaktionen"
          value={totalMonthlyTransactions}
          icon={ClipboardIcon}
          color="bg-blue-100 text-blue-700"
        />
        <StatCard
          title="Aktive Kunden"
          value={activeCustomersInPeriodCount}
          icon={UsersIcon}
          color="bg-purple-100 text-purple-700"
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Transaktionen im Zeitraum */}
        <Card>
          <h2 className="text-xl font-semibold text-gray-900 mb-4">{transactionFilter} im Zeitraum ({filteredTransactions.length})</h2>
          <div className="space-y-4 max-h-96 overflow-y-auto custom-scrollbar">
            {filteredTransactions.length === 0 ? (
              <p className="text-gray-500">Keine Transaktionen für den ausgewählten Zeitraum, Mitarbeiter und Transaktionstyp gefunden.</p>
            ) : (
              filteredTransactions.map((transaction) => {
                const customer = customers.find(c => c.id === transaction.customerId);
                const isRecharge = transaction.type === 'recharge';
                const TransactionIcon = isRecharge ? ArrowUpCircleIcon : ArrowDownCircleIcon;
                const iconColor = isRecharge ? 'text-green-500' : 'text-red-500';
                const amountColor = isRecharge ? 'text-green-700' : 'text-red-700';
                const amountSign = isRecharge ? '+' : '-';

                return (
                  <div key={transaction.id} className="flex items-center justify-between p-3 bg-gray-50 rounded-lg">
                    <div className="flex items-center">
                      <span className={`p-2 rounded-full bg-gray-200 mr-3 ${iconColor}`}>
                        <TransactionIcon className="h-5 w-5" />
                      </span>
                      <div>
                        <p className="font-medium text-gray-900">{transaction.description}</p>
                        <p className="text-sm text-gray-500">
                          {transaction.date} von {transaction.employee}
                          {customer && ` für ${customer.firstName} ${customer.lastName}`}
                        </p>
                      </div>
                    </div>
                    <p className={`font-semibold ${amountColor}`}>
                      {amountSign}{Math.abs(transaction.amount).toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })}
                    </p>
                  </div>
                );
              })
            )}
          </div>
        </Card>

        {/* Top Kunden im Zeitraum */}
        <Card>
          <h2 className="text-xl font-semibold text-gray-900 mb-4">Top Kunden im Zeitraum</h2>
          <div className="space-y-4 max-h-96 overflow-y-auto custom-scrollbar">
            {topCustomers.length === 0 ? (
              <p className="text-gray-500">Keine Top-Kunden für den ausgewählten Zeitraum und Mitarbeiter gefunden.</p>
            ) : (
              topCustomers.map((customer, index) => (
                <div key={customer.id} className="flex items-center justify-between p-3 bg-gray-50 rounded-lg">
                  <div className="flex items-center">
                    <span className="text-lg font-bold text-gray-700 mr-3">{index + 1}.</span>
                    <Avatar initials={customer.avatarInitials} color={customer.avatarColor} size="md" className="mr-3" />
                    <div>
                      <p className="font-medium text-gray-900">{customer.customerName}</p>
                      <p className="text-sm text-gray-500}>
                        {customer.dogName} &bull; {customer.transactionCount} Transaktion{customer.transactionCount !== 1 ? 'en' : ''}
                      </p>
                    </div>
                  </div>
                  <p className="font-semibold text-gray-800">
                    {customer.totalAmount.toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })}
                  </p>
                </div>
              ))
            )}
          </div>
        </Card>
      </div>
    </div>
  );
};

export default Reports;

import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import Card from '../components/Card';
import Avatar from '../components/Avatar';
import Button from '../components/Button';
import QRCodeDisplay from '../components/QRCodeDisplay';
import TransactionConfirmationModal from '../components/TransactionConfirmationModal';
import TransactionTypeSelectionModal from '../components/TransactionTypeSelectionModal';
import TransactionDetailsInputModal from '../components/TransactionDetailsInputModal';
import {
  ArrowLeftIcon,
  HeartIcon,
  CreditCardIcon,
  MailIcon,
  PhoneIcon,
  AwardIcon,
  UploadIcon,
  UserIcon,
  ChevronDownIcon,
  EditIcon,
} from '../components/Icons';
import Input from '../components/Input';
import { REFERENCE_DATE, TRAINING_LEVEL_DEFINITIONS } from '../constants';
import { Customer, TrainingLevelEnum, TransactionConfirmationData, Transaction, User, UserRoleEnum, DbCustomerProfile, DbTransaction, DbTrainingProgress } from '../types';
import { supabase } from '../supabaseClient';
import { parseDateString } from '../utils';

interface TrainingHourCircleProps {
  filled: boolean;
  className?: string;
}

const TrainingPawIcon: React.FC<TrainingHourCircleProps> = ({ filled, className = '' }) => (
  <div
    className={`flex items-center justify-center h-16 w-16 rounded-full border
      ${filled ? 'bg-gray-100 border-gray-300' : 'bg-gray-50 border-gray-200'}
      ${className}`}
  >
    <img
      src="https://hs-bw.com/wp-content/uploads/2025/12/Suchund-Icon.png"
      alt="Paw Icon"
      className={`h-10 w-10 object-contain ${!filled ? 'grayscale opacity-50' : ''}`}
    />
  </div>
);

interface HundredHourMilestoneBadgeProps {
  milestoneNumber: number;
}

const HundredHourMilestoneBadge: React.FC<HundredHourMilestoneBadgeProps> = ({ milestoneNumber }) => {
  const baseClasses = "flex flex-col items-center justify-center h-32 w-32 p-2 rounded-lg text-center shadow-md";
  let specificClasses = "";
  let textColor = "text-amber-800";

  switch (milestoneNumber) {
    case 1: // 100 Trails
      specificClasses = "bg-amber-100 border border-amber-300";
      break;
    case 2: // 200 Trails
      specificClasses = "bg-orange-100 border border-orange-300 shadow-lg";
      textColor = "text-orange-800";
      break;
    case 3: // 300 Trails
      specificClasses = "bg-red-100 border border-red-300 shadow-xl";
      textColor = "text-red-800";
      break;
    case 4: // 400 Trails
      specificClasses = "bg-purple-100 border border-purple-300 shadow-2xl";
      textColor = "text-purple-800";
      break;
    case 5: // 500 Trails
      specificClasses = "bg-blue-100 border border-blue-300 shadow-2xl";
      textColor = "text-blue-800";
      break;
    default: // For milestones beyond 500 or unknown
      specificClasses = "bg-gray-100 border border-gray-300";
      textColor = "text-gray-800";
      break;
  }

  return (
    <div className={`${baseClasses} ${specificClasses}`}>
      <img
        src="https://hs-bw.com/wp-content/uploads/2025/12/Suchund-Icon.png"
        alt={`${milestoneNumber * 100} Trails gemeistert`}
        className="h-20 w-20 object-contain filter drop-shadow-sm"
      />
      <p className={`text-sm font-bold ${textColor} mt-1`}>{milestoneNumber * 100} Trails gemeistert!</p>
    </div>
  );
};


interface CustomerDetailsProps {
  customers: Customer[]; // Wird zur Ermittlung von Mitarbeiternamen verwendet
  allTransactions: Transaction[]; // Alle Transaktionen für Berichte/Mitarbeiterzuordnung
  onUpdateCustomer: (updatedCustomer: Customer) => void;
  onAddTransaction: (newTransaction: Transaction) => void;
  currentUser: User | null;
  onRefreshData: () => Promise<void>; // Prop zur Auslösung der Datenaktualisierung in App.tsx
}

const CustomerDetails: React.FC<CustomerDetailsProps> = ({
  customers,
  allTransactions,
  onUpdateCustomer,
  onAddTransaction,
  currentUser,
  onRefreshData,
}) => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const [showConfirmationModal, setShowConfirmationModal] = useState(false);
  const [showTransactionTypeModal, setShowTransactionTypeModal] = useState(false);
  const [selectedTransactionType, setSelectedTransactionType] = useState<'Aufladung' | 'Abbuchung' | null>(null);
  const [showTransactionDetailsInputModal, setShowTransactionDetailsInputModal] = useState(false);
  const [transactionData, setTransactionData] = useState<TransactionConfirmationData | null>(null);
  const [customer, setCustomer] = useState<Customer | null>(null);
  const [isLoadingCustomer, setIsLoadingCustomer] = useState(true);
  const [error, setError] = useState<string | null>(null);

  // Status für editierbare Felder
  const [isEditingProfile, setIsEditingProfile] = useState(false);
  const [editFirstName, setEditFirstName] = useState('');
  const [editLastName, setEditLastName] = useState('');
  const [editPhone, setEditPhone] = useState('');
  const [editDogName, setEditDogName] = useState('');
  const [editChipNumber, setEditChipNumber] = useState('');

  // Status zur Verwaltung erweiterter/reduzierter Abschnitte
  const [expandedSections, setExpandedSections] = useState<Record<number, boolean>>({});


  const fetchCustomerDetails = async (customerId: string, authUserId: string | null) => {
    setIsLoadingCustomer(true);
    setError(null);
    try {
      // 1. Kundenprofil abrufen
      const { data: customerProfileData, error: customerProfileError } = await supabase
        .from('customer_profiles')
        .select('*')
        .eq('id', customerId)
        .single();

      if (customerProfileError && customerProfileError.code !== 'PGRST116') { // PGRST116 bedeutet "keine Zeilen gefunden"
        throw customerProfileError;
      }

      let currentCustomerProfile: DbCustomerProfile | null = customerProfileData;

      // Wenn Kunde eingeloggt UND kein Profil existiert, erstelle eines
      if (currentUser?.role === UserRoleEnum.KUNDE && authUserId && !currentCustomerProfile) {
        const { data: newProfileData, error: newProfileError } = await supabase
          .from('customer_profiles')
          .insert({ auth_user_id: authUserId, qr_code_data: `https://example.com/customer/${customerId}` }) // Vereinfachte QR-Code-Daten
          .select()
          .single();

        if (newProfileError) {
          throw newProfileError;
        }
        currentCustomerProfile = newProfileData;
        await onRefreshData(); // Globale Daten nach Profilerstellung aktualisieren
        alert('Ihr Kundenprofil wurde automatisch erstellt. Bitte füllen Sie Ihre Daten aus.');
      } else if (!currentCustomerProfile) {
        // Wenn kein Profil vorhanden ist und kein automatisch erstellter Kundenbenutzer, wurde der Kunde nicht gefunden.
        setError(`Kunde mit ID "${customerId}" nicht gefunden.`);
        setCustomer(null);
        setIsLoadingCustomer(false);
        return;
      }

      // Die E-Mail des Kunden wird jetzt aus dem `Customer`-Objekt in `App.tsx` bezogen
      // und sollte über die `customers`-Liste oder `currentUser` in `props` verfügbar sein.
      const customerEmail = customers.find(c => c.id === customerId)?.email || 'Nicht verfügbar';


      // 3. Transaktionen für diesen Kunden abrufen
      const { data: dbTransactions, error: transactionsError } = await supabase
        .from('transactions')
        .select('*')
        .eq('customer_profile_id', customerId);

      if (transactionsError) {
        throw transactionsError;
      }

      const transformedTransactions: Transaction[] = dbTransactions.map(dbTrx => {
        const employee = customers.find(emp => emp.authUserId === dbTrx.created_by_user_id);
        return {
          id: dbTrx.id,
          customerId: dbTrx.customer_profile_id,
          employeeId: dbTrx.created_by_user_id,
          type: dbTrx.type,
          description: dbTrx.description || (dbTrx.type === 'recharge' ? 'Aufladung' : 'Trails'),
          amount: dbTrx.amount,
          date: parseDateString(dbTrx.created_at)?.toLocaleDateString('de-DE') || dbTrx.created_at,
          employee: employee ? `${employee.firstName} ${employee.lastName}` : 'System',
        };
      });

      const currentBalance = transformedTransactions.reduce((sum, trx) => {
        return trx.type === 'recharge' ? sum + trx.amount : sum - trx.amount;
      }, 0);

      // 4. Trainingsfortschritt für diesen Kunden abrufen
      const { data: dbTrainingProgress, error: trainingProgressError } = await supabase
        .from('training_progress')
        .select('*')
        .eq('customer_profile_id', customerId);

      if (trainingProgressError && trainingProgressError.code !== 'PGRST116') {
        throw trainingProgressError;
      }

      let currentTrainingProgress: DbTrainingProgress[] = dbTrainingProgress || [];

      // Wenn keine Trainingsfortschrittseinträge existieren, initiale erstellen
      if (currentTrainingProgress.length === 0) {
        const initialProgressInserts = TRAINING_LEVEL_DEFINITIONS.map(level => ({
          customer_profile_id: customerId,
          level_name: level.name,
          completed_trails: 0,
          status: level.id === 1 ? 'Aktuell' : 'Gesperrt',
        }));
        const { data: newProgressData, error: newProgressError } = await supabase
          .from('training_progress')
          .insert(initialProgressInserts)
          .select();

        if (newProgressError) {
          console.error('Fehler beim Initialisieren des Ausbildungsfortschritts:', newProgressError.message);
          setError('Fehler beim Initialisieren des Ausbildungsfortschritts.');
          setIsLoadingCustomer(false);
          return;
        }
        currentTrainingProgress = newProgressData;
      }

      // Trainingsfortschritt für die UI transformieren
      const trainingProgressForUI = TRAINING_LEVEL_DEFINITIONS.map(levelDef => {
        const customerLevelProgress = currentTrainingProgress.find(p => p.level_name === levelDef.name);
        return {
          id: levelDef.id,
          dbId: customerLevelProgress?.id || '', // DB PK speichern
          name: levelDef.name,
          requiredHours: levelDef.requiredHours,
          completedHours: customerLevelProgress?.completed_trails || 0,
          status: customerLevelProgress?.status || (levelDef.id === 1 ? 'Aktuell' : 'Gesperrt'),
        };
      }).sort((a, b) => a.id - b.id); // Richtige Reihenfolge sicherstellen

      const currentOverallLevel = trainingProgressForUI.find(p => p.status === 'Aktuell')?.name || TrainingLevelEnum.EINSTEIGER;

      // Avatar-Initialen und Farbe aus den globalen Kunden-Props oder Ableitung
      const customerFromProps = customers.find(c => c.id === customerId);
      const initials = customerFromProps?.avatarInitials || `${currentCustomerProfile.first_name?.charAt(0) || ''}${currentCustomerProfile.last_name?.charAt(0) || ''}`.toUpperCase().slice(0, 2);
      const avatarColor = customerFromProps?.avatarColor || `bg-${['blue', 'green', 'orange', 'red', 'purple', 'indigo'][Math.floor(Math.random() * 6)]}-500`;

      const finalCustomer: Customer = {
        id: customerId,
        authUserId: currentCustomerProfile.auth_user_id,
        avatarInitials: initials,
        avatarColor: avatarColor,
        firstName: currentCustomerProfile.first_name || '',
        lastName: currentCustomerProfile.last_name || '',
        email: customerEmail, // Verwenden der von App.tsx bereitgestellten E-Mail
        phone: currentCustomerProfile.phone || '',
        dogName: currentCustomerProfile.dog_name || '',
        chipNumber: currentCustomerProfile.chip_number || '',
        qrCodeData: currentCustomerProfile.qr_code_data || '',
        balance: currentBalance,
        totalTransactions: transformedTransactions.length,
        level: currentOverallLevel,
        createdAt: parseDateString(currentCustomerProfile.created_at || new Date().toISOString())?.toLocaleDateString('de-DE') || '-',
        documents: [], // Nicht von DB implementiert
        trainingProgress: trainingProgressForUI,
      };

      setCustomer(finalCustomer);
      // Bearbeitungszustände initialisieren
      setEditFirstName(finalCustomer.firstName);
      setEditLastName(finalCustomer.lastName);
      setEditPhone(finalCustomer.phone);
      setEditDogName(finalCustomer.dogName);
      setEditChipNumber(finalCustomer.chipNumber);

      // Erweiterte Abschnitte initialisieren
      setExpandedSections(prev => {
        const newExpanded = { ...prev };
        trainingProgressForUI.forEach(section => {
          if (newExpanded[section.id] === undefined) {
            newExpanded[section.id] = false;
          }
        });
        return newExpanded;
      });

    } catch (err: any) {
      console.error('Fehler beim Abrufen der Kundendetails:', err.message);
      setError(`Fehler beim Laden der Kundendaten: ${err.message}`);
      setCustomer(null);
    } finally {
      setIsLoadingCustomer(false);
    }
  };

  useEffect(() => {
    if (id) {
      // Für Kundenrollen sicherstellen, dass sie nur ihr eigenes Profil sehen können
      if (currentUser?.role === UserRoleEnum.KUNDE && currentUser.associatedCustomerId !== id) {
        navigate(`/customers/${currentUser.associatedCustomerId}`, { replace: true });
        return;
      }
      fetchCustomerDetails(id, currentUser?.id || null);
    } else {
      setError('Keine Kunden-ID in der URL gefunden.');
      setCustomer(null);
    }
  }, [id, currentUser?.id, currentUser?.role, currentUser?.associatedCustomerId, customers]); // Re-Run, wenn ID oder currentUser oder customers ändert


  if (isLoadingCustomer) {
    return (
      <div className="p-8 text-center text-gray-600">
        Lade Kundendaten...
      </div>
    );
  }

  if (error) {
    return (
      <div className="p-8 text-center text-red-600">
        {error}
        <Button variant="primary" onClick={() => navigate('/customers')} className="mt-4">
          Zurück zur Kundenliste
        </Button>
      </div>
    );
  }

  if (!customer) {
    return (
      <div className="p-8 text-center text-gray-600">
        Kunde nicht gefunden oder nicht verfügbar.
        <Button variant="primary" onClick={() => navigate('/customers')} className="mt-4">
          Zurück zur Kundenliste
        </Button>
      </div>
    );
  }

  // Diese Funktion öffnet nun speziell das *Bestätigungs*-Modal
  const handleOpenConfirmationModal = (amount: number, type: 'Aufladung' | 'Abbuchung', description?: string) => {
    if (!customer) return; // Sollte mit den aktuellen Prüfungen nicht passieren

    const oldBalance = customer.balance;
    const newBalance = type === 'Aufladung' ? oldBalance + amount : oldBalance - amount;
    setTransactionData({
      customerId: customer.id,
      customerName: `${customer.firstName} ${customer.lastName}`,
      employee: currentUser ? `${currentUser.firstName} ${currentUser.lastName}` : 'System',
      transactionType: type,
      amount: amount,
      oldBalance: oldBalance,
      newBalance: newBalance,
      description: description, // Beschreibung übergeben
    });
    setShowConfirmationModal(true);
  };

  // Neue Funktion zur Handhabung der Auswahl des Transaktionstyps aus dem TransactionTypeSelectionModal
  const handleSelectTransactionType = (type: 'Aufladung' | 'Abbuchung') => {
    setSelectedTransactionType(type);
    setShowTransactionTypeModal(false); // Das initiale Typauswahl-Modal schließen
    setShowTransactionDetailsInputModal(true); // Das neue Detail-Eingabe-Modal öffnen
  };

  // Neue Funktion zur Handhabung der Bestätigung von Transaktionsdetails aus dem TransactionDetailsInputModal
  const handleConfirmTransactionDetails = (amount: number, description: string) => {
    if (!selectedTransactionType || !customer) return; // Sollte nicht passieren

    // Die vorhandene handleOpenConfirmationModal mit allen gesammelten Daten aufrufen
    handleOpenConfirmationModal(amount, selectedTransactionType, description);
    setShowTransactionDetailsInputModal(false); // Das Detail-Eingabe-Modal schließen
    setSelectedTransactionType(null); // Ausgewählten Typ nach Initiierung der Bestätigung zurücksetzen
  };

  const handleConfirmTransaction = async () => {
    if (!transactionData || !customer || !currentUser) {
      alert('Transaktionsdaten oder Benutzer fehlen.');
      return;
    }

    try {
      // 1. Neue Transaktion einfügen
      const { error: insertTransactionError } = await supabase
        .from('transactions')
        .insert({
          customer_profile_id: customer.id,
          created_by_user_id: currentUser.id,
          type: transactionData.transactionType === 'Aufladung' ? 'recharge' : 'debit',
          description: transactionData.description || (transactionData.transactionType === 'Aufladung' ? 'Aufladung' : 'Trails'),
          amount: transactionData.amount,
          created_at: new Date().toISOString(),
        });

      if (insertTransactionError) {
        throw insertTransactionError;
      }

      // 2. Trainingsfortschritt aktualisieren, wenn es sich um eine 'Trails'-Abbuchung handelt
      const isRecharge = transactionData.transactionType === 'Aufladung';
      // Angepasste Abbuchungsprüfung: Angenommen, transactionData.amount stellt die Anzahl der Trails dar, wenn die Beschreibung 'Trails' ist
      const isTrailDebit = !isRecharge && transactionData.description === 'Trails' && transactionData.amount > 0;

      if (isTrailDebit) {
        const currentTrainingProgress = [...customer.trainingProgress];
        let customerOverallLevel = customer.level;

        const currentLevelIndex = currentTrainingProgress.findIndex(
          (section) => section.status === 'Aktuell'
        );

        if (currentLevelIndex !== -1) {
          const currentSection = { ...currentTrainingProgress[currentLevelIndex] };

          // Für das Expert-Level können die completedHours die requiredHours überschreiten
          if (currentSection.name === TrainingLevelEnum.EXPERT) {
            currentSection.completedHours += transactionData.amount; // Abgebuchte Menge direkt zu den abgeschlossenen Trails für Expert hinzufügen
          } else if (currentSection.completedHours < currentSection.requiredHours) {
            // Abgeschlossene Stunden um den abgebuchten Betrag erhöhen (angenommen, der Betrag ist hier die Anzahl der Trails)
            const trailsDebited = transactionData.amount;
            currentSection.completedHours += trailsDebited; 

            if (currentSection.completedHours >= currentSection.requiredHours) { // Prüfen, ob die Anforderungen erfüllt oder überschritten wurden
              currentSection.status = 'Abgeschlossen';

              const nextLevelIndex = currentLevelIndex + 1;
              if (nextLevelIndex < currentTrainingProgress.length) {
                const nextSection = { ...currentTrainingProgress[nextLevelIndex] };
                nextSection.status = 'Aktuell';
                customerOverallLevel = nextSection.name;
                currentTrainingProgress[nextLevelIndex] = nextSection;
              }
            }
          }

          // DB-Eintrag für den aktuellen Abschnitt aktualisieren
          const { error: updateProgressError } = await supabase
            .from('training_progress')
            .update({
              completed_trails: currentSection.completedHours,
              status: currentSection.status,
              level_name: currentSection.name, // Sicherstellen, dass level_name bei der Aktualisierung korrekt gesetzt ist
            })
            .eq('id', currentSection.dbId);

          if (updateProgressError) {
            throw updateProgressError;
          }

          // Wenn sich das Level geändert hat, sicherstellen, dass customer.level dies widerspiegelt (obwohl nicht in customer_profiles gespeichert)
          // Das `level` im Kundenobjekt wird abgeleitet, aber diese Logik hilft, es in der UI temporär zu aktualisieren.
          if (customerOverallLevel !== customer.level) {
            // Den Status anderer Abschnitte aktualisieren, falls erforderlich (z.B. wenn ein neues Level 'Aktuell' wurde)
            for(const section of currentTrainingProgress) {
              if (section.id !== currentSection.id) {
                await supabase.from('training_progress').update({status: section.status}).eq('id', section.dbId);
              }
            }
          }
        }
      }

      alert('Transaktion erfolgreich gebucht!');
      setShowConfirmationModal(false);
      setTransactionData(null);
      await onRefreshData(); // Vollständige Datenaktualisierung in App.tsx auslösen

    } catch (err: any) {
      console.error('Fehler beim Bestätigen der Transaktion:', err.message);
      alert(`Fehler beim Buchen der Transaktion: ${err.message}`);
    }
  };

  const handleUpdateProfile = async () => {
    if (!customer) return;

    try {
      const { error: updateError } = await supabase
        .from('customer_profiles')
        .update({
          first_name: editFirstName,
          last_name: editLastName,
          phone: editPhone,
          dog_name: editDogName,
          chip_number: editChipNumber,
        })
        .eq('id', customer.id);

      if (updateError) {
        throw updateError;
      }

      alert('Kundenprofil erfolgreich aktualisiert!');
      setIsEditingProfile(false);
      await onRefreshData(); // Globale Daten aktualisieren, um ggf. Kundenliste zu aktualisieren

    } catch (err: any) {
      console.error('Fehler beim Aktualisieren des Kundenprofils:', err.message);
      alert(`Fehler beim Aktualisieren des Profils: ${err.message}`);
    }
  };

  const getStatusClasses = (status: string) => {
    switch (status) {
      case 'Aktuell':
        return 'bg-green-100 text-green-800';
      case 'Gesperrt':
        return 'bg-red-100 text-red-800';
      case 'Abgeschlossen':
        return 'bg-blue-100 text-blue-800';
      default:
        return 'bg-gray-100 text-gray-800';
    }
  };

  // Hilfskomponente für eine konsistente Datenzeile
  const DataRow: React.FC<{ Icon: React.ElementType; label: string; value: string | number; editable?: boolean; editValue?: string; onEditChange?: (e: React.ChangeEvent<HTMLInputElement>) => void }> = ({ Icon, label, value, editable, editValue, onEditChange }) => (
    <div>
      <div className="flex items-center text-gray-500 mb-1">
        <Icon className="h-4 w-4 mr-2" />
        <span className="text-sm font-medium">{label}</span>
      </div>
      {editable ? (
        <Input
          id={`edit-${label.replace(/\s/g, '')}`}
          type="text"
          value={editValue || ''}
          onChange={onEditChange}
          className="ml-6 mt-1 p-1 text-sm bg-gray-50 border border-gray-200 rounded-md focus:ring-blue-500 focus:border-blue-500"
        />
      ) : (
        <p className="font-semibold text-gray-900 ml-6">{value}</p>
      )}
    </div>
  );

  const toggleSection = (sectionId: number) => {
    setExpandedSections(prev => ({
      ...prev,
      [sectionId]: !prev[sectionId],
    }));
  };

  // Hilfsprogramm zur Ermittlung der Farben für die Level-Übersichtskarte basierend auf TrainingLevelEnum
  const getLevelSummaryCardColors = (level: TrainingLevelEnum) => {
    switch (level) {
      case TrainingLevelEnum.EINSTEIGER:
        return { bg: 'bg-fuchsia-50', text: 'text-fuchsia-700', icon: 'text-fuchsia-700' };
      case TrainingLevelEnum.GRUNDLAGEN:
        return { bg: 'bg-lime-50', text: 'text-lime-700', icon: 'text-lime-700' };
      case TrainingLevelEnum.FORTGESCHRITTENE:
        return { bg: 'bg-sky-50', text: 'text-sky-700', icon: 'text-sky-700' };
      case TrainingLevelEnum.MASTERCLASS:
        return { bg: 'bg-amber-50', text: 'text-amber-700', icon: 'text-amber-700' };
      case TrainingLevelEnum.EXPERT:
        return { bg: 'bg-indigo-50', text: 'text-indigo-700', icon: 'text-indigo-700' };
      default:
        return { bg: 'bg-gray-50', text: 'text-gray-700', icon: 'text-gray-700' };
    }
  };

  const levelSummaryColors = getLevelSummaryCardColors(customer.level);

  // Feststellen, ob der aktuelle Benutzer die Berechtigung hat, Aktionen durchzuführen (Admin oder Mitarbeiter oder eigener Kunde)
  const canPerformActions = currentUser?.role === UserRoleEnum.ADMIN || currentUser?.role === UserRoleEnum.MITARBEITER || (currentUser?.role === UserRoleEnum.KUNDE && currentUser.associatedCustomerId === customer.id);
  const canEditProfile = currentUser?.role === UserRoleEnum.ADMIN || currentUser?.role === UserRoleEnum.MITARBEITER || (currentUser?.role === UserRoleEnum.KUNDE && currentUser.associatedCustomerId === customer.id);
  const canMakeTransactions = currentUser?.role === UserRoleEnum.ADMIN || currentUser?.role === UserRoleEnum.MITARBEITER; // Nur Mitarbeiter/Admin können Transaktionen durchführen

  return (
    <div className="p-6 md:p-8 lg:p-10 min-h-screen">
      <div className="flex items-center justify-between mb-6 flex-wrap gap-4">
        <div className="flex items-center">
          {currentUser?.role !== UserRoleEnum.KUNDE && (
            <button onClick={() => navigate('/customers')} className="text-gray-500 hover:text-gray-700 mr-4">
              <ArrowLeftIcon className="h-6 w-6" />
            </button>
          )}
          <h1 className="text-2xl font-bold text-gray-900 flex items-center">
            {customer.firstName} {customer.lastName}
            <span className="text-gray-500 font-normal text-base ml-2">Kundendetails & Übersicht</span>
          </h1>
        </div>
        {canPerformActions && (
          <div className="flex space-x-3">
            {canEditProfile && (
              isEditingProfile ? (
                <>
                  <Button variant="secondary" onClick={() => setIsEditingProfile(false)}>
                    Abbrechen
                  </Button>
                  <Button variant="primary" onClick={handleUpdateProfile}>
                    Speichern
                  </Button>
                </>
              ) : (
                <Button variant="outline" icon={EditIcon} onClick={() => setIsEditingProfile(true)}>
                  Stammdaten bearbeiten
                </Button>
              )
            )}
            {canMakeTransactions && (
              <Button variant="success" onClick={() => setShowTransactionTypeModal(true)}>
                Transaktionen
              </Button>
