                {currentUser?.role === UserRoleEnum.MITARBEITER ? '1' : '0'}
              </span>
            </h2>
            <ChevronDownIcon className={`h-6 w-6 text-gray-500 transition-transform duration-200 ${expandedRoles[UserRoleEnum.MITARBEITER] ? 'rotate-180' : ''}`} />
          </button>
          {expandedRoles[UserRoleEnum.MITARBEITER] && (
            <div id={`user-list-${UserRoleEnum.MITARBEITER}`} className="p-4 border-t border-gray-200">
              <p className="text-gray-500 text-sm py-4 text-center">Mitarbeiter-Benutzer sind über die App nicht direkt auflistbar oder editierbar.</p>
              {currentUser?.role === UserRoleEnum.MITARBEITER && (
                <div className="flex items-center justify-between py-3">
                  <div className="flex items-center">
                    <Avatar initials={currentUser.avatarInitials} color={currentUser.avatarColor} size="md" className="mr-3" />
                    <div>
                      <p className="font-medium text-gray-900">{currentUser.firstName} {currentUser.lastName}</p>
