import React, { useState, useEffect } from 'react';
import Modal from './Modal';
import Button from './Button';
import Input from './Input';
import Select from './Select';
import { User, UserRoleEnum } from '../types';

interface UserFormModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSubmit: (userData: { firstName: string; lastName: string; email: string; role: UserRoleEnum; password?: string }) => void;
  userToEdit: User | null;
  currentUserRole: UserRoleEnum; // Aktuelle Benutzerrolle übergeben, um die Rollenauswahl einzuschränken
}

const UserFormModal: React.FC<UserFormModalProps> = ({ isOpen, onClose, onSubmit, userToEdit, currentUserRole }) => {
  const [firstName, setFirstName] = useState('');
  const [lastName, setLastName] = useState('');
  const [email, setEmail] = useState('');
  // Passwortfeld ist für diesen Flow nicht direkt relevant und wird entfernt.
  // const [password, setPassword] = useState('');
  const [role, setRole] = useState<UserRoleEnum>(UserRoleEnum.KUNDE); // Standard auf Kunde setzen
  const [firstNameError, setFirstNameError] = useState('');
  const [lastNameError, setLastNameError] = useState('');
  const [emailError, setEmailError] = useState('');
  // const [passwordError, setPasswordError] = useState('');

  useEffect(() => {
    if (userToEdit) {
      setFirstName(userToEdit.firstName);
      setLastName(userToEdit.lastName);
      setEmail(userToEdit.email);
      setRole(userToEdit.role);
      // setPassword('');
    } else {
      setFirstName('');
      setLastName('');
      setEmail('');
      // setPassword('');
      setRole(UserRoleEnum.KUNDE);
    }
    setFirstNameError('');
    setLastNameError('');
    setEmailError('');
    // setPasswordError('');
  }, [userToEdit, isOpen]);

  const validateForm = () => {
    let isValid = true;

    // Vorname und Nachname sind immer für Kundenprofile erforderlich, auch wenn sie erst später mit einem Auth-User verknüpft werden
    if (!firstName.trim()) { 
      setFirstNameError('Vorname ist erforderlich.');
      isValid = false;
    } else {
      setFirstNameError('');
    }

    if (!lastName.trim()) { 
      setLastNameError('Nachname ist erforderlich.');
      isValid = false;
    } else {
      setLastNameError('');
    }

    if (!email.trim()) {
      setEmailError('E-Mail ist erforderlich.');
      isValid = false;
    } else if (!/\S+@\S+\.\S+/.test(email)) {
      setEmailError('Ungültiges E-Mail-Format.');
      isValid = false;
    } else {
      setEmailError('');
    }

    // Passwortvalidierung entfernt, da Passwörter nicht direkt hier gesetzt werden
    // if (!userToEdit && (role === UserRoleEnum.ADMIN || role === UserRoleEnum.MITARBEITER) && !password.trim()) {
    //   setPasswordError('');
    // } else if (password.trim() && password.length < 6) {
    //   setPasswordError('Passwort muss mindestens 6 Zeichen lang sein.');
    //   isValid = false;
    // } else {
    //   setPasswordError('');
    // }

    return isValid;
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (validateForm()) {
      onSubmit({ firstName, lastName, email, role /*, password: password.trim() || undefined */ });
    }
  };

  const title = userToEdit ? 'Kundenprofil bearbeiten' : 'Neues Kundenprofil anlegen';

  const roleOptions = [
    { value: UserRoleEnum.KUNDE, label: 'Kunde' },
    { value: UserRoleEnum.MITARBEITER, label: 'Mitarbeiter' },
    { value: UserRoleEnum.ADMIN, label: 'Admin' },
  ].filter(option => {
    // Nur Admins können Rollen ändern oder Admin/Mitarbeiter-Rollen zuweisen
    if (currentUserRole !== UserRoleEnum.ADMIN && (option.value === UserRoleEnum.ADMIN || option.value === UserRoleEnum.MITARBEITER)) {
      return false;
    }
    // Wenn ein Benutzer bearbeitet wird und es sich nicht um einen Kunden handelt,
    // sollte die Rolle nicht direkt über dieses Frontend-Formular geändert werden können.
    // Dies ist primär für die Bearbeitung von Kundenprofilen gedacht.
    if (userToEdit && (userToEdit.role === UserRoleEnum.ADMIN || userToEdit.role === UserRoleEnum.MITARBEITER) && option.value !== userToEdit.role) {
      return false;
    }
    return true;
  });

  return (
    <Modal isOpen={isOpen} onClose={onClose} title={title} className="max-w-md">
      <form onSubmit={handleSubmit} className="p-0">
        <div className="space-y-4">
          <Input
            id="userEmail"
            label="E-Mail"
            type="email"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            placeholder="max.mustermann@example.com"
            error={emailError}
            // E-Mail ist für neue Kundenprofile bearbeitbar.
            // Für bestehende Kundenprofile (mit auth_user_id) oder Admin/Mitarbeiter ist sie read-only.
            disabled={!!userToEdit && userToEdit.role === UserRoleEnum.KUNDE && userToEdit.email !== 'N/A'} // Kunden-E-Mail nicht direkt hier änderbar, wenn verknüpft
          />
          <Input
            id="userFirstName"
            label="Vorname"
            type="text"
            value={firstName}
            onChange={(e) => setFirstName(e.target.value)}
            placeholder="Max"
            error={firstNameError}
          />
          <Input
            id="userLastName"
            label="Nachname"
            type="text"
            value={lastName}
            onChange={(e) => setLastName(e.target.value)}
            placeholder="Mustermann"
            error={lastNameError}
          />

          {/* Passwortfeld entfernt */}
          {/* <Input
            id="userPassword"
            label="Passwort (nur für neue Kunden-Registrierung oder optional ändern)"
            type="password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            placeholder="Passwort"
            error={passwordError}
          /> */}
          {userToEdit?.role !== UserRoleEnum.KUNDE && (
            <p className="text-sm text-gray-500">
              Für Admin/Mitarbeiter ist keine direkte Passwortänderung über dieses Formular möglich.
            </p>
          )}

          <Select
            id="userRole"
            label="Rolle"
            options={roleOptions}
            value={role}
            onChange={(e) => setRole(e.target.value as UserRoleEnum)}
            // Nur Admins dürfen Rollen ändern. Und selbst Admins können die Rolle
            // eines bestehenden Admin/Mitarbeiter-Benutzers hier nicht ändern,
            // da dies eine Backend-Operation mit Service Role Key erfordert.
            disabled={currentUserRole !== UserRoleEnum.ADMIN || !!userToEdit && userToEdit.role !== UserRoleEnum.KUNDE}
          />
        </div>
        <div className="p-4 border-t border-gray-200 mt-6 flex justify-end space-x-3">
          <Button variant="outline" onClick={onClose} type="button">
            Abbrechen
          </Button>
          <Button variant="success" type="submit">
            Speichern
          </Button>
        </div>
      </form>
    </Modal>
  );
};

export default UserFormModal;

import React, { useState } from 'react';
import Card from '../components/Card';
import Input from '../components/Input';
import Button from '../components/Button';
import { supabase } from '../supabaseClient';
import { UserRoleEnum } from '../types';

interface LoginPageProps {
  onLogin: (email: string, password: string) => Promise<boolean>;
  onRegister: (email: string, password: string) => Promise<boolean>;
}

const LoginPage: React.FC<LoginPageProps> = ({ onLogin, onRegister }) => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [emailError, setEmailError] = useState('');
  const [passwordError, setPasswordError] = useState('');
  const [loginError, setLoginError] = useState('');
  const [isRegistering, setIsRegistering] = useState(false);

  const validateForm = () => {
    let isValid = true;
    setEmailError('');
    setPasswordError('');
    setLoginError('');

    if (!email.trim()) {
      setEmailError('E-Mail ist erforderlich.');
      isValid = false;
    } else if (!/\S+@\S+\.\S+/.test(email)) {
      setEmailError('Ungültiges E-Mail-Format.');
      isValid = false;
    }

    if (!password.trim()) {
      setPasswordError('Passwort ist erforderlich.');
      isValid = false;
    } else if (password.length < 6) {
      setPasswordError('Passwort muss mindestens 6 Zeichen lang sein.');
      isValid = false;
    }

    return isValid;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (validateForm()) {
      setLoginError('');
      try {
        if (isRegistering) {
          const success = await onRegister(email, password);
          if (success) {
            // Registrierung erfolgreich, App.tsx wird den Rest (Profil erstellen, weiterleiten) handhaben
          } else {
            setLoginError('Registrierung fehlgeschlagen. Bitte versuchen Sie es erneut.');
          }
        } else {
          const success = await onLogin(email, password);
          if (!success) {
            setLoginError('Ungültige E-Mail oder ungültiges Passwort.');
          }
        }
      } catch (error: any) {
        console.error('Auth error:', error.message);
        setLoginError(`Ein Fehler ist aufgetreten: ${error.message || 'Bitte versuchen Sie es erneut.'}`);
      }
    }
  };

  return (
    <div className="flex items-center justify-center min-h-screen w-full bg-gray-100 p-4">
      <Card className="max-w-md w-full p-8">
        <h1 className="text-3xl font-bold text-gray-900 text-center mb-6">Mantrailing Card</h1>
        <p className="text-gray-600 text-center mb-8">{isRegistering ? 'Registrieren Sie sich als Kunde' : 'Melden Sie sich an'}</p>

        <form onSubmit={handleSubmit} className="space-y-6">
          <Input
            id="authEmail"
            label="E-Mail"
            type="email"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            placeholder="ihre.email@example.com"
            error={emailError}
          />
          <Input
            id="authPassword"
            label="Passwort"
            type="password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            placeholder="********"
            error={passwordError}
          />

          {loginError && (
            <div className="text-red-600 text-sm text-center -mt-4">
              {loginError}
            </div>
          )}

          <Button type="submit" variant="primary" className="w-full">
            {isRegistering ? 'Registrieren' : 'Anmelden'}
          </Button>
        </form>

        <div className="mt-6 text-center text-sm text-gray-600">
          {isRegistering ? (
            <>
              Sie haben bereits ein Konto?{' '}
              <button
                type="button"
                className="text-blue-600 hover:text-blue-800 font-medium"
                onClick={() => setIsRegistering(false)}
              >
                Jetzt anmelden
              </button>
            </>
          ) : (
            <>
              Sie haben noch kein Konto?{' '}
              <button
                type="button"
                className="text-blue-600 hover:text-blue-800 font-medium"
                onClick={() => setIsRegistering(true)}
              >
                Jetzt registrieren
              </button>
            </>
          )}
        </div>
      </Card>
    </div>
  );
};

export default LoginPage;

import { createClient } from '@supabase/supabase-js';

const supabaseUrl = import.meta.env.VITE_SUPABASE_URL as string | undefined;
const supabaseAnonKey = import.meta.env.VITE_SUPABASE_ANON_KEY as string | undefined;

if (!supabaseUrl || !supabaseAnonKey) {
  // Zeige eine Fehlermeldung in der Konsole an, aber lasse die App trotzdem laden
  // (z.B. bis zum Login-Bildschirm), damit der Benutzer die ENV-Variablen setzen kann.
  // Es ist besser, die App nicht komplett mit einem throw zu blockieren.
  console.error(
    'Supabase URL oder Anon Key fehlt. Bitte prüfen Sie Ihre Umgebungsvariablen VITE_SUPABASE_URL und VITE_SUPABASE_ANON_KEY.'
  );
  // Optional: Setze Platzhalter, um weitere Fehler zu vermeiden, wenn die App ohne gültige Schlüssel läuft
  // Dies würde aber dazu führen, dass Supabase-Aufrufe fehlschlagen.
  // Derzeit wird erwartet, dass die App beim Fehlen von Schlüsseln nicht korrekt funktioniert.
  // Ein throw wird hier beibehalten, da es eine kritische Abhängigkeit für den Betrieb ist.
  throw new Error(
    'Supabase URL oder Anon Key fehlt. Bitte prüfen Sie Ihre Umgebungsvariablen.'
  );
}

export const supabase = createClient(supabaseUrl, supabaseAnonKey);

import React from 'react';
import ReactDOM from 'react-dom/client';
import { HashRouter } from 'react-router-dom';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    {/* Remove initialEntries, as it's not supported by HashRouter. */}
    {/* Initial navigation is handled by App.tsx based on login status. */}
    <HashRouter> 
      <App />
    </HashRouter>
  </React.StrictMode>
);

import React from 'react';


export interface DbCustomerProfile {
  id: string; // PK
  auth_user_id: string | null; // FK to auth.users.id
  first_name: string | null;
  last_name: string | null;
  phone: string | null;
  dog_name: string | null;
  chip_number: string | null;
  qr_code_data: string | null;
  created_at?: string;
}

export interface DbProfile {
  user_id: string; // PK, FK to auth.users.id
  role: UserRoleEnum;
}

export interface DbTransaction {
  id: string; // PK
  customer_profile_id: string; // FK to customer_profiles.id
  created_by_user_id: string | null; // FK to auth.users.id
  type: 'recharge' | 'debit';
  description: string | null;
  amount: number;
  created_at: string;
}

export interface DbTrainingProgress {
  id: string; // PK
  customer_profile_id: string; // FK to customer_profiles.id
  level_name: TrainingLevelEnum;
  completed_trails: number;
  status: 'Aktuell' | 'Gesperrt' | 'Abgeschlossen';
}

export interface Customer {
  id: string; // customer_profile.id
  authUserId: string | null; // customer_profile.auth_user_id
  avatarInitials: string;
  avatarColor: string;
  firstName: string; // customer_profile.first_name
  lastName: string; // customer_profile.last_name
  email: string; // from auth.users or customer_profile (if denormalized)
  phone: string; // customer_profile.phone
  dogName: string; // customer_profile.dog_name
  chipNumber: string; // customer_profile.chip_number
  balance: number; // Calculated from transactions
  totalTransactions: number; // Calculated from transactions
  level: TrainingLevelEnum; // Derived from trainingProgress
  createdAt: string; // customer_profile.created_at (formatted)
  qrCodeData: string; // customer_profile.qr_code_data
  documents: Document[]; // Still mock/placeholder, not from DB
  trainingProgress: TrainingSection[]; // Derived from DbTrainingProgress
}

export interface Transaction {
  id: string; // transactions.id
  customerId: string; // transactions.customer_profile_id
  employeeId: string | null; // transactions.created_by_user_id
  type: 'recharge' | 'debit';
  description: string; // transactions.description
  amount: number;
  date: string; // transactions.created_at (formatted)
  employee: string; // Derived from employeeId and user data
}

export enum TrainingLevelEnum {
  EINSTEIGER = 'Einsteiger',
  GRUNDLAGEN = 'Grundlagen',
  FORTGESCHRITTENE = 'Fortgeschrittene',
  MASTERCLASS = 'Masterclass',
  EXPERT = 'Expert',
}

export interface TrainingSection {
  id: number; // Logical order ID (1, 2, 3, etc.)
  dbId: string; // training_progress.id (actual PK in DB)
  name: TrainingLevelEnum;
  requiredHours: number;
  completedHours: number; // training_progress.completed_trails
  status: 'Aktuell' | 'Gesperrt' | 'Abgeschlossen';
}

export interface Document {
  id: string;
  name: string;
  url: string;
}

export interface StatCardProps {
  title: string;
  value: string | number;
  icon: React.ElementType; // SVG component
  color: string; // Tailwind color class
  description?: string;
}

export interface NavigationItem {
  path: string;
  label: string;
  icon: React.ElementType; // SVG component
}

export interface CustomerTableData {
  id: string;
  avatarInitials: string;
  avatarColor: string;
  name: string;
  dog: string;
  balance: number;
  level: TrainingLevelEnum;
  createdAt: string;
}

export interface TransactionConfirmationData {
  customerId: string;
  customerName: string;
  employee: string;
  transactionType: 'Aufladung' | 'Abbuchung';
  amount: number;
  oldBalance: number;
  newBalance: number;
  description?: string; // Optional description for the transaction, especially for debits
}

export enum UserRoleEnum {
  ADMIN = 'admin', // Matches SQL enum
  MITARBEITER = 'staff', // Matches SQL enum
  KUNDE = 'customer', // Matches SQL enum
}

