// utils.ts

/**
 * Parses a date string in DD.MM.YYYY format into a Date object.
 * @param dateString The date string to parse.
 * @returns A Date object, or null if parsing fails.
 */
export const parseDateString = (dateString: string): Date | null => {
  const parts = dateString.split('.');
  if (parts.length === 3) {
    const day = parseInt(parts[0], 10);
    const month = parseInt(parts[1], 10) - 1; // Month is 0-indexed
    const year = parseInt(parts[2], 10);

    const date = new Date(year, month, day);
    // Validate if the parsed date components match the input to catch invalid dates like "31.02.2025"
    if (date.getFullYear() === year && date.getMonth() === month && date.getDate() === day) {
      return date;
    }
  }
  return null;
};

/**
 * Checks if two Date objects represent the same day (ignoring time).
 * @param date1 The first Date object.
 * @param date2 The second Date object.
 * @returns True if they represent the same day, false otherwise.
 */
export const isSameDay = (date1: Date, date2: Date): boolean => {
  return (
    date1.getDate() === date2.getDate() &&
    date1.getMonth() === date2.getMonth() &&
    date1.getFullYear() === date2.getFullYear()
  );
};

/**
 * Checks if two Date objects represent the same month and year (ignoring day and time).
 * @param date1 The first Date object.
 * @param date2 The second Date object.
 * @returns True if they represent the same month and year, false otherwise.
 */
export const isSameMonth = (date1: Date, date2: Date): boolean => {
  return (
    date1.getMonth() === date2.getMonth() &&
    date1.getFullYear() === date2.getFullYear()
  );
};

import React, { useState } from 'react';
import Card from '../components/Card';
import Button from '../components/Button';
import Avatar from '../components/Avatar';
import UserFormModal from '../components/UserFormModal';
import UserDeleteConfirmationModal from '../components/UserDeleteConfirmationModal';
import { EditIcon, TrashIcon, UserPlusIcon, ChevronDownIcon } from '../components/Icons';
import { User, UserRoleEnum, Customer } from '../types'; // Import Customer type

interface UserManagementProps {
  users: User[]; // Enthält den currentUser und Kundenprofile (Admin/Mitarbeiter)
  onAddUser: (newUser: { firstName: string; lastName: string; email: string; role: UserRoleEnum; password?: string }) => Promise<void>;
  onUpdateUser: (updatedUser: User) => Promise<void>;
  onDeleteUser: (userId: string) => Promise<void>;
  currentUser: User | null; // Aktuell eingeloggter Benutzer zur Überprüfung von Berechtigungen
  customers: Customer[]; // Liste der Kunden aus App.tsx, um Kundenprofile darzustellen
}

const UserManagement: React.FC<UserManagementProps> = ({ users, onAddUser, onUpdateUser, onDeleteUser, currentUser, customers }) => {
  const [showUserFormModal, setShowUserFormModal] = useState(false);
  const [userToEdit, setUserToEdit] = useState<User | null>(null);
  const [showDeleteConfirmationModal, setShowDeleteConfirmationModal] = useState(false);
  const [userToDeleteId, setUserToDeleteId] = useState<string | null>(null);

  // Zustand für die erweiterbaren Abschnitte der Rollen (nur noch für "Kunden" relevant)
  const [expandedRoles, setExpandedRoles] = useState<Record<UserRoleEnum, boolean>>({
    [UserRoleEnum.ADMIN]: false, // Administratoren sind nicht direkt editierbar oder einsehbar hier
    [UserRoleEnum.MITARBEITER]: false, // Mitarbeiter sind nicht direkt editierbar oder einsehbar hier
    [UserRoleEnum.KUNDE]: true, // Kunden standardmäßig erweitert
  });

  const toggleRoleSection = (role: UserRoleEnum) => {
    setExpandedRoles(prev => ({
      ...prev,
      [role]: !prev[role],
    }));
  };

  const handleOpenAddUserModal = () => {
    setUserToEdit(null); // Für einen neuen Kunden setzen wir null
    setShowUserFormModal(true);
  };

  const handleOpenEditUserModal = (user: User) => {
    setUserToEdit(user);
    setShowUserFormModal(true);
  };

  const handleCloseUserFormModal = () => {
    setShowUserFormModal(false);
    setUserToEdit(null);
  };

  const handleSubmitUserForm = async (userData: { firstName: string; lastName: string; email: string; role: UserRoleEnum; password?: string }) => {
    if (!currentUser) return;

    try {
      if (userToEdit) {
        // Bestehendes Kundenprofil bearbeiten
        const updatedUser: User = {
          ...userToEdit,
          firstName: userData.firstName,
          lastName: userData.lastName,
          // E-Mail kann hier nicht direkt geändert werden
          role: userData.role, // Rolle kann nur von Admin geändert werden
        };
        await onUpdateUser(updatedUser);
      } else {
        // Neues Kundenprofil erstellen (Admin-Sicht)
        await onAddUser(userData);
      }
      handleCloseUserFormModal();
    } catch (error: any) {
      console.error('Fehler beim Übermitteln des Benutzerformulars:', error.message);
      alert(`Fehler beim Speichern des Benutzers: ${error.message}`);
    }
  };

  const handleOpenDeleteConfirmation = (userId: string) => {
    setUserToDeleteId(userId);
    setShowDeleteConfirmationModal(true);
  };

  const handleConfirmDelete = async () => {
    if (userToDeleteId) {
      try {
        await onDeleteUser(userToDeleteId);
        alert('Benutzer erfolgreich gelöscht.');
      } catch (error: any) {
        console.error('Fehler während der Löschbestätigung:', error.message);
        alert(`Fehler beim Löschen des Benutzers: ${error.message}`);
      }
    }
    setShowDeleteConfirmationModal(false);
    setUserToDeleteId(null);
  };

  const handleCloseDeleteConfirmation = () => {
    setShowDeleteConfirmationModal(false);
    setUserToDeleteId(null);
  };

  const getRoleColorClass = (role: UserRoleEnum) => {
    switch (role) {
      case UserRoleEnum.ADMIN:
        return 'bg-red-100 text-red-800';
      case UserRoleEnum.MITARBEITER:
        return 'bg-blue-100 text-blue-800';
      case UserRoleEnum.KUNDE:
        return 'bg-teal-100 text-teal-800';
      default:
        return 'bg-gray-100 text-gray-800';
    }
  };

  // Wir listen nur Kundenprofile auf. Admin/Mitarbeiter-Benutzer sind nicht direkt clientseitig abrufbar.
  // Die "users"-Prop enthält jetzt den currentUser und alle Kunden-Benutzerobjekte (Customer-Objekte transformiert zu User-Objekten)
  const kundeUsers: User[] = customers.map(cust => ({
    id: cust.id, // Hier verwenden wir die customer_profile.id als User.id
    avatarInitials: cust.avatarInitials,
    avatarColor: cust.avatarColor,
    firstName: cust.firstName,
    lastName: cust.lastName,
    email: cust.email,
    role: UserRoleEnum.KUNDE,
    createdAt: cust.createdAt,
    associatedCustomerId: cust.id,
  }));

  // Filterung, falls ein Customer an der UserManagement vorbei kommt (was nicht passieren sollte, aber zur Sicherheit)
  if (currentUser && currentUser.role !== UserRoleEnum.ADMIN) {
    return (
      <div className="p-8 text-center text-red-600">
        Sie haben keine Berechtigung, diese Seite anzuzeigen.
      </div>
    );
  }

  interface UserRoleSectionProps {
    title: string;
    role: UserRoleEnum;
    users: User[];
    isExpanded: boolean;
    onToggle: (role: UserRoleEnum) => void;
    onOpenEditUserModal: (user: User) => void;
    onOpenDeleteConfirmation: (userId: string) => void;
    currentLoggedInUser: User | null;
    showEditDeleteButtons: boolean; // Neue Prop zur Steuerung der Sichtbarkeit der Buttons
  }

  const UserRoleSection: React.FC<UserRoleSectionProps> = ({
    title,
    role,
    users,
    isExpanded,
    onToggle,
    onOpenEditUserModal,
    onOpenDeleteConfirmation,
    currentLoggedInUser,
    showEditDeleteButtons,
  }) => {
    return (
      <Card padding="none" className="overflow-hidden">
        <button
          className="flex items-center justify-between w-full p-4 bg-gray-50 hover:bg-gray-100 transition-colors duration-200"
          onClick={() => onToggle(role)}
          aria-expanded={isExpanded}
          aria-controls={`user-list-${role}`}
        >
          <h2 className="text-xl font-semibold text-gray-900 flex items-center">
            {title}
            <span className={`ml-3 px-2.5 py-0.5 rounded-full text-xs font-medium ${getRoleColorClass(role)}`}>
              {users.length}
            </span>
          </h2>
          <ChevronDownIcon className={`h-6 w-6 text-gray-500 transition-transform duration-200 ${isExpanded ? 'rotate-180' : ''}`} />
        </button>

        {isExpanded && (
          <div id={`user-list-${role}`} className={`p-4 border-t border-gray-200 ${users.length > 5 ? 'max-h-96 overflow-y-auto custom-scrollbar' : ''}`}>
            {users.length === 0 ? (
              <p className="text-gray-500 text-sm py-4 text-center">Keine Benutzer in dieser Rolle gefunden.</p>
            ) : (
              <div className="divide-y divide-gray-200">
                {users.map(user => (
                  <div key={user.id} className="flex items-center justify-between py-3">
                    <div className="flex items-center">
                      <Avatar initials={user.avatarInitials} color={user.avatarColor} size="md" className="mr-3" />
                      <div>
                        <p className="font-medium text-gray-900">{user.firstName} {user.lastName}</p>
                        <p className="text-sm text-gray-500">{user.email}</p>
                      </div>
                    </div>
                    {showEditDeleteButtons && (
                      <div className="flex items-center space-x-3">
                        <button
                          onClick={(e) => { e.stopPropagation(); onOpenEditUserModal(user); }}
                          className="text-gray-500 hover:text-blue-600"
                          aria-label={`Benutzer ${user.firstName} ${user.lastName} bearbeiten`}
                          disabled={user.id === currentLoggedInUser?.id} // Man kann sich nicht selbst bearbeiten
                        >
                          <EditIcon className="h-5 w-5" />
                        </button>
                        <button
                          onClick={(e) => { e.stopPropagation(); onOpenDeleteConfirmation(user.id); }}
                          className="text-gray-500 hover:text-red-600"
                          aria-label={`Benutzer ${user.firstName} ${user.lastName} löschen`}
                          disabled={user.id === currentLoggedInUser?.id} // Man kann sich nicht selbst löschen
                        >
                          <TrashIcon className="h-5 w-5" />
                        </button>
                      </div>
                    )}
                  </div>
                ))}
              </div>
            )}
          </div>
        )}
      </Card>
    );
  };


  const userToDelete = customers.find(c => c.id === userToDeleteId); // Finden des zu löschenden Kunden

  return (
    <div className="p-6 md:p-8 lg:p-10">
      <div className="flex justify-between items-center mb-2">
        <div>
          <h1 className="text-3xl font-bold text-gray-900">Benutzerverwaltung</h1>
          <p className="text-gray-600">Verwalten Sie alle Kundenprofile</p>
        </div>
        {/* Der "Benutzer einladen"-Button wird entfernt, da die Einladung von Admin/Mitarbeiter-Benutzern
            aus dem Frontend ohne supabase.auth.admin.* oder Edge Functions nicht möglich ist.
            Der "Neuer Kunde" Button wird auf diese Weise auch deaktiviert, da die Registrierung über die Login-Seite der primäre Weg ist.
            Admins können hier manuell Kundenprofile OHNE Auth-Benutzer anlegen, diese müssen sich dann selbst registrieren und verknüpfen. */}
        {currentUser?.role === UserRoleEnum.ADMIN && (
          <Button variant="success" icon={UserPlusIcon} onClick={handleOpenAddUserModal}>
            Kundenprofil anlegen
          </Button>
        )}
      </div>

      <div className="mt-8 space-y-6">
        {/* Bereiche für Admin und Mitarbeiter sind hier nicht direkt editierbar/anzeigbar */}
        <Card padding="none" className="overflow-hidden">
          <button
            className="flex items-center justify-between w-full p-4 bg-gray-50 hover:bg-gray-100 transition-colors duration-200"
            onClick={() => toggleRoleSection(UserRoleEnum.ADMIN)}
            aria-expanded={expandedRoles[UserRoleEnum.ADMIN]}
            aria-controls={`user-list-${UserRoleEnum.ADMIN}`}
          >
            <h2 className="text-xl font-semibold text-gray-900 flex items-center">
              Administratoren
              <span className={`ml-3 px-2.5 py-0.5 rounded-full text-xs font-medium ${getRoleColorClass(UserRoleEnum.ADMIN)}`}>
                {/* Anzahl Admins, wenn irgendwie verfügbar, sonst 1 für eingeloggten Admin */}
                {currentUser?.role === UserRoleEnum.ADMIN ? '1' : '0'}
              </span>
            </h2>
            <ChevronDownIcon className={`h-6 w-6 text-gray-500 transition-transform duration-200 ${expandedRoles[UserRoleEnum.ADMIN] ? 'rotate-180' : ''}`} />
          </button>
          {expandedRoles[UserRoleEnum.ADMIN] && (
            <div id={`user-list-${UserRoleEnum.ADMIN}`} className="p-4 border-t border-gray-200">
              <p className="text-gray-500 text-sm py-4 text-center">Admin-Benutzer sind über die App nicht direkt auflistbar oder editierbar.</p>
              {currentUser?.role === UserRoleEnum.ADMIN && (
                <div className="flex items-center justify-between py-3">
                  <div className="flex items-center">
                    <Avatar initials={currentUser.avatarInitials} color={currentUser.avatarColor} size="md" className="mr-3" />
                    <div>
                      <p className="font-medium text-gray-900">{currentUser.firstName} {currentUser.lastName}</p>
                      <p className="text-sm text-gray-500">{currentUser.email}</p>
                    </div>
                  </div>
                  <div className="flex items-center space-x-3">
                     {/* Edit-Button für eigenen Admin-Account (falls direkt bearbeitbar in Zukunft) */}
                    <button
                      className="text-gray-500 hover:text-blue-600"
                      aria-label={`Benutzer ${currentUser.firstName} ${currentUser.lastName} bearbeiten`}
                      disabled // Editieren des eigenen Admin-Accounts hier deaktiviert
                    >
                      <EditIcon className="h-5 w-5" />
                    </button>
                    {/* Delete-Button für eigenen Admin-Account ist immer deaktiviert */}
                    <button
                      className="text-gray-500 hover:text-red-600"
                      aria-label={`Benutzer ${currentUser.firstName} ${currentUser.lastName} löschen`}
                      disabled
                    >
                      <TrashIcon className="h-5 w-5" />
                    </button>
                  </div>
                </div>
              )}
            </div>
          )}
        </Card>

        <Card padding="none" className="overflow-hidden">
          <button
            className="flex items-center justify-between w-full p-4 bg-gray-50 hover:bg-gray-100 transition-colors duration-200"
            onClick={() => toggleRoleSection(UserRoleEnum.MITARBEITER)}
            aria-expanded={expandedRoles[UserRoleEnum.MITARBEITER]}
            aria-controls={`user-list-${UserRoleEnum.MITARBEITER}`}
          >
            <h2 className="text-xl font-semibold text-gray-900 flex items-center">
              Mitarbeiter
              <span className={`ml-3 px-2.5 py-0.5 rounded-full text-xs font-medium ${getRoleColorClass(UserRoleEnum.MITARBEITER)}`}>
                {/* Anzahl Mitarbeiter, wenn irgendwie verfügbar, sonst 0 */}
                {currentUser?.role === UserRoleEnum.MITARBEITER ? '1' : '0'}
              </span>
