                    </button>
                    {/* Delete-Button für eigenen Mitarbeiter-Account ist immer deaktiviert */}
                    <button
                      className="text-gray-500 hover:text-red-600"
                      aria-label={`Benutzer ${currentUser.firstName} ${currentUser.lastName} löschen`}
                      disabled
                    >
                      <TrashIcon className="h-5 w-5" />
                    </button>
                  </div>
                </div>
              )}
            </div>
          )}
        </Card>

        {/* Kundenprofile */}
        <UserRoleSection
          title="Kundenprofile"
          role={UserRoleEnum.KUNDE}
          users={kundeUsers}
          isExpanded={expandedRoles[UserRoleEnum.KUNDE]}
          onToggle={toggleRoleSection}
          onOpenEditUserModal={handleOpenEditUserModal}
          onOpenDeleteConfirmation={handleOpenDeleteConfirmation}
