import React, { useState, useEffect } from 'react';
import Modal from './Modal';
import Button from './Button';
import Input from './Input';
import { PlusIcon } from './Icons'; // Reusing PlusIcon for consistency

interface TransactionDetailsInputModalProps {
  isOpen: boolean;
  onClose: () => void;
  transactionType: 'Aufladung' | 'Abbuchung'; // Type already selected from previous modal
  onConfirmDetails: (amount: number, description: string) => void;
}

const TransactionDetailsInputModal: React.FC<TransactionDetailsInputModalProps> = ({
  isOpen,
  onClose,
  transactionType,
  onConfirmDetails,
}) => {
  const [amount, setAmount] = useState('');
  const [description, setDescription] = useState('');
  const [amountError, setAmountError] = useState('');

  useEffect(() => {
    if (isOpen) {
      setAmount('');
      // Set default description based on type
      setDescription(transactionType === 'Aufladung' ? 'Aufladung' : 'Trails');
      setAmountError('');
    }
  }, [isOpen, transactionType]);

  const validateAndConfirm = () => {
    let isValid = true;
    const parsedAmount = parseFloat(amount.replace(',', '.')); // Handle comma as decimal separator

    if (isNaN(parsedAmount) || parsedAmount <= 0) {
      setAmountError('Bitte geben Sie einen gültigen Betrag (> 0) ein.');
      isValid = false;
    } else {
      setAmountError('');
    }

    if (isValid) {
      // Pass the parsed amount and description (or default if empty)
      onConfirmDetails(parsedAmount, description.trim() || (transactionType === 'Aufladung' ? 'Aufladung' : 'Trails'));
    }
  };

  const title = transactionType === 'Aufladung' ? 'Details zur Aufladung' : 'Details zur Abbuchung';

  return (
    <Modal isOpen={isOpen} onClose={onClose} title={title} className="max-w-md">
      <div className="p-0 space-y-4">
        <Input
          id="transactionAmount"
          label="Betrag (€)"
          type="text" // Use text to allow comma, then parse
          inputMode="decimal"
          value={amount}
          onChange={(e) => setAmount(e.target.value)}
          placeholder="z.B. 18.00 oder 18,00"
          error={amountError}
        />
        <Input
          id="transactionDescription"
          label="Beschreibung (optional)"
          type="text"
          value={description}
          onChange={(e) => setDescription(e.target.value)}
          placeholder={transactionType === 'Aufladung' ? 'Aufladung' : 'Trails'}
        />
      </div>
      <div className="p-4 border-t border-gray-200 mt-6 flex justify-end space-x-3">
        <Button variant="outline" onClick={onClose}>
          Abbrechen
        </Button>
        <Button variant="primary" onClick={validateAndConfirm} icon={PlusIcon}>
          Weiter
        </Button>
      </div>
    </Modal>
  );
};

export default TransactionDetailsInputModal;

import { serve } from 'https://deno.land/std@0.224.0/http/server.ts';
import { createClient } 'https://esm.sh/@supabase/supabase-js@2.89.0';

serve(async (req) => {
  if (req.method !== 'POST') {
    return new Response(JSON.stringify({ message: 'Method Not Allowed' }), {
      headers: { 'Content-Type': 'application/json' },
      status: 405,
    });
  }

  // Fix: Add type assertion to Deno.env.get
  const supabaseUrl = (Deno as any).env.get('SUPABASE_URL') ?? '';
  const serviceRoleKey = (Deno as any).env.get('SUPABASE_SERVICE_ROLE_KEY') ?? '';

  const supabaseClient = createClient(
    supabaseUrl,
    serviceRoleKey,
    {
      auth: {
        autoRefreshToken: false,
        persistSession: false,
      },
    },
  );

  // Authentifizierung des Aufrufers (muss ein Admin sein)
  const authHeader = req.headers.get('Authorization');
  if (!authHeader) {
    return new Response(JSON.stringify({ message: 'Authorization header missing' }), {
      headers: { 'Content-Type': 'application/json' },
      status: 401,
    });
  }

  const token = authHeader.split(' ')[1];
  const { data: userData, error: authError } = await supabaseClient.auth.getUser(token);
  if (authError || !userData.user) {
    return new Response(JSON.stringify({ message: 'Invalid or expired token', error: authError?.message }), {
      headers: { 'Content-Type': 'application/json' },
      status: 401,
    });
  }

  const { data: profile, error: profileError } = await supabaseClient
    .from('profiles')
    .select('role')
    .eq('user_id', userData.user.id)
    .single();

  if (profileError || profile?.role !== 'admin') {
    return new Response(JSON.stringify({ message: 'Forbidden: Only administrators can invite users.' }), {
      headers: { 'Content-Type': 'application/json' },
      status: 403,
    });
  }

  try {
    const { email, role } = await req.json();

    if (!email || !['admin', 'staff'].includes(role)) {
      return new Response(JSON.stringify({ message: 'Invalid input: email and role (admin or staff) are required.' }), {
        headers: { 'Content-Type': 'application/json' },
        status: 400,
      });
    }

    // Invite user via email
    const { data: inviteData, error: inviteError } = await supabaseClient.auth.admin.inviteUserByEmail(email, {
      redirectTo: `${supabaseUrl}/auth/v1/callback`, // Supabase default callback, adjust if you have a specific reset page
    });

    if (inviteError) throw inviteError;

    const newUserId = inviteData.user?.id;
    if (!newUserId) throw new Error('User ID not returned after invitation.');

    // Update role in public.profiles table
    const { error: profileInsertError } = await supabaseClient
      .from('profiles')
      .insert({ user_id: newUserId, role: role })
      .select()
      .single();

    if (profileInsertError) throw profileInsertError;

    return new Response(JSON.stringify({
      message: `Benutzer ${email} als ${role} eingeladen.`,
      userEmail: email,
      resetPasswordUrl: inviteData.user?.action_link, // The magic link/reset link
    }), {
      headers: { 'Content-Type': 'application/json' },
      status: 200,
    });

  } catch (error: any) {
    return new Response(JSON.stringify({ message: error.message }), {
      headers: { 'Content-Type': 'application/json' },
      status: 400,
    });
  }
});

