    ...users
      .filter(user => user.role === UserRoleEnum.ADMIN || user.role === UserRoleEnum.MITARBEITER)
      .map(user => ({
        value: `${user.firstName} ${user.lastName}`,
        label: `${user.firstName} ${user.lastName}`,
      }))
      .sort((a, b) => a.label.localeCompare(b.label)),
  ];

  // Effect to update availableTimePeriods and reset timePeriod when reportType changes
  useEffect(() => {
    const newPeriods = generateReportPeriods(reportType, REFERENCE_DATE);
    setAvailableTimePeriods(newPeriods);
    if (newPeriods.length > 0) {
      setTimePeriod(newPeriods[0].value); // Set to the first option by default
    } else {
      setTimePeriod('Gesamt'); // Fallback
    }
  }, [reportType]);


  if (isLoading) {
    return (
      <div className="p-8 text-center text-gray-600">
        Lade Berichtsdaten...
      </div>
    );
  }

  // Helper for parsing current filter period
  const getFilterPeriodDate = () => {
    if (timePeriod === 'Gesamt') return null;

    // Check if it's a year (e.g., "2025")
    if (!isNaN(parseInt(timePeriod, 10)) && timePeriod.length === 4) {
      return new Date(parseInt(timePeriod, 10), 0, 1); // January 1st of the year
    }

    // Assume "Month YYYY" format for detailed filtering
    const [monthName, year] = timePeriod.split(' ');
    const monthMap: { [key: string]: number } = {
      'Januar': 0, 'Februar': 1, 'März': 2, 'April': 3, 'Mai': 4, 'Juni': 5,
      'Juli': 6, 'August': 7, 'September': 8, 'Oktober': 9, 'November': 10, 'Dezember': 11
    };
    const monthIndex = monthMap[monthName];
    if (monthIndex !== undefined && year) {
      return new Date(parseInt(year, 10), monthIndex, 1);
    }
    return null;
  };

  const selectedFilterPeriod = getFilterPeriodDate();

  // Filter transactions based on selected criteria
  const filteredTransactions = transactions.filter(t => {
    const transactionDate = parseDateString(t.date);
    if (!transactionDate) return false;

    // Filter by period
    let matchesPeriod = true;
    if (timePeriod === 'Gesamt') {
      matchesPeriod = true;
    } else if (reportType === 'Monatlich' && selectedFilterPeriod) {
      matchesPeriod = isSameMonth(transactionDate, selectedFilterPeriod);
    } else if (reportType === 'Jährlich' && selectedFilterPeriod) {
      matchesPeriod = transactionDate.getFullYear() === selectedFilterPeriod.getFullYear();
    }


    // Filter by employee
    const matchesEmployee = employee === 'Alle Mitarbeiter' || t.employee === employee;

    // Filter by transaction type
    let matchesTransactionType = true;
    if (transactionFilter === 'Einnahmen (Aufladungen)') {
      matchesTransactionType = t.type === 'recharge';
    } else if (transactionFilter === 'Ausgaben (Abbuchungen)') {
      matchesTransactionType = t.type === 'debit';
    }

    return matchesPeriod && matchesEmployee && matchesTransactionType;
  });

  // Dynamic calculations for Report Stats
  const monthlyRecharges = filteredTransactions
    .filter(t => t.type === 'recharge')
    .reduce((sum, t) => sum + Math.abs(t.amount), 0);

  const monthlyDebits = filteredTransactions
    .filter(t => t.type === 'debit')
    .reduce((sum, t) => sum + Math.abs(t.amount), 0);

  const totalMonthlyTransactions = filteredTransactions.length;

  const activeCustomerIdsInPeriod = new Set(
    filteredTransactions.map(t => t.customerId)
  );
  const activeCustomersInPeriodCount = customers.filter(c => activeCustomerIdsInPeriod.has(c.id)).length;


  const getTopCustomers = () => {
    const customerTransactions: { [key: string]: { count: number; totalAmount: number } } = {};
    filteredTransactions.forEach(t => {
      if (!customerTransactions[t.customerId]) {
        customerTransactions[t.customerId] = { count: 0, totalAmount: 0 };
      }
      customerTransactions[t.customerId].count++;
      customerTransactions[t.customerId].totalAmount += Math.abs(t.amount);
    });

    return Object.entries(customerTransactions)
      .sort(([, a], [, b]) => b.totalAmount - a.totalAmount)
      .slice(0, 3)
      .map(([customerId, data]) => {
        const customer = customers.find(c => c.id === customerId);
        return {
          customerName: customer ? `${customer.firstName} ${customer.lastName}` : 'Unbekannt',
          dogName: customer?.dogName || '',
          transactionCount: data.count,
          totalAmount: data.totalAmount,
          avatarInitials: customer?.avatarInitials || '?',
          avatarColor: customer?.avatarColor || 'bg-gray-400',
          id: customerId,
        };
      });
  };

  const topCustomers = getTopCustomers();

  const handleExportPdf = async () => {
    setIsGeneratingPdf(true);
    try {
      const doc = new jsPDF();
      let yPos = 20;

      // Report Title
      doc.setFontSize(22);
      doc.text(`Mantrailing Card App - ${reportType} Bericht`, 105, yPos, { align: 'center' });
      yPos += 10;
      doc.line(20, yPos, 190, yPos); // Horizontal line
      yPos += 10;

      // Filter Details
      doc.setFontSize(12);
      doc.text(`Berichtstyp: ${reportType}`, 20, yPos);
      yPos += 7;
      doc.text(`Zeitraum: ${timePeriod}`, 20, yPos);
      yPos += 7;
      doc.text(`Mitarbeiter: ${employee}`, 20, yPos);
      yPos += 7;
      doc.text(`Transaktionstyp: ${transactionFilter}`, 20, yPos); // Add transaction filter to PDF
      yPos += 7;
      doc.text(`Erstellt am: ${REFERENCE_DATE.toLocaleDateString('de-DE')}`, 20, yPos);
      yPos += 15;

      // Summary Stats
      doc.setFontSize(16);
      doc.text('Übersicht', 20, yPos);
      yPos += 7;
      doc.setFontSize(12);
      doc.text(`Gesamtaufladungen: ${monthlyRecharges.toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })}`, 20, yPos);
      yPos += 7;
      doc.text(`Abbuchungen: ${monthlyDebits.toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })}`, 20, yPos);
      yPos += 7;
      doc.text(`Anzahl Transaktionen: ${totalMonthlyTransactions}`, 20, yPos);
      yPos += 7;
      doc.text(`Aktive Kunden: ${activeCustomersInPeriodCount}`, 20, yPos);
      yPos += 15;

      // Transactions Table
      doc.setFontSize(16);
      doc.text(`${transactionFilter} im Zeitraum`, 20, yPos); // Dynamic title based on filter
      yPos += 5;

      const transactionsHeaders = [['Datum', 'Beschreibung', 'Kunde', 'Mitarbeiter', 'Typ', 'Betrag']];
      const transactionsData = filteredTransactions.map(t => {
        const customer = customers.find(c => c.id === t.customerId);
        const customerName = customer ? `${customer.firstName} ${customer.lastName}` : 'Unbekannt';
        const isRecharge = t.type === 'recharge';
        const amountSign = isRecharge ? '+' : '-';
        const formattedAmount = `${amountSign}${Math.abs(t.amount).toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })}`;
        return [t.date, t.description, customerName, t.employee, t.type === 'recharge' ? 'Aufladung' : 'Abbuchung', formattedAmount];
      });

      (doc as any).autoTable({
        startY: yPos,
        head: transactionsHeaders,
        body: transactionsData,
        theme: 'striped',
        headStyles: { fillColor: [0, 161, 214] }, // Blue color for header
        margin: { top: 10, right: 20, bottom: 10, left: 20 },
        didParseCell: function (data: any) {
          if (data.section === 'body' && data.column.index === 5) { // Amount column
            const amountStr = data.cell.text[0];
            if (amountStr && amountStr.startsWith('+')) {
              data.cell.styles.textColor = [34, 139, 34]; // Green for recharge
            } else if (amountStr && amountStr.startsWith('-')) {
              data.cell.styles.textColor = [220, 20, 60]; // Red for debit
            }
          }
        },
      });

      yPos = (doc as any).autoTable.previous.finalY + 15;

      // Top Customers Table
      doc.setFontSize(16);
      doc.text('Top Kunden im Zeitraum', 20, yPos);
      yPos += 5;

      const topCustomersHeaders = [['Rang', 'Kunde', 'Hund', 'Transaktionen', 'Gesamtbetrag']];
      const topCustomersData = topCustomers.map((c, index) => [
        index + 1,
        c.customerName,
        c.dogName,
        c.transactionCount,
        c.totalAmount.toLocaleString('de-DE', { style: 'currency', currency: 'EUR' }),
      ]);

      (doc as any).autoTable({
        startY: yPos,
        head: topCustomersHeaders,
        body: topCustomersData,
        theme: 'striped',
        headStyles: { fillColor: [0, 161, 214] }, // Blue color for header
        margin: { top: 10, right: 20, bottom: 10, left: 20 },
      });

      const fileName = `Bericht_${reportType.replace(' ', '_')}_${timePeriod.replace(' ', '_')}_${employee.replace(' ', '_')}_${transactionFilter.replace(' ', '_')}.pdf`;
      doc.save(fileName);
      alert('PDF Export erfolgreich!');
    } catch (error) {
      console.error("Fehler beim Erstellen der PDF:", error);
      alert('Fehler beim PDF Export. Bitte versuchen Sie es erneut.');
    } finally {
      setIsGeneratingPdf(false);
    }
  };

  return (
    <div className="p-6 md:p-8 lg:p-10">
      <h1 className="text-3xl font-bold text-gray-900 mb-2">Berichte & Statistiken</h1>
      <p className="text-gray-600 mb-8">Analysieren und exportieren Sie Ihre Geschäftsdaten</p>

      {/* Filters and Export Button */}
      <Card className="mb-8">
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 items-end">
          <Select
            id="reportType"
            label="Berichtstyp"
            options={MOCK_REPORT_TYPES.map(type => ({ value: type, label: type }))}
            value={reportType}
            onChange={(e) => setReportType(e.target.value)}
            disabled={isGeneratingPdf}
          />
          <Select
            id="timePeriod"
            label="Zeitraum"
            options={availableTimePeriods}
            value={timePeriod}
            onChange={(e) => setTimePeriod(e.target.value)}
            disabled={isGeneratingPdf}
          />
          <Select
            id="employee"
            label="Mitarbeiter"
            options={employeeOptions}
            value={employee}
            onChange={(e) => setEmployee(e.target.value)}
            disabled={isGeneratingPdf}
          />
          <Select
            id="transactionFilter"
            label="Transaktionstyp"
            options={MOCK_TRANSACTION_FILTERS.map(filter => ({ value: filter, label: filter }))}
            value={transactionFilter}
            onChange={(e) => setTransactionFilter(e.target.value)}
            disabled={isGeneratingPdf}
          />
          {/* Button moved to the last position in the grid to appear bottom-right */}
          <Button 
            variant="success" 
            className="w-full sm:col-span-1 lg:col-start-4 lg:col-span-1 lg:w-auto"
            onClick={handleExportPdf}
            disabled={isGeneratingPdf}
          >
            {isGeneratingPdf ? 'PDF wird generiert...' : 'Als PDF exportieren'}
          </Button>
        </div>
      </Card>

      {/* Stats Cards for Reports */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
        <StatCard
          title="Gesamtaufladungen"
          value={monthlyRecharges.toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })}
          icon={UsersIcon}
          color="bg-green-100 text-green-700"
        />
        <StatCard
          title="Abbuchungen"
          value={monthlyDebits.toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })}
          icon={DollarSignIcon}
          color="bg-orange-100 text-orange-700"
        />
        <StatCard
          title="Transaktionen"
          value={totalMonthlyTransactions}
          icon={ClipboardIcon}
          color="bg-blue-100 text-blue-700"
        />
        <StatCard
          title="Aktive Kunden"
          value={activeCustomersInPeriodCount}
          icon={UsersIcon}
          color="bg-purple-100 text-purple-700"
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Transaktionen im Zeitraum */}
        <Card>
          <h2 className="text-xl font-semibold text-gray-900 mb-4">{transactionFilter} im Zeitraum ({filteredTransactions.length})</h2>
          <div className="space-y-4 max-h-96 overflow-y-auto custom-scrollbar">
            {filteredTransactions.length === 0 ? (
              <p className="text-gray-500">Keine Transaktionen für den ausgewählten Zeitraum, Mitarbeiter und Transaktionstyp gefunden.</p>
            ) : (
              filteredTransactions.map((transaction) => {
                const customer = customers.find(c => c.id === transaction.customerId);
                const isRecharge = transaction.type === 'recharge';
                const TransactionIcon = isRecharge ? ArrowUpCircleIcon : ArrowDownCircleIcon;
                const iconColor = isRecharge ? 'text-green-500' : 'text-red-500';
                const amountColor = isRecharge ? 'text-green-700' : 'text-red-700';
                const amountSign = isRecharge ? '+' : '-';

                return (
                  <div key={transaction.id} className="flex items-center justify-between p-3 bg-gray-50 rounded-lg">
                    <div className="flex items-center">
                      <span className={`p-2 rounded-full bg-gray-200 mr-3 ${iconColor}`}>
                        <TransactionIcon className="h-5 w-5" />
                      </span>
                      <div>
                        <p className="font-medium text-gray-900">{transaction.description}</p>
                        <p className="text-sm text-gray-500">
                          {transaction.date} von {transaction.employee}
                          {customer && ` für ${customer.firstName} ${customer.lastName}`}
                        </p>
                      </div>
                    </div>
                    <p className={`font-semibold ${amountColor}`}>
                      {amountSign}{Math.abs(transaction.amount).toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })}
                    </p>
                  </div>
                );
              })
            )}
          </div>
        </Card>

        {/* Top Kunden im Zeitraum */}
        <Card>
          <h2 className="text-xl font-semibold text-gray-900 mb-4">Top Kunden im Zeitraum</h2>
          <div className="space-y-4 max-h-96 overflow-y-auto custom-scrollbar">
            {topCustomers.length === 0 ? (
              <p className="text-gray-500">Keine Top-Kunden für den ausgewählten Zeitraum und Mitarbeiter gefunden.</p>
            ) : (
              topCustomers.map((customer, index) => (
                <div key={customer.id} className="flex items-center justify-between p-3 bg-gray-50 rounded-lg">
                  <div className="flex items-center">
                    <span className="text-lg font-bold text-gray-700 mr-3">{index + 1}.</span>
                    <Avatar initials={customer.avatarInitials} color={customer.avatarColor} size="md" className="mr-3" />
                    <div>
                      <p className="font-medium text-gray-900">{customer.customerName}</p>
                      <p className="text-sm text-gray-500">
                        {customer.dogName} &bull; {customer.transactionCount} Transaktion{customer.transactionCount !== 1 ? 'en' : ''}
                      </p>
                    </div>
                  </div>
                  <p className="font-semibold text-gray-800">
                    {customer.totalAmount.toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })}
                  </p>
                </div>
              ))
            )}
          </div>
        </Card>
      </div>
    </div>
  );
};

export default Reports;

import React, { useState, useEffect, useCallback } from 'react';
import { Routes, Route, useNavigate, Navigate } from 'react-router-dom';
import { createClient } from '@supabase/supabase-js';
import Sidebar from './components/Sidebar';
import Dashboard from './pages/Dashboard';
import CustomerManagement from './pages/CustomerManagement';
import CustomerDetails from './pages/CustomerDetails';
import Reports from './pages/Reports';
import UserManagement from './pages/UserManagement'; // Import the new UserManagement page
import LoginPage from './pages/LoginPage'; // Import the new LoginPage
import { Customer, Transaction, TrainingLevelEnum, User, UserRoleEnum, Database } from './types'; // Import types
import { REFERENCE_DATE } from './constants'; // Import constants needed for initial state
import { parseDateString } from './utils'; // Import parseDateString

// Supabase Client Initialization
const supabaseUrl = window.SUPABASE_URL || import.meta.env.VITE_SUPABASE_URL;
const supabaseAnonKey = window.SUPABASE_ANON_KEY || import.meta.env.VITE_SUPABASE_ANON_KEY;

if (!supabaseUrl || !supabaseAnonKey) {
  console.error("Supabase URL or Anon Key is missing. Please check your environment variables or global script.");
  // Fallback to prevent app crash, but indicate a problem
  // alert("Supabase configuration missing! Please ensure SUPABASE_URL and SUPABASE_ANON_KEY are set.");
}

const supabase = createClient<Database>(supabaseUrl, supabaseAnonKey);

const App: React.FC = () => {
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [users, setUsers] = useState<User[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true); // Initial loading state for app data
  const navigate = useNavigate();

  const fetchUsers = useCallback(async () => {
    setLoading(true);
    const { data: profilesData, error: profilesError } = await supabase
      .from('profiles')
      .select('*');

    if (profilesError) {
      console.error('Error fetching users:', profilesError);
      alert(`Fehler beim Laden der Benutzer: ${profilesError.message}`);
      setUsers([]);
      return;
    }

    const fetchedUsers: User[] = profilesData.map(profile => ({
      id: profile.id,
      avatarInitials: profile.avatarInitials,
      avatarColor: profile.avatarColor,
      firstName: profile.firstName,
      lastName: profile.lastName,
      email: profile.email,
      role: profile.role as UserRoleEnum, // Cast to enum
      createdAt: profile.createdAt,
      associatedCustomerId: profile.associatedCustomerId,
    }));
    setUsers(fetchedUsers);
    setLoading(false);
  }, []);

  const fetchCustomers = useCallback(async () => {
    setLoading(true);
    const { data: customersData, error: customersError } = await supabase
      .from('customers')
      .select(`
        *,
        documents(*),
        training_sections(*)
      `);

    if (customersError) {
      console.error('Error fetching customers:', customersError);
      alert(`Fehler beim Laden der Kunden: ${customersError.message}`);
      setCustomers([]);
      return;
    }

    const fetchedCustomers: Customer[] = customersData.map(customer => {
      // Ensure trainingProgress is sorted by id
      const sortedTrainingProgress = customer.training_sections
        ? [...customer.training_sections].sort((a, b) => a.id - b.id)
        : [];

      return {
        id: customer.id,
        avatarInitials: customer.avatarInitials,
        avatarColor: customer.avatarColor,
        firstName: customer.firstName,
        lastName: customer.lastName,
        email: customer.email,
        phone: customer.phone || '',
        dogName: customer.dogName,
        chipNumber: customer.chipNumber,
        balance: customer.balance,
        totalTransactions: customer.totalTransactions,
        level: customer.level as TrainingLevelEnum, // Cast to enum
        createdAt: customer.createdAt,
        createdBy: customer.createdBy,
        qrCodeData: customer.qrCodeData,
        documents: customer.documents || [],
        trainingProgress: sortedTrainingProgress,
      };
    });
    setCustomers(fetchedCustomers);
    setLoading(false);
  }, []);

  const fetchTransactions = useCallback(async () => {
    setLoading(true);
    const { data: transactionsData, error: transactionsError } = await supabase
      .from('transactions')
      .select('*');

    if (transactionsError) {
      console.error('Error fetching transactions:', transactionsError);
      alert(`Fehler beim Laden der Transaktionen: ${transactionsError.message}`);
      setTransactions([]);
      return;
    }

    const fetchedTransactions: Transaction[] = transactionsData.map(t => ({
      id: t.id,
      customerId: t.customerId,
      type: t.type as 'recharge' | 'debit',
      description: t.description || '',
      amount: t.amount,
      date: t.date,
      employee: t.employee,
    }));
    setTransactions(fetchedTransactions);
    setLoading(false);
  }, []);

  const fetchAllData = useCallback(async () => {
    setLoading(true);
    await Promise.all([
      fetchUsers(),
      fetchCustomers(),
      fetchTransactions(),
    ]);
    setLoading(false);
  }, [fetchUsers, fetchCustomers, fetchTransactions]);

  // Auth State Change Listener
  useEffect(() => {
    const { data: authListener } = supabase.auth.onAuthStateChange(
      async (event, session) => {
        if (session) {
          setIsLoggedIn(true);
          // Fetch the user's profile from the 'profiles' table
          const { data: profile, error: profileError } = await supabase
            .from('profiles')
            .select('*')
            .eq('id', session.user.id)
            .single();

          if (profileError) {
            console.error('Error fetching user profile:', profileError);
            alert(`Fehler beim Laden des Benutzerprofils: ${profileError.message}`);
            setCurrentUser(null);
            setIsLoggedIn(false); // Log out if profile can't be fetched
            navigate('/login', { replace: true });
            return;
          }

          const userProfile: User = {
            id: profile.id,
            avatarInitials: profile.avatarInitials,
            avatarColor: profile.avatarColor,
            firstName: profile.firstName,
            lastName: profile.lastName,
            email: profile.email,
            role: profile.role as UserRoleEnum,
            createdAt: profile.createdAt,
            associatedCustomerId: profile.associatedCustomerId,
          };
          setCurrentUser(userProfile);
          await fetchAllData(); // Fetch all app data after user is logged in

          // Redirection logic based on role
          if (userProfile.role === UserRoleEnum.KUNDE && userProfile.associatedCustomerId) {
            const expectedPath = `/customers/${userProfile.associatedCustomerId}`;
            if (!window.location.hash.startsWith(`#${expectedPath}`)) {
              navigate(expectedPath, { replace: true });
            }
          } else if (window.location.hash === '#/login') {
            navigate('/', { replace: true });
          }
        } else {
          setIsLoggedIn(false);
          setCurrentUser(null);
          setCustomers([]);
          setUsers([]);
          setTransactions([]);
          navigate('/login', { replace: true });
        }
      }
    );

    return () => {
      authListener.subscription.unsubscribe();
    };
  }, [navigate, fetchAllData]);


  // Initial data fetch if already logged in (on page refresh)
  useEffect(() => {
    const checkSession = async () => {
      setLoading(true);
      const { data: { session }, error } = await supabase.auth.getSession();
      if (session) {
        // Session handled by onAuthStateChange listener
      } else if (error) {
        console.error("Error getting session:", error);
        setIsLoggedIn(false);
        setCurrentUser(null);
        navigate('/login', { replace: true });
      } else {
        setIsLoggedIn(false);
        setCurrentUser(null);
        navigate('/login', { replace: true });
      }
      // setLoading(false); // onAuthStateChange will manage final loading state
    };
    checkSession();
  }, [navigate]);

  const handleLogin = async (email: string, passwordInput: string): Promise<boolean> => {
    const { data, error } = await supabase.auth.signInWithPassword({
      email,
      password: passwordInput,
    });

    if (error) {
      console.error('Login error:', error.message);
      alert(`Anmeldung fehlgeschlagen: ${error.message}`);
      return false;
    }

    if (data.user) {
      // onAuthStateChange will handle setting isLoggedIn, currentUser, and redirection
      return true;
    }
    return false;
  };

  const handleLogout = async () => {
    const { error } = await supabase.auth.signOut();
    if (error) {
      console.error('Logout error:', error.message);
      alert(`Abmeldung fehlgeschlagen: ${error.message}`);
    } else {
      // onAuthStateChange will handle state reset and redirection
      alert('Sie wurden erfolgreich abgemeldet.');
    }
  };

  const handleUpdateCustomer = useCallback(async (updatedCustomer: Customer) => {
    setLoading(true);
    // Update customer main data
    const { error: customerError } = await supabase
      .from('customers')
      .update({
        "firstName": updatedCustomer.firstName,
        "lastName": updatedCustomer.lastName,
        email: updatedCustomer.email,
        phone: updatedCustomer.phone,
        "dogName": updatedCustomer.dogName,
        "chipNumber": updatedCustomer.chipNumber,
        balance: updatedCustomer.balance,
        "totalTransactions": updatedCustomer.totalTransactions,
        level: updatedCustomer.level,
        "avatarInitials": updatedCustomer.avatarInitials,
        "avatarColor": updatedCustomer.avatarColor,
        "qrCodeData": updatedCustomer.qrCodeData,
      })
      .eq('id', updatedCustomer.id);

    if (customerError) {
      console.error('Error updating customer:', customerError);
      alert(`Fehler beim Aktualisieren des Kunden: ${customerError.message}`);
      setLoading(false);
      return;
    }

    // Update training progress (delete existing and insert new ones)
    const { error: deleteTpError } = await supabase
      .from('training_sections')
      .delete()
      .eq('customerId', updatedCustomer.id);

    if (deleteTpError) {
      console.error('Error deleting old training progress:', deleteTpError);
      alert(`Fehler beim Aktualisieren des Trainingsfortschritts (Löschen): ${deleteTpError.message}`);
      setLoading(false);
      return;
    }

    const trainingProgressInserts = updatedCustomer.trainingProgress.map(section => ({
      ...section,
      customerId: updatedCustomer.id, // Ensure customerId is set for each section
    }));

    const { error: insertTpError } = await supabase
      .from('training_sections')
      .insert(trainingProgressInserts);

    if (insertTpError) {
      console.error('Error inserting new training progress:', insertTpError);
      alert(`Fehler beim Aktualisieren des Trainingsfortschritts (Einfügen): ${insertTpError.message}`);
      setLoading(false);
      return;
    }

    await fetchCustomers(); // Re-fetch customers to get the updated data
    setLoading(false);
  }, [fetchCustomers]);

  const handleAddTransaction = useCallback(async (newTransaction: Transaction, updatedCustomer: Customer) => {
    setLoading(true);
    const { error: transactionError } = await supabase
      .from('transactions')
      .insert({
        id: newTransaction.id,
        "customerId": newTransaction.customerId,
        type: newTransaction.type,
        description: newTransaction.description,
        amount: newTransaction.amount,
        date: newTransaction.date,
        employee: newTransaction.employee,
      });

    if (transactionError) {
      console.error('Error adding transaction:', transactionError);
      alert(`Fehler beim Hinzufügen der Transaktion: ${transactionError.message}`);
      setLoading(false);
      return;
    }

    // After adding transaction, also update customer's balance and totalTransactions in DB
    await handleUpdateCustomer(updatedCustomer); // Reuses the update logic

    await fetchTransactions(); // Re-fetch transactions
    setLoading(false);
  }, [handleUpdateCustomer, fetchTransactions]);


  const handleAddUser = useCallback(async (newUser: User) => {
    setLoading(true);
    // 1. Create user in Supabase Auth
    const { data: authData, error: authError } = await supabase.auth.signUp({
      email: newUser.email,
      password: newUser.password!, // Password is required for signup
      options: {
        data: {
          firstName: newUser.firstName,
          lastName: newUser.lastName,
          role: newUser.role,
        },
      },
    });

    if (authError) {
      console.error('Error creating auth user:', authError);
      alert(`Fehler beim Erstellen des Benutzers: ${authError.message}`);
      setLoading(false);
      return;
    }

    if (!authData.user) {
      alert('Benutzererstellung fehlgeschlagen: Kein Benutzerobjekt erhalten.');
      setLoading(false);
      return;
    }

    // 2. Create profile entry in 'profiles' table
    const { error: profileError } = await supabase
      .from('profiles')
      .insert({
        id: authData.user.id,
        "firstName": newUser.firstName,
        "lastName": newUser.lastName,
        email: newUser.email,
        role: newUser.role,
        "avatarInitials": newUser.avatarInitials,
        "avatarColor": newUser.avatarColor,
        "createdAt": new Date().toISOString(), // Use ISO string for DB
        "associatedCustomerId": newUser.associatedCustomerId || null,
      });

    if (profileError) {
      console.error('Error creating profile:', profileError);
      alert(`Fehler beim Erstellen des Profils: ${profileError.message}`);
      // Consider deleting auth user here if profile creation fails
      setLoading(false);
      return;
    }

    // 3. If 'Kunde' role, create customer entry in 'customers' table
    if (newUser.role === UserRoleEnum.KUNDE && newUser.associatedCustomerId) {
      const { error: customerError } = await supabase
        .from('customers')
        .insert({
          id: newUser.associatedCustomerId,
          "firstName": newUser.firstName,
          "lastName": newUser.lastName,
          email: newUser.email,
          "phone": '', // Default
          "dogName": 'Unbekannt', // Default
          "chipNumber": '', // Default
          balance: 0.00,
          "totalTransactions": 0,
          level: TrainingLevelEnum.EINSTEIGER, // Default
          "createdAt": new Date().toISOString(), // Use ISO string for DB
          "createdBy": currentUser ? `${currentUser.firstName} ${currentUser.lastName}` : 'System',
          "qrCodeData": `https://api.qrserver.com/v1/create-qr-code/?size=150x150&data=https://example.com/customer/${newUser.associatedCustomerId}`,
          "avatarInitials": newUser.avatarInitials,
          "avatarColor": newUser.avatarColor,
        });

      if (customerError) {
        console.error('Error creating customer for new Kunde user:', customerError);
        alert(`Fehler beim Erstellen des Kundeneintrags: ${customerError.message}`);
        setLoading(false);
        return;
      }

      // Also insert initial training progress
      const initialTrainingProgress = [
        { id: 1, name: TrainingLevelEnum.EINSTEIGER, requiredHours: 6, completedHours: 0, status: 'Aktuell', customerId: newUser.associatedCustomerId },
        { id: 2, name: TrainingLevelEnum.GRUNDLAGEN, requiredHours: 12, completedHours: 0, status: 'Gesperrt', customerId: newUser.associatedCustomerId },
        { id: 3, name: TrainingLevelEnum.FORTGESCHRITTENE, requiredHours: 12, completedHours: 0, status: 'Gesperrt', customerId: newUser.associatedCustomerId },
        { id: 4, name: TrainingLevelEnum.MASTERCLASS, requiredHours: 12, completedHours: 0, status: 'Gesperrt', customerId: newUser.associatedCustomerId },
        { id: 5, name: TrainingLevelEnum.EXPERT, requiredHours: 100, completedHours: 0, status: 'Gesperrt', customerId: newUser.associatedCustomerId },
      ];

      const { error: tpError } = await supabase
        .from('training_sections')
        .insert(initialTrainingProgress);

      if (tpError) {
        console.error('Error creating initial training progress for new Kunde user:', tpError);
        alert(`Fehler beim Erstellen des initialen Trainingsfortschritts: ${tpError.message}`);
        setLoading(false);
        return;
      }
    }

    alert('Benutzer erfolgreich erstellt!');
    await fetchAllData(); // Re-fetch all data to update lists
    setLoading(false);
  }, [fetchAllData, currentUser]);

  const handleUpdateUser = useCallback(async (updatedUser: User) => {
    setLoading(true);
    // Update profile
    const { error: profileError } = await supabase
      .from('profiles')
      .update({
        "firstName": updatedUser.firstName,
        "lastName": updatedUser.lastName,
        email: updatedUser.email,
        role: updatedUser.role,
        "avatarInitials": updatedUser.avatarInitials,
        "avatarColor": updatedUser.avatarColor,
        "associatedCustomerId": updatedUser.associatedCustomerId,
      })
      .eq('id', updatedUser.id);

    if (profileError) {
      console.error('Error updating profile:', profileError);
      alert(`Fehler beim Aktualisieren des Profils: ${profileError.message}`);
      setLoading(false);
      return;
    }

    // Update password if provided
    if (updatedUser.password) {
      const { error: passwordError } = await supabase.auth.updateUser({
        email: updatedUser.email, // Ensure email matches the user being updated
        password: updatedUser.password,
      });
      if (passwordError) {
        console.error('Error updating user password:', passwordError);
        alert(`Fehler beim Aktualisieren des Passworts: ${passwordError.message}`);
        setLoading(false);
        return;
      }
    }

    // If the updated user is a 'Kunde' and has an associatedCustomerId,
    // also update the corresponding customer's details
    if (updatedUser.role === UserRoleEnum.KUNDE && updatedUser.associatedCustomerId) {
      const { error: customerError } = await supabase
        .from('customers')
        .update({
          "firstName": updatedUser.firstName,
          "lastName": updatedUser.lastName,
          email: updatedUser.email,
          "avatarInitials": updatedUser.avatarInitials,
          "avatarColor": updatedUser.avatarColor,
        })
        .eq('id', updatedUser.associatedCustomerId);

      if (customerError) {
        console.error('Error updating associated customer:', customerError);
        alert(`Fehler beim Aktualisieren des zugehörigen Kunden: ${customerError.message}`);
        setLoading(false);
        return;
      }
    }

    alert('Benutzer erfolgreich aktualisiert!');
    await fetchAllData(); // Re-fetch all data to update lists
    setLoading(false);
  }, [fetchAllData]);

  const handleDeleteUser = useCallback(async (userId: string) => {
    setLoading(true);
    // Find user to see if they have an associated customer
    const userToDelete = users.find(u => u.id === userId);

    // Delete user from Auth (this should cascade delete the profile due to FK setup)
    const { error: authError } = await supabase.auth.admin.deleteUser(userId);

    if (authError) {
      console.error('Error deleting auth user:', authError);
      alert(`Fehler beim Löschen des Benutzers: ${authError.message}`);
      setLoading(false);
      return;
    }

    // If the deleted user was a 'Kunde' with an associatedCustomerId,
    // also delete the corresponding customer entry.
    // NOTE: If RLS is strict, this might need admin privileges or a function.
    // For now, assuming RLS allows admins/employees to delete customers.
    if (userToDelete && userToDelete.role === UserRoleEnum.KUNDE && userToDelete.associatedCustomerId) {
      const { error: customerError } = await supabase
        .from('customers')
        .delete()
        .eq('id', userToDelete.associatedCustomerId);

      if (customerError) {
        console.error('Error deleting associated customer:', customerError);
        alert(`Fehler beim Löschen des zugehörigen Kunden: ${customerError.message}`);
        setLoading(false);
        return;
      }
    }

    alert('Benutzer erfolgreich gelöscht!');
    await fetchAllData(); // Re-fetch all data to update lists
    setLoading(false);
  }, [fetchAllData, users]);


  return (
    <div className="flex min-h-screen bg-gray-100">
      {isLoggedIn && currentUser ? (
        <>
          <Sidebar appName="Mantrailing Card" currentUser={currentUser} onLogout={handleLogout} />
          <main className="flex-1 md:ml-64 p-0">
            <Routes>
              {currentUser.role === UserRoleEnum.ADMIN ? (
                // Admin has full access
                <>
                  <Route path="/" element={<Dashboard customers={customers} transactions={transactions} currentUser={currentUser} isLoading={loading} />} />
                  <Route path="/customers" element={<CustomerManagement customers={customers} transactions={transactions} currentUser={currentUser} onAddUser={handleAddUser} isLoading={loading} />} />
                  <Route
                    path="/customers/:id"
                    element={<CustomerDetails customers={customers} transactions={transactions} onUpdateCustomer={handleUpdateCustomer} onAddTransaction={handleAddTransaction} currentUser={currentUser} isLoading={loading} />}
                  />
                  <Route path="/reports" element={<Reports customers={customers} transactions={transactions} users={users} isLoading={loading} />} />
                  <Route path="/users" element={<UserManagement users={users} onAddUser={handleAddUser} onUpdateUser={handleUpdateUser} onDeleteUser={handleDeleteUser} isLoading={loading} />} />
                  <Route path="*" element={<Dashboard customers={customers} transactions={transactions} currentUser={currentUser} isLoading={loading} />} /> {/* Fallback for Admin */}
                </>
              ) : currentUser.role === UserRoleEnum.MITARBEITER ? (
                // Mitarbeiter has restricted access
                <>
                  <Route path="/" element={<Dashboard customers={customers} transactions={transactions} currentUser={currentUser} isLoading={loading} />} />
                  <Route path="/customers" element={<CustomerManagement customers={customers} transactions={transactions} currentUser={currentUser} onAddUser={handleAddUser} isLoading={loading} />} />
                  <Route
                    path="/customers/:id"
                    element={<CustomerDetails customers={customers} transactions={transactions} onUpdateCustomer={handleUpdateCustomer} onAddTransaction={handleAddTransaction} currentUser={currentUser} isLoading={loading} />}
                  />
                  {/* Redirect any restricted path or unknown path for Mitarbeiter to dashboard */}
                  <Route path="/reports" element={<Navigate replace to="/" />} />
                  <Route path="/users" element={<Navigate replace to="/" />} />
                  <Route path="*" element={<Dashboard customers={customers} transactions={transactions} currentUser={currentUser} isLoading={loading} />} /> {/* Fallback for Mitarbeiter */}
                </>
              ) : currentUser.role === UserRoleEnum.KUNDE && currentUser.associatedCustomerId ? (
                // Kunde has access only to their own customer details, enforced by internal component logic and redirects
                <>
                  {/* Dynamic route for *any* customer ID. The CustomerDetails component will authorize. */}
                  <Route
                    path="/customers/:id"
                    element={<CustomerDetails customers={customers} transactions={transactions} onUpdateCustomer={handleUpdateCustomer} onAddTransaction={handleAddTransaction} currentUser={currentUser} isLoading={loading} />}
                  />
                  {/* Redirect root path to their own specific customer page */}
                  <Route path="/" element={<Navigate replace to={`/customers/${currentUser.associatedCustomerId}`} />} />
                  {/* Catch-all for any other path not explicitly handled, redirects to their own customer page */}
                  <Route path="*" element={<Navigate replace to={`/customers/${currentUser.associatedCustomerId}`} />} />
                </>
              ) : (
                // Fallback for any other unexpected logged-in state (e.g., customer role without associated ID, though type system should prevent this state for a logged-in user)
                <Route path="*" element={<Dashboard customers={customers} transactions={transactions} currentUser={currentUser} isLoading={loading} />} />
              )}
            </Routes>
          </main>
        </>
      ) : (
        // Not logged in
        <Routes>
          <Route path="/login" element={<LoginPage onLogin={handleLogin} isLoading={loading} />} />
          <Route path="*" element={<LoginPage onLogin={handleLogin} isLoading={loading} />} />
        </Routes>
      )}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import Card from '../components/Card';
import Button from '../components/Button';
import Avatar from '../components/Avatar';
import UserFormModal from '../components/UserFormModal';
import UserDeleteConfirmationModal from '../components/UserDeleteConfirmationModal';
import { EditIcon, TrashIcon, UserPlusIcon, ChevronDownIcon } from '../components/Icons';
import { User, UserTableData, UserRoleEnum } from '../types';
import { REFERENCE_DATE } from '../constants';

interface UserManagementProps {
  users: User[];
  onAddUser: (newUser: User) => Promise<void>;
  onUpdateUser: (updatedUser: User) => Promise<void>;
  onDeleteUser: (userId: string) => Promise<void>;
  isLoading: boolean; // Add isLoading prop
}

const UserManagement: React.FC<UserManagementProps> = ({ users, onAddUser, onUpdateUser, onDeleteUser, isLoading }) => {
  const [showUserFormModal, setShowUserFormModal] = useState(false);
  const [userToEdit, setUserToEdit] = useState<User | null>(null);
  const [showDeleteConfirmationModal, setShowDeleteConfirmationModal] = useState(false);
  const [userToDeleteId, setUserToDeleteId] = useState<string | null>(null);

  // State to manage expanded/collapsed sections for each role
  const [expandedRoles, setExpandedRoles] = useState<Record<UserRoleEnum, boolean>>({
    [UserRoleEnum.ADMIN]: true, // Admins expanded by default
    [UserRoleEnum.MITARBEITER]: false,
    [UserRoleEnum.KUNDE]: false,
  });

  const toggleRoleSection = (role: UserRoleEnum) => {
    setExpandedRoles(prev => ({
      ...prev,
      [role]: !prev[role],
    }));
  };

  const handleOpenAddUserModal = () => {
    setUserToEdit(null);
    setShowUserFormModal(true);
  };

  const handleOpenEditUserModal = (user: User) => {
    setUserToEdit(user);
    setShowUserFormModal(true);
  };

  const handleCloseUserFormModal = () => {
    setShowUserFormModal(false);
    setUserToEdit(null);
  };

  const handleSubmitUserForm = async (userData: { firstName: string; lastName: string; email: string; role: UserRoleEnum; password?: string }) => {
    const initials = `${userData.firstName.charAt(0)}${userData.lastName.charAt(0)}`.toUpperCase().slice(0, 2);
    const avatarColors = ['bg-red-500', 'bg-orange-500', 'bg-purple-500', 'bg-indigo-500', 'bg-blue-500', 'bg-green-500', 'bg-teal-500', 'bg-fuchsia-500', 'bg-lime-500'];
    const randomColor = avatarColors[Math.floor(Math.random() * avatarColors.length)];

    if (userToEdit) {
      const updatedUser: User = {
        ...userToEdit,
        firstName: userData.firstName,
        lastName: userData.lastName,
        email: userData.email,
        role: userData.role,
        avatarInitials: initials, // Update initials on edit
        avatarColor: userToEdit.avatarColor || randomColor, // Keep existing color or assign random
        ...(userData.password ? { password: userData.password } : {}),
      };
      await onUpdateUser(updatedUser);
    } else {
      let newUser: User = {
        id: crypto.randomUUID ? crypto.randomUUID() : `user-${Date.now()}`, // Generate a unique ID
        avatarInitials: initials,
        avatarColor: randomColor,
        firstName: userData.firstName,
        lastName: userData.lastName,
        email: userData.email,
        role: userData.role,
        password: userData.password,
        createdAt: new Date().toISOString(), // Use ISO string for consistency
      };

      // If the new user is a 'Kunde', generate and associate a customer ID here
      if (userData.role === UserRoleEnum.KUNDE) {
        // We generate a new customer ID. App.tsx's handleAddUser will handle customer creation.
        const associatedCustomerId = `cust-${crypto.randomUUID ? crypto.randomUUID() : Date.now()}`; 
        newUser = { ...newUser, associatedCustomerId: associatedCustomerId };
      }

      await onAddUser(newUser);
    }
    handleCloseUserFormModal();
  };

  const handleOpenDeleteConfirmation = (userId: string) => {
    setUserToDeleteId(userId);
    setShowDeleteConfirmationModal(true);
  };

  const handleConfirmDelete = async () => {
    if (userToDeleteId) {
      await onDeleteUser(userToDeleteId);
    }
    setShowDeleteConfirmationModal(false);
    setUserToDeleteId(null);
  };

  const handleCloseDeleteConfirmation = () => {
    setShowDeleteConfirmationModal(false);
    setUserToDeleteId(null);
  };

  const getRoleColorClass = (role: UserRoleEnum) => {
    switch (role) {
      case UserRoleEnum.ADMIN:
        return 'bg-red-100 text-red-800';
      case UserRoleEnum.MITARBEITER:
        return 'bg-blue-100 text-blue-800';
      case UserRoleEnum.KUNDE:
        return 'bg-teal-100 text-teal-800';
      default:
        return 'bg-gray-100 text-gray-800';
    }
  };

  if (isLoading) {
    return (
      <div className="p-8 text-center text-gray-600">
        Lade Benutzerdaten...
      </div>
    );
  }

  // Filter users by role
  const adminUsers = users.filter(user => user.role === UserRoleEnum.ADMIN);
  const mitarbeiterUsers = users.filter(user => user.role === UserRoleEnum.MITARBEITER);
  const kundeUsers = users.filter(user => user.role === UserRoleEnum.KUNDE);

  // Reusable component for displaying a list of users for a specific role
  interface UserRoleSectionProps {
    title: string;
    role: UserRoleEnum;
    users: User[];
    isExpanded: boolean;
    onToggle: (role: UserRoleEnum) => void;
    onOpenEditUserModal: (user: User) => void;
    onOpenDeleteConfirmation: (userId: string) => void;
  }

  const UserRoleSection: React.FC<UserRoleSectionProps> = ({
    title,
    role,
    users,
    isExpanded,
    onToggle,
    onOpenEditUserModal,
    onOpenDeleteConfirmation,
  }) => {
    const displayUsers = users.slice(0, 5); // Show first 5 users
    const hasMoreUsers = users.length > 5;

    return (
      <Card padding="none" className="overflow-hidden">
        <button
          className="flex items-center justify-between w-full p-4 bg-gray-50 hover:bg-gray-100 transition-colors duration-200"
          onClick={() => onToggle(role)}
          aria-expanded={isExpanded}
          aria-controls={`user-list-${role}`}
        >
          <h2 className="text-xl font-semibold text-gray-900 flex items-center">
            {title}
            <span className={`ml-3 px-2.5 py-0.5 rounded-full text-xs font-medium ${getRoleColorClass(role)}`}>
              {users.length}
            </span>
          </h2>
          <ChevronDownIcon className={`h-6 w-6 text-gray-500 transition-transform duration-200 ${isExpanded ? 'rotate-180' : ''}`} />
        </button>

        {isExpanded && (
          <div id={`user-list-${role}`} className={`p-4 border-t border-gray-200 ${hasMoreUsers ? 'max-h-96 overflow-y-auto custom-scrollbar' : ''}`}>
            {users.length === 0 ? (
              <p className="text-gray-500 text-sm py-4 text-center">Keine Benutzer in dieser Rolle gefunden.</p>
            ) : (
              <div className="divide-y divide-gray-200">
                {users.map(user => (
                  <div key={user.id} className="flex items-center justify-between py-3">
                    <div className="flex items-center">
                      <Avatar initials={user.avatarInitials} color={user.avatarColor} size="md" className="mr-3" />
                      <div>
                        <p className="font-medium text-gray-900">{user.firstName} {user.lastName}</p>
                        <p className="text-sm text-gray-500">{user.email}</p>
                      </div>
                    </div>
                    <div className="flex items-center space-x-3">
                      <button
                        onClick={(e) => { e.stopPropagation(); onOpenEditUserModal(user); }}
                        className="text-gray-500 hover:text-blue-600"
                        aria-label={`Benutzer ${user.firstName} ${user.lastName} bearbeiten`}
                      >
                        <EditIcon className="h-5 w-5" />
                      </button>
                      <button
                        onClick={(e) => { e.stopPropagation(); onOpenDeleteConfirmation(user.id); }}
                        className="text-gray-500 hover:text-red-600"
                        aria-label={`Benutzer ${user.firstName} ${user.lastName} löschen`}
                      >
                        <TrashIcon className="h-5 w-5" />
                      </button>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        )}
      </Card>
    );
  };


  const userToDelete = users.find(u => u.id === userToDeleteId);

  return (
    <div className="p-6 md:p-8 lg:p-10">
      <div className="flex justify-between items-center mb-2">
        <div>
          <h1 className="text-3xl font-bold text-gray-900">Benutzerverwaltung</h1>
          <p className="text-gray-600">Verwalten Sie alle Systembenutzer an einem Ort</p>
        </div>
        <Button variant="success" icon={UserPlusIcon} onClick={handleOpenAddUserModal}>
          Neuer Benutzer
        </Button>
      </div>

      <div className="mt-8 space-y-6">
        <UserRoleSection
          title="Administratoren"
          role={UserRoleEnum.ADMIN}
          users={adminUsers}
          isExpanded={expandedRoles[UserRoleEnum.ADMIN]}
          onToggle={toggleRoleSection}
          onOpenEditUserModal={handleOpenEditUserModal}
          onOpenDeleteConfirmation={handleOpenDeleteConfirmation}
        />
        <UserRoleSection
          title="Mitarbeiter"
          role={UserRoleEnum.MITARBEITER}
          users={mitarbeiterUsers}
          isExpanded={expandedRoles[UserRoleEnum.MITARBEITER]}
          onToggle={toggleRoleSection}
          onOpenEditUserModal={handleOpenEditUserModal}
          onOpenDeleteConfirmation={handleOpenDeleteConfirmation}
        />
        <UserRoleSection
          title="Kunden"
          role={UserRoleEnum.KUNDE}
          users={kundeUsers}
          isExpanded={expandedRoles[UserRoleEnum.KUNDE]}
          onToggle={toggleRoleSection}
          onOpenEditUserModal={handleOpenEditUserModal}
          onOpenDeleteConfirmation={handleOpenDeleteConfirmation}
        />
      </div>


      <UserFormModal
        isOpen={showUserFormModal}
        onClose={handleCloseUserFormModal}
        onSubmit={handleSubmitUserForm}
        userToEdit={userToEdit}
      />

      <UserDeleteConfirmationModal
        isOpen={showDeleteConfirmationModal}
        onClose={handleCloseDeleteConfirmation}
        onConfirm={handleConfirmDelete}
        userNameToDelete={userToDelete ? `${userToDelete.firstName} ${userToDelete.lastName}`.trim() : ''}
      />
    </div>
  );
};

export default UserManagement;

import React, { useState, useEffect } from 'react';
import Modal from './Modal';
import Button from './Button';
import Input from './Input';
import Select from './Select';
import { User, UserRoleEnum } from '../types';

interface UserFormModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSubmit: (userData: { firstName: string; lastName: string; email: string; role: UserRoleEnum; password?: string }) => Promise<void>;
  userToEdit: User | null;
  forceRole?: UserRoleEnum; // New prop: if provided, role selection is locked
}

const UserFormModal: React.FC<UserFormModalProps> = ({ isOpen, onClose, onSubmit, userToEdit, forceRole }) => {
  const [firstName, setFirstName] = useState('');
  const [lastName, setLastName] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState(''); // New state for password
  const [role, setRole] = useState<UserRoleEnum>(forceRole || UserRoleEnum.MITARBEITER); // Use forceRole if provided
  const [firstNameError, setFirstNameError] = useState('');
  const [lastNameError, setLastNameError] = useState('');
  const [emailError, setEmailError] = useState('');
  const [passwordError, setPasswordError] = useState(''); // New state for password error

  useEffect(() => {
    if (userToEdit) {
      setFirstName(userToEdit.firstName);
      setLastName(userToEdit.lastName);
      setEmail(userToEdit.email);
      setRole(userToEdit.role);
      setPassword(''); // Clear password field when editing for security, user can set new one
    } else {
      // Reset form for new user
      setFirstName('');
      setLastName('');
      setEmail('');
      setPassword(''); // Clear password field for new user
      setRole(forceRole || UserRoleEnum.MITARBEITER); // Reset role with forceRole or default
    }
    setFirstNameError('');
    setLastNameError('');
    setEmailError('');
    setPasswordError(''); // Clear password error
  }, [userToEdit, isOpen, forceRole]); // Reset when modal opens, userToEdit changes, or forceRole changes

  const validateForm = () => {
    let isValid = true;
    if (!firstName.trim()) {
      setFirstNameError('Vorname ist erforderlich.');
      isValid = false;
    } else {
      setFirstNameError('');
    }

    if (!lastName.trim()) {
      setLastNameError('Nachname ist erforderlich.');
      isValid = false;
    } else {
      setLastNameError('');
    }

    if (!email.trim()) {
      setEmailError('E-Mail ist erforderlich.');
      isValid = false;
    } else if (!/\S+@\S+\.\S+/.test(email)) { // Basic email format validation
      setEmailError('Ungültiges E-Mail-Format.');
      isValid = false;
    } else {
      setEmailError('');
    }

    if (!userToEdit && !password.trim()) { // Password is required only for new users
      setPasswordError('Passwort ist erforderlich.');
      isValid = false;
    } else if (password.trim() && password.length < 6) { // If password is provided (new or editing), validate length
      setPasswordError('Passwort muss mindestens 6 Zeichen lang sein.');
      isValid = false;
    }
    else {
      setPasswordError('');
    }

    return isValid;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (validateForm()) {
      await onSubmit({ firstName, lastName, email, role, password: password.trim() || undefined }); // Pass password if not empty
    }
  };

  const title = userToEdit ? 'Benutzer bearbeiten' : 'Neuen Benutzer erstellen';

  const roleOptions = [
    { value: UserRoleEnum.ADMIN, label: 'Admin' },
    { value: UserRoleEnum.MITARBEITER, label: 'Mitarbeiter' },
    { value: UserRoleEnum.KUNDE, label: 'Kunde' }, // Added Kunde role
  ];

  return (
    <Modal isOpen={isOpen} onClose={onClose} title={title} className="max-w-md">
      <form onSubmit={handleSubmit} className="p-0">
        <div className="space-y-4">
          <Input
            id="userFirstName"
            label="Vorname"
            type="text"
            value={firstName}
            onChange={(e) => setFirstName(e.target.value)}
            placeholder="Max"
            error={firstNameError}
          />
          <Input
            id="userLastName"
            label="Nachname"
            type="text"
            value={lastName}
            onChange={(e) => setLastName(e.target.value)}
            placeholder="Mustermann"
            error={lastNameError}
          />
          <Input
            id="userEmail"
            label="E-Mail"
            type="email"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            placeholder="max.mustermann@example.com"
            error={emailError}
          />
          <Input // New password input field
            id="userPassword"
            label={userToEdit ? "Neues Passwort (optional)" : "Passwort"}
            type="password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            placeholder={userToEdit ? "Passwort ändern" : "Passwort festlegen"}
            error={passwordError}
          />
          <Select
            id="userRole"
            label="Rolle"
            options={roleOptions}
            value={role}
            onChange={(e) => setRole(e.target.value as UserRoleEnum)}
            disabled={!!forceRole} // Disable if forceRole is provided
          />
        </div>
        <div className="p-4 border-t border-gray-200 mt-6 flex justify-end space-x-3">
          <Button variant="outline" onClick={onClose} type="button">
            Abbrechen
          </Button>
          <Button variant="success" type="submit">
            Speichern
          </Button>
        </div>
      </form>
    </Modal>
  );
};

