            error={emailError}
            disabled={isAuthenticating || isLoading}
          />
          <Input
            id="loginPassword"
            label="Passwort"
            type="password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            placeholder="********"
            error={passwordError}
            disabled={isAuthenticating || isLoading}
          />

          {loginError && (
            <div className="text-red-600 text-sm text-center -mt-4">
              {loginError}
