          firstName: newUser.firstName,
          lastName: newUser.lastName,
          role: newUser.role,
        },
      },
    });

    if (authError) {
      console.error('Error creating auth user:', authError);
      alert(`Fehler beim Erstellen des Benutzers: ${authError.message}`);
      setLoading(false);
      return;
    }

    if (!authData.user) {
      alert('Benutzererstellung fehlgeschlagen: Kein Benutzerobjekt erhalten.');
      setLoading(false);
