import React, { useState, useEffect, useCallback } from 'react';
import { Routes, Route, useNavigate, Navigate } from 'react-router-dom';
import { createClient } from '@supabase/supabase-js';
import Sidebar from './components/Sidebar';
import Dashboard from './pages/Dashboard';
import CustomerManagement from './pages/CustomerManagement';
import CustomerDetails from './pages/CustomerDetails';
import Reports from './pages/Reports';
import UserManagement from './pages/UserManagement'; // Import the new UserManagement page
import LoginPage from './pages/LoginPage'; // Import the new LoginPage
import { Customer, Transaction, TrainingLevelEnum, User, UserRoleEnum, Database, TrainingSection } from './types'; // Import types
import { REFERENCE_DATE } from './constants'; // Import constants needed for initial state
import { parseDateString } from './utils'; // Import parseDateString

// Supabase Client Initialization
const SUPABASE_PLACEHOLDER_URL = "YOUR_SUPABASE_URL";
const SUPABASE_PLACEHOLDER_ANON_KEY = "YOUR_SUPABASE_ANON_KEY";

const rawSupabaseUrl = (window as any).SUPABASE_URL || (import.meta as any).env.VITE_SUPABASE_URL;
const rawSupabaseAnonKey = (window as any).SUPABASE_ANON_KEY || (import.meta as any).env.VITE_SUPABASE_ANON_KEY;

let supabase: ReturnType<typeof createClient<Database>> | null = null;
let supabaseConfigMissing = false;

// Log raw values for debugging
console.log("Supabase Init: rawSupabaseUrl =", rawSupabaseUrl);
console.log("Supabase Init: rawSupabaseAnonKey =", rawSupabaseAnonKey);

if (rawSupabaseUrl === SUPABASE_PLACEHOLDER_URL || rawSupabaseAnonKey === SUPABASE_PLACEHOLDER_ANON_KEY || !rawSupabaseUrl || !rawSupabaseAnonKey) {
  console.error("Supabase configuration missing or placeholder values detected. Please update index.html with your actual Supabase URL and Anon Key.");
  supabaseConfigMissing = true;
} else {
  try {
    supabase = createClient<Database>(rawSupabaseUrl, rawSupabaseAnonKey);
    console.log("Supabase client initialized successfully.");
  } catch (e) {
    console.error("Failed to initialize Supabase client:", e);
    supabaseConfigMissing = true;
  }
}

const App: React.FC = () => {
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [users, setUsers] = useState<User[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true); // Initial loading state for app data
  const [showConfigError, setShowConfigError] = useState(supabaseConfigMissing); // Use the global flag for rendering
  const navigate = useNavigate();

  // If config is missing from the start, display error immediately
  useEffect(() => {
    if (showConfigError) {
      setLoading(false); // Stop loading animation
    }
  }, [showConfigError]);

  const fetchUsers = useCallback(async () => {
    if (!supabase) { console.error("Supabase client not initialized. Cannot fetch users."); setLoading(false); return; }
    console.log("Fetching users...");
    const { data: profilesData, error: profilesError } = await supabase
      .from('profiles')
      .select('*');

    if (profilesError) {
      console.error('Error fetching users:', profilesError);
      // Specific check for RLS
      if (profilesError.message?.includes('permission denied') || profilesError.code === '42501') {
        console.warn("Possible RLS issue: User might not have permission to read 'profiles' table.");
      }
      const errorMessageForUser = profilesError.message || 'Unbekannter Fehler beim Laden der Benutzerprofile.';
      alert(`Fehler beim Laden der Benutzer: ${errorMessageForUser}`);
      setUsers([]);
      return false; // Indicate failure
    }

    const fetchedUsers: User[] = profilesData.map(profile => ({
      id: profile.id,
      avatarInitials: profile.avatarInitials,
      avatarColor: profile.avatarColor,
      firstName: profile.firstName,
      lastName: profile.lastName,
      email: profile.email,
      role: profile.role as UserRoleEnum, // Cast to enum
      createdAt: profile.createdAt,
      associatedCustomerId: profile.associatedCustomerId,
    }));
    setUsers(fetchedUsers);
    console.log("Users fetched successfully:", fetchedUsers.length);
    return true; // Indicate success
  }, []);

  const fetchCustomers = useCallback(async () => {
    if (!supabase) { console.error("Supabase client not initialized. Cannot fetch customers."); setLoading(false); return; }
    console.log("Fetching customers...");
    const { data: customersData, error: customersError } = await supabase
      .from('customers')
      .select(`
        *,
        documents(*),
        training_sections(*)
      `);

    if (customersError) {
      console.error('Error fetching customers:', customersError);
      if (customersError.message?.includes('permission denied') || customersError.code === '42501') {
        console.warn("Possible RLS issue: User might not have permission to read 'customers' or related tables.");
      }
      const errorMessageForUser = customersError.message || 'Unbekannter Fehler beim Laden der Kundendaten.';
      alert(`Fehler beim Laden der Kunden: ${errorMessageForUser}`);
      setCustomers([]);
      return false; // Indicate failure
    }

    const fetchedCustomers: Customer[] = customersData.map(customer => {
      const sortedTrainingProgress = customer.training_sections
        ? [...customer.training_sections]
            .sort((a, b) => a.id - b.id)
            .map(section => ({
              ...section,
              status: section.status as TrainingSection['status'],
            }))
        : [];

      return {
        id: customer.id,
        avatarInitials: customer.avatarInitials,
        avatarColor: customer.avatarColor,
        firstName: customer.firstName,
        lastName: customer.lastName,
        email: customer.email,
        phone: customer.phone || '',
        dogName: customer.dogName,
        chipNumber: customer.chipNumber,
        balance: customer.balance,
        totalTransactions: customer.totalTransactions,
        level: customer.level as TrainingLevelEnum, // Cast to enum
        createdAt: customer.createdAt,
        createdBy: customer.createdBy,
        qrCodeData: customer.qrCodeData,
        documents: customer.documents || [],
        trainingProgress: sortedTrainingProgress,
      };
    });
    setCustomers(fetchedCustomers);
    console.log("Customers fetched successfully:", fetchedCustomers.length);
    return true; // Indicate success
  }, []);

  const fetchTransactions = useCallback(async () => {
    if (!supabase) { console.error("Supabase client not initialized. Cannot fetch transactions."); setLoading(false); return; }
    console.log("Fetching transactions...");
    const { data: transactionsData, error: transactionsError } = await supabase
      .from('transactions')
      .select('*');

    if (transactionsError) {
      console.error('Error fetching transactions:', transactionsError);
      if (transactionsError.message?.includes('permission denied') || transactionsError.code === '42501') {
        console.warn("Possible RLS issue: User might not have permission to read 'transactions' table.");
      }
      const errorMessageForUser = transactionsError.message || 'Unbekannter Fehler beim Laden der Transaktionsdaten.';
      alert(`Fehler beim Laden der Transaktionen: ${errorMessageForUser}`);
      setTransactions([]);
      return false; // Indicate failure
    }

    const fetchedTransactions: Transaction[] = transactionsData.map(t => ({
      id: t.id,
      customerId: t.customerId,
      type: t.type as 'recharge' | 'debit',
      description: t.description || '',
      amount: t.amount,
      date: t.date,
      employee: t.employee,
    }));
    setTransactions(fetchedTransactions);
    console.log("Transactions fetched successfully:", fetchedTransactions.length);
    return true; // Indicate success
  }, []);

  const fetchAllData = useCallback(async () => {
    if (!supabase) { console.error("Supabase client not initialized. Cannot fetch all data."); setLoading(false); return; }
    console.log("Attempting to fetch all app data...");
    setLoading(true);
    try {
      // Execute all fetches in parallel
      const [usersSuccess, customersSuccess, transactionsSuccess] = await Promise.all([
        fetchUsers(),
        fetchCustomers(),
        fetchTransactions(),
      ]);

      if (!usersSuccess || !customersSuccess || !transactionsSuccess) {
        console.error("One or more data fetches failed.");
        // Specific alert could be added here if needed for aggregated failure
      }
    } catch (e) {
      console.error("Error during fetchAllData:", e);
      alert(`Ein unerwarteter Fehler beim Laden der Daten ist aufgetreten: ${e instanceof Error ? e.message : String(e)}`);
    } finally {
      setLoading(false); // Ensure loading is always set to false
      console.log("Finished fetchAllData attempt.");
    }
  }, [fetchUsers, fetchCustomers, fetchTransactions]);

  // Auth State Change Listener
  useEffect(() => {
    if (!supabase || showConfigError) {
      console.log("Skipping AuthStateChange listener setup due to missing config or supabase client.");
      return;
    }
    console.log("Setting up AuthStateChange listener...");
    const { data: authListener } = supabase.auth.onAuthStateChange(
      async (event, session) => {
        console.log("Auth event:", event, "Session:", session);
        if (session) {
          setIsLoggedIn(true);
          // Fetch the user's profile from the 'profiles' table
          const { data: profile, error: profileError } = await supabase!
            .from('profiles')
            .select('*')
            .eq('id', session.user.id)
            .single();

          if (profileError) {
            console.error('Error fetching user profile after login:', profileError);
            if (profileError.message?.includes('permission denied') || profileError.code === '42501') {
              console.warn("Possible RLS issue: Authenticated user might not have permission to read their own 'profiles' entry.");
            }
            const errorMessageForUser = profileError.message || 'Unbekannter Fehler beim Laden des Benutzerprofils. Bitte überprüfen Sie die Konsolenausgabe für weitere Details.';
            alert(`Fehler beim Laden des Benutzerprofils: ${errorMessageForUser}`);
            setCurrentUser(null);
            setIsLoggedIn(false); // Log out if profile can't be fetched
            navigate('/login', { replace: true });
            return;
          }

          const userProfile: User = {
            id: profile.id,
            avatarInitials: profile.avatarInitials,
            avatarColor: profile.avatarColor,
            firstName: profile.firstName,
            lastName: profile.lastName,
            email: profile.email,
            role: profile.role as UserRoleEnum,
            createdAt: profile.createdAt,
            associatedCustomerId: profile.associatedCustomerId,
          };
          setCurrentUser(userProfile);
          console.log("Current user set:", userProfile);
          await fetchAllData(); // Fetch all app data after user is logged in

          // Redirection logic based on role
          if (userProfile.role === UserRoleEnum.KUNDE && userProfile.associatedCustomerId) {
            const expectedPath = `/customers/${userProfile.associatedCustomerId}`;
            if (!window.location.hash.startsWith(`#${expectedPath}`)) {
              console.log("Redirecting Kunde to own customer page:", expectedPath);
              navigate(expectedPath, { replace: true });
            }
          } else if (window.location.hash === '#/login') {
            console.log("Redirecting non-Kunde from login to dashboard.");
            navigate('/', { replace: true });
          }
        } else {
          console.log("No session found or user logged out. Resetting state.");
          setIsLoggedIn(false);
          setCurrentUser(null);
          setCustomers([]);
          setUsers([]);
          setTransactions([]);
          navigate('/login', { replace: true });
        }
      }
    );

    return () => {
      console.log("Cleaning up AuthStateChange listener.");
      authListener.subscription.unsubscribe();
    };
  }, [navigate, fetchAllData, showConfigError]);


  // Initial data fetch if already logged in (on page refresh)
  useEffect(() => {
    const checkSession = async () => {
      if (!supabase || showConfigError) {
        console.log("Skipping initial session check due to missing config or supabase client.");
        setLoading(false);
        return;
      }
      console.log("Performing initial session check...");
      setLoading(true);
      const { data: { session }, error } = await supabase.auth.getSession();
      if (session) {
        console.log("Initial session found:", session.user?.email);
        // AuthStateChange listener will handle setting user and fetching data
      } else if (error) {
        console.error("Error getting initial session:", error);
        const errorMessageForUser = error.message || 'Unbekannter Fehler beim Abrufen der Sitzung.';
        alert(`Fehler beim Abrufen der Sitzung: ${errorMessageForUser}`);
        setIsLoggedIn(false);
        setCurrentUser(null);
        navigate('/login', { replace: true });
      } else {
        console.log("No initial session found.");
        setIsLoggedIn(false);
        setCurrentUser(null);
        navigate('/login', { replace: true });
      }
      // setLoading(false) is handled by onAuthStateChange callback for success
      // and explicit error paths for failure, or in the very end if no session.
      if (!session && !error) { // If no session and no explicit error, ensure loading is off.
        setLoading(false);
      }
    };
    checkSession();
  }, [navigate, showConfigError]);

  // Temporary RLS Debugging: Try to fetch a user profile as anon
  useEffect(() => {
    if (!supabase || showConfigError) return;
    async function checkRLS() {
      console.log("RLS Check: Attempting to fetch a single profile as anonymous user (for debugging RLS)...");
      const { data, error } = await supabase.from('profiles').select('id, email, role').limit(1);
      if (error) {
        console.error("RLS Check Error (Anon user profile read):", error);
        if (error.message?.includes('permission denied') || error.code === '42501') {
          console.warn("RLS Check Warning: Anonymous users likely don't have SELECT permission on the 'profiles' table. This is common, but ensure authenticated users can read their *own* profile.");
        }
      } else {
        console.log("RLS Check Success (Anon user profile read):", data);
        if (data.length === 0) {
          console.warn("RLS Check: 'profiles' table is accessible to anon, but returned no rows. Make sure there's data.");
        }
      }
    }
    checkRLS();
  }, [supabase, showConfigError]);


  const handleLogin = async (email: string, passwordInput: string): Promise<boolean> => {
    if (!supabase) { console.error("Supabase client not initialized. Cannot log in."); return false; }
    console.log("Attempting login for:", email);
    const { data, error } = await supabase.auth.signInWithPassword({
      email,
      password: passwordInput,
    });

    if (error) {
      console.error('Login error:', error);
      const errorMessageForUser = error.message || 'Unbekannter Fehler bei der Anmeldung.';
      alert(`Anmeldung fehlgeschlagen: ${errorMessageForUser}`);
      return false;
    }

    if (data.user) {
      console.log("Login successful for user:", data.user.email);
      // onAuthStateChange will handle setting isLoggedIn, currentUser, and redirection
      return true;
    }
    return false;
  };

  const handleLogout = async () => {
    if (!supabase) { console.error("Supabase client not initialized. Cannot log out."); return; }
    console.log("Attempting logout.");
    const { error } = await supabase.auth.signOut();
    if (error) {
      console.error('Logout error:', error);
      const errorMessageForUser = error.message || 'Unbekannter Fehler beim Abmelden.';
      alert(`Abmeldung fehlgeschlagen: ${errorMessageForUser}`);
    } else {
      console.log("Logout successful.");
      // onAuthStateChange will handle state reset and redirection
      alert('Sie wurden erfolgreich abgemeldet.');
    }
  };

  const handleUpdateCustomer = useCallback(async (updatedCustomer: Customer) => {
    if (!supabase) { console.error("Supabase client not initialized. Cannot update customer."); return; }
    setLoading(true);
    console.log("Updating customer:", updatedCustomer.id);
    const { error: customerError } = await supabase
      .from('customers')
      .update({
        "firstName": updatedCustomer.firstName,
        "lastName": updatedCustomer.lastName,
        email: updatedCustomer.email,
        phone: updatedCustomer.phone,
        "dogName": updatedCustomer.dogName,
        "chipNumber": updatedCustomer.chipNumber,
        balance: updatedCustomer.balance,
        "totalTransactions": updatedCustomer.totalTransactions,
        level: updatedCustomer.level,
        "avatarInitials": updatedCustomer.avatarInitials,
        "avatarColor": updatedCustomer.avatarColor,
        "qrCodeData": updatedCustomer.qrCodeData,
      })
      .eq('id', updatedCustomer.id);

    if (customerError) {
      console.error('Error updating customer:', customerError);
      const errorMessageForUser = customerError.message || 'Unbekannter Fehler beim Aktualisieren der Kundendaten.';
      alert(`Fehler beim Aktualisieren des Kunden: ${errorMessageForUser}`);
      setLoading(false);
      return;
    }

    // Update training progress (delete existing and insert new ones)
    const { error: deleteTpError } = await supabase
      .from('training_sections')
      .delete()
      .eq('customerId', updatedCustomer.id);

    if (deleteTpError) {
      console.error('Error deleting old training progress:', deleteTpError);
      const errorMessageForUser = deleteTpError.message || 'Unbekannter Fehler beim Löschen des Trainingsfortschritts.';
      alert(`Fehler beim Aktualisieren des Trainingsfortschritts (Löschen): ${errorMessageForUser}`);
      setLoading(false);
      return;
    }

    const trainingProgressInserts = updatedCustomer.trainingProgress.map(section => ({
      ...section,
      customerId: updatedCustomer.id, // Ensure customerId is set for each section
    }));

    const { error: insertTpError } = await supabase
      .from('training_sections')
      .insert(trainingProgressInserts);

    if (insertTpError) {
      console.error('Error inserting new training progress:', insertTpError);
      const errorMessageForUser = insertTpError.message || 'Unbekannter Fehler beim Einfügen des neuen Trainingsfortschritts.';
      alert(`Fehler beim Aktualisieren des Trainingsfortschritts (Einfügen): ${errorMessageForUser}`);
      setLoading(false);
      return;
    }

    await fetchCustomers(); // Re-fetch customers to get the updated data
    setLoading(false);
    console.log("Customer updated successfully:", updatedCustomer.id);
  }, [fetchCustomers]);

  const handleAddTransaction = useCallback(async (newTransaction: Transaction, updatedCustomer: Customer) => {
    if (!supabase) { console.error("Supabase client not initialized. Cannot add transaction."); return; }
    setLoading(true);
    console.log("Adding new transaction:", newTransaction);
    const { error: transactionError } = await supabase
      .from('transactions')
      .insert({
        id: newTransaction.id,
        "customerId": newTransaction.customerId,
        type: newTransaction.type,
        description: newTransaction.description,
        amount: newTransaction.amount,
        date: newTransaction.date,
        employee: newTransaction.employee,
      });

    if (transactionError) {
      console.error('Error adding transaction:', transactionError);
      const errorMessageForUser = transactionError.message || 'Unbekannter Fehler beim Hinzufügen der Transaktion.';
      alert(`Fehler beim Hinzufügen der Transaktion: ${errorMessageForUser}`);
      setLoading(false);
      return;
    }

    // After adding transaction, also update customer's balance and totalTransactions in DB
    await handleUpdateCustomer(updatedCustomer); // Reuses the update logic

    await fetchTransactions(); // Re-fetch transactions
    setLoading(false);
    console.log("Transaction added successfully:", newTransaction.id);
  }, [handleUpdateCustomer, fetchTransactions]);


  const handleAddUser = useCallback(async (newUser: User) => {
    if (!supabase) { console.error("Supabase client not initialized. Cannot add user."); return; }
    setLoading(true);
    console.log("Attempting to add new user:", newUser.email, "with role:", newUser.role);
    // 1. Create user in Supabase Auth
    const { data: authData, error: authError } = await supabase.auth.signUp({
      email: newUser.email,
      password: newUser.password!, // Password is required for signup
      options: {
        data: {
          firstName: newUser.firstName,
          lastName: newUser.lastName,
          role: newUser.role,
        },
      },
    });

    if (authError) {
      console.error('Error creating auth user:', authError);
      const errorMessageForUser = authError.message || 'Unbekannter Fehler beim Erstellen des Auth-Benutzers.';
      alert(`Fehler beim Erstellen des Benutzers: ${errorMessageForUser}`);
      setLoading(false);
      return;
    }

    if (!authData.user) {
      alert('Benutzererstellung fehlgeschlagen: Kein Benutzerobjekt erhalten.');
      setLoading(false);
      return;
    }
    console.log("Auth user created:", authData.user.id);

    // 2. Create profile entry in 'profiles' table
    const { error: profileError } = await supabase
      .from('profiles')
      .insert({
        id: authData.user.id,
        "firstName": newUser.firstName,
        "lastName": newUser.lastName,
        email: newUser.email,
        role: newUser.role,
        "avatarInitials": newUser.avatarInitials,
        "avatarColor": newUser.avatarColor,
        "createdAt": new Date().toISOString(), // Use ISO string for DB
        "associatedCustomerId": newUser.associatedCustomerId || null,
      });

    if (profileError) {
      console.error('Error creating profile:', profileError);
      const errorMessageForUser = profileError.message || 'Unbekannter Fehler beim Erstellen des Profils.';
      alert(`Fehler beim Erstellen des Profils: ${errorMessageForUser}`);
      // Consider deleting auth user here if profile creation fails
      setLoading(false);
      return;
    }
    console.log("Profile created for user:", authData.user.id);

    // 3. If 'Kunde' role, create customer entry in 'customers' table
    if (newUser.role === UserRoleEnum.KUNDE && newUser.associatedCustomerId) {
      console.log("Creating customer entry for new Kunde user:", newUser.associatedCustomerId);
      const { error: customerError } = await supabase
        .from('customers')
        .insert({
          id: newUser.associatedCustomerId,
          "firstName": newUser.firstName,
          "lastName": newUser.lastName,
          email: newUser.email,
          "phone": '', // Default
          "dogName": 'Unbekannt', // Default
          "chipNumber": '', // Default
          balance: 0.00,
          "totalTransactions": 0,
          level: TrainingLevelEnum.EINSTEIGER, // Default
          "createdAt": new Date().toISOString(), // Use ISO string for DB
          "createdBy": currentUser ? `${currentUser.firstName} ${currentUser.lastName}` : 'System',
          "qrCodeData": `https://api.qrserver.com/v1/create-qr-code/?size=150x150&data=https://example.com/customer/${newUser.associatedCustomerId}`,
          "avatarInitials": newUser.avatarInitials,
          "avatarColor": newUser.avatarColor,
        });

      if (customerError) {
        console.error('Error creating customer for new Kunde user:', customerError);
        const errorMessageForUser = customerError.message || 'Unbekannter Fehler beim Erstellen des Kundeneintrags.';
        alert(`Fehler beim Erstellen des Kundeneintrags: ${errorMessageForUser}`);
        setLoading(false);
        return;
      }

      // Also insert initial training progress
      const initialTrainingProgress = [
        { id: 1, name: TrainingLevelEnum.EINSTEIGER, requiredHours: 6, completedHours: 0, status: 'Aktuell' as TrainingSection['status'], customerId: newUser.associatedCustomerId },
        { id: 2, name: TrainingLevelEnum.GRUNDLAGEN, requiredHours: 12, completedHours: 0, status: 'Gesperrt' as TrainingSection['status'], customerId: newUser.associatedCustomerId },
        { id: 3, name: TrainingLevelEnum.FORTGESCHRITTENE, requiredHours: 12, completedHours: 0, status: 'Gesperrt' as TrainingSection['status'], customerId: newUser.associatedCustomerId },
        { id: 4, name: TrainingLevelEnum.MASTERCLASS, requiredHours: 12, completedHours: 0, status: 'Gesperrt' as TrainingSection['status'], customerId: newUser.associatedCustomerId },
        { id: 5, name: TrainingLevelEnum.EXPERT, requiredHours: 100, completedHours: 0, status: 'Gesperrt' as TrainingSection['status'], customerId: newUser.associatedCustomerId },
      ];

      const { error: tpError } = await supabase
        .from('training_sections')
        .insert(initialTrainingProgress);

      if (tpError) {
        console.error('Error creating initial training progress for new Kunde user:', tpError);
        const errorMessageForUser = tpError.message || 'Unbekannter Fehler beim Erstellen des initialen Trainingsfortschritts.';
        alert(`Fehler beim Erstellen des initialen Trainingsfortschritts: ${errorMessageForUser}`);
        setLoading(false);
        return;
      }
      console.log("Initial training progress created for customer:", newUser.associatedCustomerId);
    }

    alert('Benutzer erfolgreich erstellt!');
    await fetchAllData(); // Re-fetch all data to update lists
    setLoading(false);
    console.log("New user and associated data (if any) successfully created and data re-fetched.");
  }, [fetchAllData, currentUser]);

  const handleUpdateUser = useCallback(async (updatedUser: User) => {
    if (!supabase) { console.error("Supabase client not initialized. Cannot update user."); return; }
    setLoading(true);
    console.log("Updating user:", updatedUser.id, updatedUser.email);
    // Update profile
    const { error: profileError } = await supabase
      .from('profiles')
      .update({
        "firstName": updatedUser.firstName,
        "lastName": updatedUser.lastName,
        email: updatedUser.email,
        role: updatedUser.role,
        "avatarInitials": updatedUser.avatarInitials,
        "avatarColor": updatedUser.avatarColor,
        "associatedCustomerId": updatedUser.associatedCustomerId,
      })
      .eq('id', updatedUser.id);

    if (profileError) {
      console.error('Error updating profile:', profileError);
      const errorMessageForUser = profileError.message || 'Unbekannter Fehler beim Aktualisieren des Profils.';
      alert(`Fehler beim Aktualisieren des Profils: ${errorMessageForUser}`);
      setLoading(false);
      return;
    }

    // Update password if provided
    if (updatedUser.password) {
      console.log("Updating user password for:", updatedUser.email);
      const { error: passwordError } = await supabase.auth.updateUser({
        email: updatedUser.email, // Ensure email matches the user being updated
        password: updatedUser.password,
      });
      if (passwordError) {
        console.error('Error updating user password:', passwordError);
        const errorMessageForUser = passwordError.message || 'Unbekannter Fehler beim Aktualisieren des Passworts.';
        alert(`Fehler beim Aktualisieren des Passworts: ${errorMessageForUser}`);
        setLoading(false);
        return;
      }
    }

    // If the updated user is a 'Kunde' and has an associatedCustomerId,
    // also update the corresponding customer's details
    if (updatedUser.role === UserRoleEnum.KUNDE && updatedUser.associatedCustomerId) {
      console.log("Updating associated customer details for user:", updatedUser.id);
      const { error: customerError } = await supabase
        .from('customers')
        .update({
          "firstName": updatedUser.firstName,
          "lastName": updatedUser.lastName,
          email: updatedUser.email,
          "avatarInitials": updatedUser.avatarInitials,
          "avatarColor": updatedUser.avatarColor,
        })
        .eq('id', updatedUser.associatedCustomerId);

      if (customerError) {
        console.error('Error updating associated customer:', customerError);
        const errorMessageForUser = customerError.message || 'Unbekannter Fehler beim Aktualisieren des zugehörigen Kunden.';
        alert(`Fehler beim Aktualisieren des zugehörigen Kunden: ${errorMessageForUser}`);
        setLoading(false);
        return;
      }
    }

    alert('Benutzer erfolgreich aktualisiert!');
    await fetchAllData(); // Re-fetch all data to update lists
    setLoading(false);
    console.log("User updated successfully:", updatedUser.id);
  }, [fetchAllData]);

  const handleDeleteUser = useCallback(async (userId: string) => {
    if (!supabase) { console.error("Supabase client not initialized. Cannot delete user."); return; }
    setLoading(true);
    console.log("Attempting to delete user:", userId);
    // Find user to see if they have an associated customer
    const userToDelete = users.find(u => u.id === userId);

    // Delete user from Auth (this should cascade delete the profile due to FK setup)
    const { error: authError } = await supabase.auth.admin.deleteUser(userId);

    if (authError) {
      console.error('Error deleting auth user:', authError);
      const errorMessageForUser = authError.message || 'Unbekannter Fehler beim Löschen des Auth-Benutzers.';
      alert(`Fehler beim Löschen des Benutzers: ${errorMessageForUser}`);
      setLoading(false);
      return;
    }
    console.log("Auth user deleted:", userId);

    // If the deleted user was a 'Kunde' with an associatedCustomerId,
    // also delete the corresponding customer entry.
    // NOTE: If RLS is strict, this might need admin privileges or a function.
    // For now, assuming RLS allows admins/employees to delete customers.
    if (userToDelete && userToDelete.role === UserRoleEnum.KUNDE && userToDelete.associatedCustomerId) {
      console.log("Deleting associated customer:", userToDelete.associatedCustomerId);
      const { error: customerError } = await supabase
        .from('customers')
        .delete()
        .eq('id', userToDelete.associatedCustomerId);

      if (customerError) {
        console.error('Error deleting associated customer:', customerError);
        const errorMessageForUser = customerError.message || 'Unbekannter Fehler beim Löschen des zugehörigen Kunden.';
        alert(`Fehler beim Löschen des zugehörigen Kunden: ${errorMessageForUser}`);
        setLoading(false);
        return;
      }
    }

    alert('Benutzer erfolgreich gelöscht!');
    await fetchAllData(); // Re-fetch all data to update lists
    setLoading(false);
    console.log("User and associated data (if any) successfully deleted and data re-fetched.");
  }, [fetchAllData, users]);


  return (
    <div className="flex min-h-screen bg-gray-100">
      {showConfigError ? (
        <div className="flex flex-col items-center justify-center min-h-screen w-full p-4 text-center">
          <h1 className="text-3xl font-bold text-red-700 mb-4">Konfigurationsfehler</h1>
          <p className="text-lg text-gray-700 mb-6">
            Bitte aktualisieren Sie Ihre Supabase-Anmeldeinformationen.
          </p>
          <p className="text-md text-gray-600">
            Öffnen Sie die Datei <code className="bg-gray-200 p-1 rounded">index.html</code> und ersetzen Sie die Platzhalter
            <code className="bg-gray-200 p-1 rounded">YOUR_SUPABASE_URL</code> und <code className="bg-gray-200 p-1 rounded">YOUR_SUPABASE_ANON_KEY</code>
            durch Ihre tatsächlichen Supabase Projekt-URL und Anon Key.
          </p>
          <a
            href="https://supabase.com/dashboard/project/_/settings/api"
            target="_blank"
            rel="noopener noreferrer"
            className="mt-6 inline-flex items-center px-4 py-2 border border-transparent text-sm font-medium rounded-md shadow-sm text-white bg-blue-600 hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500"
          >
            Supabase API-Einstellungen öffnen
            <svg xmlns="http://www.w3.org/2000/svg" className="ml-2 -mr-1 h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="2"><path strokeLinecap="round" strokeLinejoin="round" d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0l-7 7"></path></svg>
          </a>
        </div>
      ) : (
        isLoggedIn && currentUser ? (
          <>
            <Sidebar appName="Mantrailing Card" currentUser={currentUser} onLogout={handleLogout} />
            <main className="flex-1 md:ml-64 p-0">
              <Routes>
                {currentUser.role === UserRoleEnum.ADMIN ? (
                  // Admin has full access
                  <>
                    <Route path="/" element={<Dashboard customers={customers} transactions={transactions} currentUser={currentUser} isLoading={loading} />} />
                    <Route path="/customers" element={<CustomerManagement customers={customers} transactions={transactions} currentUser={currentUser} onAddUser={handleAddUser} isLoading={loading} />} />
                    <Route
                      path="/customers/:id"
                      element={<CustomerDetails customers={customers} transactions={transactions} onUpdateCustomer={handleUpdateCustomer} onAddTransaction={handleAddTransaction} currentUser={currentUser} isLoading={loading} />}
                    />
                    <Route path="/reports" element={<Reports customers={customers} transactions={transactions} users={users} isLoading={loading} />} />
                    <Route path="/users" element={<UserManagement users={users} onAddUser={handleAddUser} onUpdateUser={handleUpdateUser} onDeleteUser={handleDeleteUser} isLoading={loading} />} />
                    <Route path="*" element={<Dashboard customers={customers} transactions={transactions} currentUser={currentUser} isLoading={loading} />} /> {/* Fallback for Admin */}
                  </>
                ) : currentUser.role === UserRoleEnum.MITARBEITER ? (
                  // Mitarbeiter has restricted access
                  <>
                    <Route path="/" element={<Dashboard customers={customers} transactions={transactions} currentUser={currentUser} isLoading={loading} />} />
                    <Route path="/customers" element={<CustomerManagement customers={customers} transactions={transactions} currentUser={currentUser} onAddUser={handleAddUser} isLoading={loading} />} />
                    <Route
                      path="/customers/:id"
                      element={<CustomerDetails customers={customers} transactions={transactions} onUpdateCustomer={handleUpdateCustomer} onAddTransaction={handleAddTransaction} currentUser={currentUser} isLoading={loading} />}
                    />
                    {/* Redirect any restricted path or unknown path for Mitarbeiter to dashboard */}
                    <Route path="/reports" element={<Navigate replace to="/" />} />
                    <Route path="/users" element={<Navigate replace to="/" />} />
                    <Route path="*" element={<Dashboard customers={customers} transactions={transactions} currentUser={currentUser} isLoading={loading} />} /> {/* Fallback for Mitarbeiter */}
                  </>
                ) : currentUser.role === UserRoleEnum.KUNDE && currentUser.associatedCustomerId ? (
                  // Kunde has access only to their own customer details, enforced by internal component logic and redirects
                  <>
                    {/* Dynamic route for *any* customer ID. The CustomerDetails component will authorize. */}
                    <Route
                      path="/customers/:id"
                      element={<CustomerDetails customers={customers} transactions={transactions} onUpdateCustomer={handleUpdateCustomer} onAddTransaction={handleAddTransaction} currentUser={currentUser} isLoading={loading} />}
                    />
                    {/* Redirect root path to their own specific customer page */}
                    <Route path="/" element={<Navigate replace to={`/customers/${currentUser.associatedCustomerId}`} />} />
                    {/* Catch-all for any other path not explicitly handled, redirects to their own customer page */}
                    <Route path="*" element={<Navigate replace to={`/customers/${currentUser.associatedCustomerId}`} />} />
                  </>
                ) : (
                  // Fallback for any other unexpected logged-in state (e.g., customer role without associated ID, though type system should prevent this state for a logged-in user)
                  <Route path="*" element={<Dashboard customers={customers} transactions={transactions} currentUser={currentUser} isLoading={loading} />} />
                )}
              </Routes>
            </main>
          </>
        ) : (
          // Not logged in
          <Routes>
            <Route path="/login" element={<LoginPage onLogin={handleLogin} isLoading={loading} />} />
            <Route path="*" element={<LoginPage onLogin={handleLogin} isLoading={loading} />} />
          </Routes>
        )
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback } from 'react';
import { Routes, Route, useNavigate, Navigate } from 'react-router-dom';
import { createClient } from '@supabase/supabase-js';
import Sidebar from './components/Sidebar';
import Dashboard from './pages/Dashboard';
import CustomerManagement from './pages/CustomerManagement';
import CustomerDetails from './pages/CustomerDetails';
import Reports from './pages/Reports';
import UserManagement from './pages/UserManagement'; // Import the new UserManagement page
import LoginPage from './pages/LoginPage'; // Import the new LoginPage
import { Customer, Transaction, TrainingLevelEnum, User, UserRoleEnum, Database, TrainingSection } from './types'; // Import types
import { REFERENCE_DATE } from './constants'; // Import constants needed for initial state
import { parseDateString } from './utils'; // Import parseDateString

// Supabase Client Initialization
const SUPABASE_PLACEHOLDER_URL = "YOUR_SUPABASE_URL";
const SUPABASE_PLACEHOLDER_ANON_KEY = "YOUR_SUPABASE_ANON_KEY";

const rawSupabaseUrl = (window as any).SUPABASE_URL || (import.meta as any).env.VITE_SUPABASE_URL;
const rawSupabaseAnonKey = (window as any).SUPABASE_ANON_KEY || (import.meta as any).env.VITE_SUPABASE_ANON_KEY;

let supabase: ReturnType<typeof createClient<Database>> | null = null;
let supabaseConfigMissing = false;

// Log raw values for debugging
console.log("Supabase Init: rawSupabaseUrl =", rawSupabaseUrl);
console.log("Supabase Init: rawSupabaseAnonKey =", rawSupabaseAnonKey);

if (rawSupabaseUrl === SUPABASE_PLACEHOLDER_URL || rawSupabaseAnonKey === SUPABASE_PLACEHOLDER_ANON_KEY || !rawSupabaseUrl || !rawSupabaseAnonKey) {
  console.error("Supabase configuration missing or placeholder values detected. Please update index.html with your actual Supabase URL and Anon Key.");
  supabaseConfigMissing = true;
} else {
  try {
    supabase = createClient<Database>(rawSupabaseUrl, rawSupabaseAnonKey);
    console.log("Supabase client initialized successfully.");
  } catch (e) {
    console.error("Failed to initialize Supabase client:", e);
    supabaseConfigMissing = true;
  }
}

const App: React.FC = () => {
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [users, setUsers] = useState<User[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true); // Initial loading state for app data
  const [showConfigError, setShowConfigError] = useState(supabaseConfigMissing); // Use the global flag for rendering
  const navigate = useNavigate();

  // If config is missing from the start, display error immediately
  useEffect(() => {
    if (showConfigError) {
      setLoading(false); // Stop loading animation
    }
  }, [showConfigError]);

  const fetchUsers = useCallback(async () => {
    if (!supabase) { console.error("Supabase client not initialized. Cannot fetch users."); setLoading(false); return; }
    console.log("Fetching users...");
    const { data: profilesData, error: profilesError } = await supabase
      .from('profiles')
      .select('*');

    if (profilesError) {
      console.error('Error fetching users:', profilesError);
      // Specific check for RLS
      if (profilesError.message?.includes('permission denied') || profilesError.code === '42501') {
        console.warn("Possible RLS issue: User might not have permission to read 'profiles' table.");
      }
      const errorMessageForUser = profilesError.message || 'Unbekannter Fehler beim Laden der Benutzerprofile.';
      alert(`Fehler beim Laden der Benutzer: ${errorMessageForUser}`);
      setUsers([]);
      return false; // Indicate failure
    }

    const fetchedUsers: User[] = profilesData.map(profile => ({
      id: profile.id,
      avatarInitials: profile.avatarInitials,
      avatarColor: profile.avatarColor,
      firstName: profile.firstName,
      lastName: profile.lastName,
      email: profile.email,
      role: profile.role as UserRoleEnum, // Cast to enum
      createdAt: profile.createdAt,
      associatedCustomerId: profile.associatedCustomerId,
    }));
    setUsers(fetchedUsers);
    console.log("Users fetched successfully:", fetchedUsers.length);
    return true; // Indicate success
  }, []);

  const fetchCustomers = useCallback(async () => {
    if (!supabase) { console.error("Supabase client not initialized. Cannot fetch customers."); setLoading(false); return; }
    console.log("Fetching customers...");
    const { data: customersData, error: customersError } = await supabase
      .from('customers')
      .select(`
        *,
        documents(*),
        training_sections(*)
      `);

    if (customersError) {
      console.error('Error fetching customers:', customersError);
      if (customersError.message?.includes('permission denied') || customersError.code === '42501') {
        console.warn("Possible RLS issue: User might not have permission to read 'customers' or related tables.");
      }
      const errorMessageForUser = customersError.message || 'Unbekannter Fehler beim Laden der Kundendaten.';
      alert(`Fehler beim Laden der Kunden: ${errorMessageForUser}`);
      setCustomers([]);
      return false; // Indicate failure
    }

    const fetchedCustomers: Customer[] = customersData.map(customer => {
      const sortedTrainingProgress = customer.training_sections
        ? [...customer.training_sections]
            .sort((a, b) => a.id - b.id)
            .map(section => ({
              ...section,
              status: section.status as TrainingSection['status'],
            }))
