              console.warn("Possible RLS issue: Authenticated user might not have permission to read their own 'profiles' entry.");
            } else if (profileError.code === 'PGRST116' || profileError.details?.includes('0 rows')) {
              console.warn("User profile not found in 'profiles' table after login. This likely means the user was created outside the app's 'Add User' flow.");
            }
            const errorMessageForUser = profileError.message || 'Unbekannter Fehler beim Laden des Benutzerprofils. Bitte überprüfen Sie die Konsolenausgabe für weitere Details.';
            alert(`Fehler beim Laden des Benutzerprofils: ${errorMessageForUser}`);
