            avatarColor: profile.avatarColor,
            firstName: profile.firstName,
            lastName: profile.lastName,
            email: profile.email,
            role: profile.role as UserRoleEnum,
            createdAt: profile.createdAt,
            associatedCustomerId: profile.associatedCustomerId,
          };
          setCurrentUser(userProfile);
          console.log("Current user set:", userProfile);
          await fetchAllData(); // Fetch all app data after user is logged in

          // Redirection logic based on role
          if (userProfile.role === UserRoleEnum.KUNDE && userProfile.associatedCustomerId) {
            const expectedPath = `/customers/${userProfile.associatedCustomerId}`;
            if (!window.location.hash.startsWith(`#${expectedPath}`)) {
              console.log("Redirecting Kunde to own customer page:", expectedPath);
              navigate(expectedPath, { replace: true });
            }
          } else if (window.location.hash === '#/login') {
            console.log("Redirecting non-Kunde from login to dashboard.");
            navigate('/', { replace: true });
          }
        } else {
          console.log("No session found or user logged out. Resetting state.");
          setIsLoggedIn(false);
          setCurrentUser(null);
          setCustomers([]);
          setUsers([]);
          setTransactions([]);
          navigate('/login', { replace: true });
        }
